#         eval_work cleanup.
# ════════════════════════════════════════════════════════════════════════════


def check_remote_archive_eval_self_bootstraps_uv_and_ffmpeg(
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """PCC5: scripts/remote_archive_only_eval.sh + every scripts/remote_lane_*.sh
    that runs contest_auth_eval MUST self-bootstrap uv (and ffmpeg if it
    enforces the color-contract).

    Bug class extincted: a fresh pytorch:cuda image has no `uv` on PATH;
    a system-default ffmpeg 4.4.2 lacks `in_primaries` scale option that
    `submissions/robust_current/inflate.sh require_ffmpeg_parity` requires.
    Without an in-script self-bootstrap, the lane crashes immediately at
    Stage 1 and a $0.30 dispatch is wasted.

    Reference: feedback_uv_not_on_path_vast_instance_20260501.md +
    feedback_loop_session_permanent_bug_class_extinction_20260501.md.

    Acceptable patterns (in priority order):
      1. function definition `bootstrap_runtime_deps()` (the canonical
         pattern from remote_archive_only_eval.sh)
      2. invocation of `scripts/ensure_remote_uv.sh`
      3. inline `curl -LsSf https://astral.sh/uv/install.sh` block
    Any of (1)-(3) satisfies the check.

    Exempt: scripts that don't run contest_auth_eval (build-only, training-
    only, smoke-only) — the check is keyed on `contest_auth_eval` text.
    """
    root = repo_root or REPO_ROOT
    violations: list[str] = []
    scripts_dir = root / "scripts"
    if not scripts_dir.is_dir():
        return violations
    candidates: list[Path] = []
    canonical = scripts_dir / "remote_archive_only_eval.sh"
    if canonical.exists():
        candidates.append(canonical)
    for p in sorted(scripts_dir.glob("remote_lane_*.sh")):
        candidates.append(p)

    n_scanned = 0
    n_relevant = 0
    # In-script self-bootstrap markers (the strongest pattern).
    bootstrap_markers = (
        "bootstrap_runtime_deps",
        "scripts/ensure_remote_uv.sh",
        "ensure_remote_uv.sh",
        "https://astral.sh/uv/install.sh",
    )
    # Inheritance markers — script assumes setup_full.sh / canonical
    # bootstrap (which DOES bootstrap uv) ran first. Acceptable but weaker
    # because operator MUST run setup_full.sh in the bootstrap chain.
    canonical_inheritance_markers = (
        "source $WORKSPACE/env.sh",
        'source "$WORKSPACE/env.sh"',
        "source env.sh",
        '. "$WORKSPACE/env.sh"',
        "source $REPO_ROOT/env.sh",
        # Common pattern in our remote_lane_*.sh: depends on
        # remote_setup_full.sh having pre-bootstrapped uv.
        "remote_setup_full.sh",
        "setup_full.sh",
        # Lane scripts that delegate the eval to remote_archive_only_eval.sh
        # inherit its self-bootstrap (lines 46-72 in that script). The
        # delegation is the acceptance: the canonical wrapper bootstraps
        # before running contest_auth_eval.py.
        "remote_archive_only_eval.sh",
        # Some scripts call `command -v uv` then source the install if
        # missing — that satisfies the contract by self-healing.
        "command -v uv >/dev/null",
    )
    # Detect ACTUAL contest_auth_eval.py subprocess invocations, not
    # JSON-string mentions inside heredocs (e.g. provenance manifests
    # writing `"required_score_truth": "... contest_auth_eval.py ..."`).
    _invocation_re = re.compile(
        r'(?:"?\$PYBIN"?|\bpython3?\b)\s+(?:-u\s+)?(?:-m\s+)?'
        r'(?:\S+/)?contest_auth_eval\.py\b'
    )
    for path in candidates:
        n_scanned += 1
        try:
            text = path.read_text(errors="ignore")
        except OSError:
            continue
        # Strip comments so a "# we use bootstrap_runtime_deps" doc line
        # doesn't satisfy the check.
        non_comment = "\n".join(
            line if not line.lstrip().startswith("#") else ""
            for line in text.split("\n")
        )
        # Accept either a real python invocation OR a delegation to a
        # remote_lane_*.sh / remote_archive_only_eval.sh that itself runs
        # contest_auth_eval.py — the delegation is satisfied by the
        # `remote_archive_only_eval.sh` inheritance marker below.
        if not _invocation_re.search(non_comment) and "remote_archive_only_eval.sh" not in non_comment:
            continue
        n_relevant += 1
        if any(m in non_comment for m in bootstrap_markers):
            continue
        if any(m in non_comment for m in canonical_inheritance_markers):
            continue
        rel = path.relative_to(root) if path.is_absolute() else path
        violations.append(
            f"{rel}: invokes contest_auth_eval but does NOT self-bootstrap "
            f"uv (no `bootstrap_runtime_deps`, `scripts/ensure_remote_uv.sh`, "
            f"`source env.sh`, or `setup_full.sh` reference). Add the "
            f"canonical bootstrap from "
            f"scripts/remote_archive_only_eval.sh:46-72 OR call "
            f"`bash scripts/ensure_remote_uv.sh --symlink-system`. "
            f"Reference: feedback_uv_not_on_path_vast_instance_20260501."
        )

    if verbose:
        if violations:
            print(
                f"  [pcc5-self-bootstrap-uv-ffmpeg] {len(violations)}/{n_relevant} "
                f"contest-eval script(s) violate (of {n_scanned} scanned)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [pcc5-self-bootstrap-uv-ffmpeg] OK: {n_relevant} contest-eval "
                f"script(s) self-bootstrap (of {n_scanned} scanned)"
            )

    if violations and strict:
        raise PreflightError(
            "PCC5 self-bootstrap-uv-ffmpeg violations:\n  • "
            + "\n  • ".join(violations)
            + "\n\nReference: feedback_loop_session_permanent_bug_class_"
            "extinction_20260501.md (Bug Class #1, #4)."
        )
    return violations


# Pattern: shell-script venv-creation tokens that DON'T install pip by
# default. `python -m venv` ships pip in the stdlib bundle; `uv venv` and
# bare `virtualenv` do not. So we only flag the latter two.
# (To audit `python -m venv` callers separately, use _VENV_CREATE_ANY_RE.)
_VENV_CREATE_RE = re.compile(
    r"(?:^|[\s;&|`(])(?:uv\s+venv|virtualenv\s)"
)
_VENV_CREATE_ANY_RE = re.compile(
    r"(?:^|[\s;&|`(])(?:python\d?\s+-m\s+venv|uv\s+venv|virtualenv\s)"
)


def check_venv_creators_use_ensurepip(
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """PCC6: every shell script that creates a venv (python -m venv / uv venv /
    virtualenv) MUST install pip into it (or document why pip is not needed).

    Bug class extincted (2026-05-01): `uv venv` does NOT install pip. Any
    downstream `python -m pip ...` or `python -m ensurepip` call then fails
    with `No module named pip`. probe_nvdec.sh hit this on a fresh venv and
    a $0.30 dispatch was wasted.

    Reference: feedback_loop_session_permanent_bug_class_extinction_20260501.md
    (Bug Class #3) + the user's "ensurepip" guidance during the loop session.

    Acceptable companions within 12 lines after the venv-create line:
      1. `scripts/ensure_remote_pip.sh` invocation (canonical)
      2. `python -m ensurepip` call
      3. `uv pip install` (uv handles its own pip-less install)
      4. an inline comment `# NO_PIP_NEEDED:` justifying the omission

    Exempt: docs / .md / .txt files (we only scan .sh under scripts/).
    """
    root = repo_root or REPO_ROOT
    violations: list[str] = []
    scripts_dir = root / "scripts"
    if not scripts_dir.is_dir():
        return violations
    n_scanned = 0
    n_with_venv = 0
    for path in sorted(scripts_dir.rglob("*.sh")):
        n_scanned += 1
        try:
            text = path.read_text(errors="ignore")
        except OSError:
            continue
        # Strip comment-only lines so "# uv venv ..." doc doesn't trip the regex.
        # But keep partial-line comments intact (in case operator wrote
        # `uv venv ...  # comment`).
        text_no_full_comments = "\n".join(
            line if not line.lstrip().startswith("#") else ""
            for line in text.split("\n")
        )
        lines = text_no_full_comments.split("\n")
        for i, line in enumerate(lines):
            if not _VENV_CREATE_RE.search(line):
                continue
            n_with_venv += 1
            window_lines = lines[i:i + 12]
            window = "\n".join(window_lines)
            satisfies = (
                "ensure_remote_pip.sh" in window
                or "ensurepip" in window
                or "uv pip install" in window
                or "# NO_PIP_NEEDED" in window
                # uv-only paths (no pip needed): if the very next non-empty
                # action is `uv pip install` chained, that satisfies.
                or "--system-site-packages" in line  # inherits system pip
            )
            if not satisfies:
                rel = path.relative_to(root) if path.is_absolute() else path
                violations.append(
                    f"{rel}:{i+1}: venv-create line `{line.strip()[:80]}` "
                    f"has no `scripts/ensure_remote_pip.sh` / `ensurepip` "
                    f"/ `uv pip install` within next 12 lines. Either add "
                    f"a pip-bootstrap or annotate `# NO_PIP_NEEDED: <why>` "
                    f"on the same line. Reference: "
                    f"feedback_loop_session_permanent_bug_class_extinction_"
                    f"20260501.md (Bug Class #3)."
                )

    if verbose:
        if violations:
            print(
                f"  [pcc6-ensurepip-after-venv] {len(violations)} violation(s) "
                f"across {n_with_venv} venv-create site(s) in {n_scanned} script(s)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [pcc6-ensurepip-after-venv] OK: {n_with_venv} venv-create "
                f"site(s) clean across {n_scanned} script(s)"
            )

    if violations and strict:
        raise PreflightError(
            "PCC6 ensurepip-after-venv-create violations:\n  • "
            + "\n  • ".join(violations)
            + "\n\nReference: feedback_loop_session_permanent_bug_class_"
            "extinction_20260501.md (Bug Class #3)."
        )
    return violations


# Pattern: any `vastai create instance` invocation in shell or python.
# Tolerant of leading `str(VASTAI),` / `"vastai",` / `${VASTAI}` etc.
_VASTAI_CREATE_RE = re.compile(
    r"""(?ix)
    \b vastai \b [^\n]{0,40}? \b create \s+ instance \b
    |
    " create " \s* , \s* " instance "
    |
    ' create ' \s* , \s* ' instance '
    """
)
_DISK_FLAG_LITERAL_RE = re.compile(
    r"""(?x)
    (?: --disk \s* | "--disk" \s* , \s* )
    ['"]? \s*
    (?P<value> \d+ )
    """
)
# Catches python source where --disk value is a variable / expression
# rather than a literal: `"--disk", str(int(disk_gb))` or
# `"--disk", str(int(spec.disk_gb))`. The presence of --disk + non-literal
# value means we trust the upstream `disk_gb`/`spec.disk_gb` parameter
# default — which we ALSO check via the dataclass-default scanner below.
_DISK_FLAG_VAR_RE = re.compile(
    r"""(?x)
    (?: --disk \s* | "--disk" \s* , \s* | '--disk' \s* , \s* )
    ['"]? \s*
    (?P<expr> str\s*\([^)]+\) | \$\{?[A-Z_][A-Z0-9_]*\}? | [A-Za-z_][A-Za-z_0-9]* )
    """
)


def check_vastai_create_uses_min_disk_60(
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """PCC7: every `vastai create instance` invocation MUST allocate at least
    60 GB of disk (or annotate `# SINGLE_CANDIDATE_DISK_OK: <why>` on the
    same line for justified small-disk allocs).

    Bug class extincted (2026-05-01): a 30-GB disk crashed a 6-candidate
    chain eval at the 4th candidate (uv torch wheels 5GB + 4×3.6GB inflated
    frames = 19.4GB working set, then 5th eval push tipped over the 30GB
    ceiling and the rest of the chain failed at "no space left on device").
    A 60-GB floor gives safe headroom up to ~12 candidates.

    Reference: feedback_loop_session_permanent_bug_class_extinction_20260501.md
    (Bug Class #6).
    """
    root = repo_root or REPO_ROOT
    violations: list[str] = []
    n_scanned = 0
    n_creates = 0
    # Scan both shell (.sh) and python (.py) files in scripts/ + src/tac/deploy/.
    candidate_paths: list[Path] = []
    for d in ("scripts", "src/tac/deploy", "tools"):
        d_path = root / d
        if not d_path.exists():
            continue
        for ext in ("*.sh", "*.py"):
            candidate_paths.extend(sorted(d_path.rglob(ext)))

    for path in candidate_paths:
        n_scanned += 1
        try:
            text = path.read_text(errors="ignore")
        except OSError:
            continue
        # Strip whole-line comments so docstrings/banners don't trigger.
        # We keep inline comments so the SINGLE_CANDIDATE_DISK_OK marker
        # parses on the same line as the create.
        non_comment = "\n".join(
            line if not (
                line.lstrip().startswith("#") or line.lstrip().startswith('"""')
            ) else ""
            for line in text.split("\n")
        )
        for m in _VASTAI_CREATE_RE.finditer(non_comment):
            n_creates += 1
            # Find the line containing this match.
            start = m.start()
            line_start = non_comment.rfind("\n", 0, start) + 1
            # Get a window around the create call (often the --disk flag is
            # within ~25 lines; argparse calls in py are dataclass-like).
            window_end = min(len(non_comment), m.end() + 1500)
            window = non_comment[line_start:window_end]
            # Same-line waiver for justified small-disk paths.
            same_line_end = non_comment.find("\n", line_start)
            if same_line_end < 0:
                same_line_end = len(non_comment)
            same_line = non_comment[line_start:same_line_end]
            if "SINGLE_CANDIDATE_DISK_OK" in same_line:
                continue
            # Find first --disk arg in the window. Try literal value first;
            # if not found, look for a variable / expression form (e.g.
            # `"--disk", str(int(disk_gb))`) and trust the dataclass default
            # which is checked separately below.
            disk_match = _DISK_FLAG_LITERAL_RE.search(window)
            lineno = non_comment[:start].count("\n") + 1
            rel = path.relative_to(root) if path.is_absolute() else path
            if not disk_match:
                # Variable form acceptable for python (we can't statically
                # eval at preflight time without overreach). Whitelist
                # only when the variable name itself contains 'disk' or is
                # a likely capitalized constant.
                var_match = _DISK_FLAG_VAR_RE.search(window)
                if var_match:
                    expr = var_match.group("expr")
                    if "disk" in expr.lower() or expr.isupper():
                        # Pass — the disk value is parameterized; the
                        # parameter default is checked elsewhere (e.g.,
                        # InstanceSpec.disk_gb default in src/tac/deploy/base.py
                        # was bumped to 60 in this commit).
                        continue
                violations.append(
                    f"{rel}:{lineno}: `vastai create instance` has no `--disk` "
                    f"arg (literal or `disk`-named variable) in next ~1500 "
                    f"chars. Default Vast.ai disk is 16GB, too small for "
                    f"chain evals (Bug Class #6). Add `--disk 60` OR "
                    f"annotate `# SINGLE_CANDIDATE_DISK_OK: <why>`."
                )
                continue
            try:
                disk_gb = int(disk_match.group("value"))
            except (TypeError, ValueError):
                continue
            if disk_gb < 60:
                violations.append(
                    f"{rel}:{lineno}: `vastai create instance` uses "
                    f"--disk {disk_gb} < 60GB. Multi-candidate chains need "
                    f"~30GB working set + uv-torch ~5GB. Use --disk 60 OR "
                    f"annotate `# SINGLE_CANDIDATE_DISK_OK: <why>` on the "
                    f"same line. Reference: feedback_loop_session_permanent_"
                    f"bug_class_extinction_20260501.md (Bug Class #6)."
                )

    if verbose:
        if violations:
            print(
                f"  [pcc7-vastai-disk-60] {len(violations)}/{n_creates} create "
                f"call(s) violate (of {n_scanned} scanned files)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [pcc7-vastai-disk-60] OK: {n_creates} create call(s) "
                f"clean (of {n_scanned} scanned files)"
            )

    if violations and strict:
        raise PreflightError(
            "PCC7 vastai-create-disk-60 violations:\n  • "
            + "\n  • ".join(violations)
            + "\n\nReference: feedback_loop_session_permanent_bug_class_"
            "extinction_20260501.md (Bug Class #6)."
        )
    return violations


def check_remote_chain_drivers_clean_inflated_per_candidate(
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """PCC8: every multi-candidate chain driver script MUST clean up
    `eval_work/inflated` (and ideally `eval_work/extracted` + `archive.zip`)
    BETWEEN candidates so a 6+ candidate chain doesn't fill the disk.

    Bug class extincted (2026-05-01): a chain driver that leaves
    `LOG_DIR/eval_work/inflated/` from candidate N around when starting
    candidate N+1 piles 3.6 GB per candidate. After 6 candidates that's
    21.6 GB in /workspace alone — combined with uv torch wheels (5 GB) the
    30/35 GB Vast.ai disk fills up mid-chain.

    Reference: feedback_loop_session_permanent_bug_class_extinction_20260501.md
    (Bug Class #7).

    Heuristic: any script under scripts/ or experiments/results/ matching
    `*chain*.sh` (case-insensitive) that loops with `for cid in ...` or
    `for entry in ...` MUST contain `rm -rf` of `eval_work/inflated` (or
    explicit `--no-keep-work-dir` flag, or `# NO_INFLATE_CLEANUP_NEEDED:`
    waiver).
    """
    root = repo_root or REPO_ROOT
    violations: list[str] = []
    n_scanned = 0
    n_chains = 0
    chain_paths: list[Path] = []
    for d in ("scripts", "experiments/results"):
        d_path = root / d
        if not d_path.exists():
            continue
        for p in d_path.rglob("*chain*.sh"):
            chain_paths.append(p)
        for p in d_path.rglob("*chain*driver*.sh"):
            if p not in chain_paths:
                chain_paths.append(p)

    for path in sorted(set(chain_paths)):
        n_scanned += 1
        try:
            text = path.read_text(errors="ignore")
        except OSError:
            continue
        # Strip whole-line comments for the chain-detection logic only —
        # the waiver marker IS in a comment so it must remain visible.
        non_comment = "\n".join(
            line if not line.lstrip().startswith("#") else ""
            for line in text.split("\n")
        )
        # A "multi-candidate chain" has a for-loop over an array.
        if not re.search(
            r"for\s+\w+\s+in\s+(?:\$\{?\w+\[@\]\}?|\$\(.*\)|`.*`|\$\w+|\w+_\w+)",
            non_comment,
        ):
            continue
        # Also require contest_auth_eval or remote_archive_only_eval reference.
        if "contest_auth_eval" not in non_comment and \
                "remote_archive_only_eval.sh" not in non_comment:
            continue
        n_chains += 1
        # Specifically: rm -rf must reference inflated / eval_work / extracted.
        rm_eval_work_re = re.compile(
            r"rm\s+-rf[^\n]*(?:eval_work|inflated|extracted|archive\.zip)"
        )
        has_cleanup = (
            bool(rm_eval_work_re.search(non_comment))
            or "--no-keep-work-dir" in non_comment
            # Waiver marker stays in the ORIGINAL text (often a comment).
            or "NO_INFLATE_CLEANUP_NEEDED" in text
        )
        if not has_cleanup:
            rel = path.relative_to(root) if path.is_absolute() else path
            violations.append(
                f"{rel}: multi-candidate chain driver has no per-candidate "
                f"`rm -rf eval_work/inflated` cleanup. After 6 candidates "
                f"that's ~21GB of inflated frames stacked on a 30/60GB disk. "
                f"Add `rm -rf $LOG_DIR/eval_work/inflated` (and ideally "
                f"`extracted` + `archive.zip`) at end of each iteration, OR "
                f"annotate `# NO_INFLATE_CLEANUP_NEEDED: <why>`. Reference: "
                f"feedback_loop_session_permanent_bug_class_extinction_"
                f"20260501.md (Bug Class #7)."
            )

    if verbose:
        if violations:
            print(
                f"  [pcc8-chain-cleanup] {len(violations)}/{n_chains} chain "
                f"driver(s) violate (of {n_scanned} scanned)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [pcc8-chain-cleanup] OK: {n_chains} chain driver(s) "
                f"clean (of {n_scanned} scanned)"
            )

    if violations and strict:
        raise PreflightError(
            "PCC8 chain-driver-per-candidate-cleanup violations:\n  • "
            + "\n  • ".join(violations)
            + "\n\nReference: feedback_loop_session_permanent_bug_class_"
            "extinction_20260501.md (Bug Class #7)."
        )
    return violations


# ════════════════════════════════════════════════════════════════════════════
# HARDEN-2026-05-08 — preflight checks for the Path B step 5/6 ADMM tools +
# cross-paradigm composition + 137,531 B candidate (commit 8d33d5c1).
#
# Five new checks per the HARDEN subagent mandate. All start `strict=False`;
# each lands at 0 live violations on the current tree, so the wiring at the
# call site flips them STRICT immediately (per the Lane A → strict pattern
# in commit 7f2740e4).
# ════════════════════════════════════════════════════════════════════════════


# Tools that perform Lagrangian λ-bisection over per-tensor cost curves and
# MUST converge under a finite budget. New tools added by HARDEN should be
# appended here.
_ADMM_BISECTION_TOOLS = (
    "tools/pr101_omega_opt_joint_admm_allocation_empirical.py",
    "tools/pr101_omega_opt_admm_x_lossy_coarsening_empirical.py",
)


def _canonical_lagrangian_allocator_has_bisection_contract(root: Path) -> bool:
    """Return true when the canonical allocator owns max-iter + tolerance.

    Thin empirical tools may delegate λ-bisection to this reviewed module.
    Accept delegation only while the canonical implementation itself still has
    an explicit finite loop and tolerance break.
    """
    allocator_path = (
        root / "src" / "tac" / "optimization" / "lagrangian_per_tensor_allocation.py"
    )
    if not allocator_path.is_file():
        return False
    text = allocator_path.read_text(encoding="utf-8")
    has_loop = bool(
        re.search(r"for\s+\w+\s+in\s+range\(\s*max_iter\s*\)\s*:", text)
    )
    has_tolerance = (
        "abs(hi - lo)" in text
        or "abs(hi-lo)" in text
        or re.search(r"\bhi\s*==\s*lo\b", text) is not None
    )
    return has_loop and has_tolerance


def _delegates_to_canonical_lagrangian_bisection(text: str) -> bool:
    """Detect reviewed delegation to LagrangianPerTensorAllocator.bisect.

    The tool still must pass a concrete ``max_iter`` so the budget remains
    visible at the callsite instead of becoming an implicit default.
    """
    if "LagrangianPerTensorAllocator" not in text or "bisect_for_rms_target" not in text:
        return False
    try:
        tree = ast.parse(text)
    except SyntaxError:
        return False
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        func = node.func
        if not (
            isinstance(func, ast.Attribute)
            and func.attr == "bisect_for_rms_target"
        ):
            continue
        for keyword in node.keywords:
            if keyword.arg != "max_iter":
                continue
            value = keyword.value
            if isinstance(value, ast.Constant) and isinstance(value.value, int):
                return value.value > 0
    return False


def check_admm_lagrangian_bisection_convergent(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """STRICT: every ADMM/Lagrangian bisection tool must declare a finite
    iteration cap AND a tolerance.

    Catches the "infinite-loop on a never-converging Lagrangian" bug class:
    a bisect over [0, 1e15] with no max-iters spins until SIGURG. Tools must
    contain BOTH:
        * a ``for _ in range(<INT>):`` bisection loop, AND
        * either ``abs(hi - lo) <`` (tolerance break) OR
          ``hi == lo`` (degenerate-window break) inside the loop.

    Reference: HARDEN-2026-05-08 mandate; CLAUDE.md "Internal-consistency
    assertions in stats files" by analogy (any iterative numerical procedure
    must declare its termination contract).
    """
    root = Path(repo_root or REPO_ROOT)
    violations: list[str] = []
    n_scanned = 0
    for rel in _ADMM_BISECTION_TOOLS:
        path = root / rel
        if not path.is_file():
            violations.append(
                f"{rel}: declared ADMM bisection tool MISSING — was it "
                f"renamed or deleted? Update _ADMM_BISECTION_TOOLS."
            )
            continue
        n_scanned += 1
        text = path.read_text(encoding="utf-8")
        # Look for `for _ in range(<INT>):` near a function whose body
        # contains a Lagrangian update (lo/hi assignment).
        has_max_iter = bool(
            re.search(r"for\s+\w+\s+in\s+range\(\s*\d+\s*\)\s*:", text)
        )
        has_tolerance = (
            "abs(hi - lo)" in text
            or "abs(hi-lo)" in text
            or re.search(r"\bhi\s*==\s*lo\b", text) is not None
        )
        delegates_to_canonical = (
            _delegates_to_canonical_lagrangian_bisection(text)
            and _canonical_lagrangian_allocator_has_bisection_contract(root)
        )
        if delegates_to_canonical:
            has_max_iter = True
            has_tolerance = True
        if not has_max_iter:
            violations.append(
                f"{rel}: ADMM bisection MUST declare a finite "
                f"`for _ in range(<INT>):` cap or delegate to canonical "
                f"LagrangianPerTensorAllocator.bisect_for_rms_target with "
                f"`max_iter=<INT>`. Found none."
            )
        if not has_tolerance:
            violations.append(
                f"{rel}: ADMM bisection MUST declare a tolerance break "
                f"(`abs(hi - lo) < ...` or `hi == lo`) or delegate to the "
                f"canonical allocator that owns that break. Found none."
            )
    if verbose:
        if violations:
            print(
                f"  [harden-admm-bisection] {len(violations)} violation(s) "
                f"across {n_scanned} bisection tool(s)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [harden-admm-bisection] OK: {n_scanned} bisection tool(s) "
                f"all declare finite iters + tolerance"
            )
    if violations and strict:
        raise PreflightError(
            "ADMM LAGRANGIAN BISECTION CONVERGENCE VIOLATIONS:\n  • "
            + "\n  • ".join(violations)
            + "\n\nReference: HARDEN-2026-05-08 mandate; bisection without a "
            "max-iter cap is a SIGURG-magnet."
        )
    return violations


def check_codec_pipeline_op_order_deterministic(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """STRICT: ``CodecPipeline.encode`` must be byte-deterministic for a
    fixed input + fixed op order.

    AST-level scan of :mod:`tac.codec_pipeline` for the encode method body —
    requires that the manifest emit a ``ts_iso`` field (timestamp) but that
    the actual blob bytes are NOT a function of any wall-clock or random
    source (``time.time``, ``random.``, ``os.urandom``, ``uuid.uuid``).

    The blob may contain ``ts_iso`` only inside the manifest sidecar (which
    is JSON, deserialized separately); it must NOT enter the op blob itself.
    """
    root = Path(repo_root or REPO_ROOT)
    src_path = root / "src" / "tac" / "codec_pipeline.py"
    if not src_path.is_file():
        msg = f"src/tac/codec_pipeline.py missing: {src_path}"
        if strict:
            raise PreflightError(msg)
        return [msg]

    text = src_path.read_text(encoding="utf-8")
    # AST scan: parse the encode method body, find every Call whose function
    # is one of the non-deterministic sources, then trace whether the result
    # propagates into the `out` bytearray that constitutes the blob. The
    # canonical CodecPipeline.encode uses `time.time()` only for the manifest
    # sidecar (`started_at_utc`, `elapsed_seconds`), which is NOT part of the
    # blob bytes — so AST scoping is the only way to reject true offenders.
    violations: list[str] = []
    NONDETERMINISTIC_NAMES = {
        ("time", "time"): "time.time()",
        ("random",): "random.*",  # any attr of random
        ("os", "urandom"): "os.urandom()",
    }

    def _is_nondeterministic_call(call_node: ast.AST) -> str | None:
        if not isinstance(call_node, ast.Call):
            return None
        f = call_node.func
        if isinstance(f, ast.Attribute) and isinstance(f.value, ast.Name):
            mod = f.value.id
            attr = f.attr
            if (mod, attr) == ("time", "time"):
                return "time.time()"
            if (mod, attr) == ("os", "urandom"):
                return "os.urandom()"
            if mod == "random":
                return f"random.{attr}()"
            if mod == "uuid" and attr.startswith("uuid"):
                return f"uuid.{attr}()"
        return None

    try:
        tree = ast.parse(text)
    except SyntaxError as e:
        msg = f"src/tac/codec_pipeline.py: AST parse failed: {e}"
        if strict:
            raise PreflightError(msg)
        return [msg]

    # For each function whose name is `encode` or `decode`, find non-det
    # calls; for each such call, walk up the AST and check whether the
    # assignment target eventually flows into a write to a bytes-building
    # sink (heuristic: target name appears in `out += ...`, `out.extend(...)`,
    # `blob = ...` adjacent to a return).
    for fn in ast.walk(tree):
        if not isinstance(fn, ast.FunctionDef):
            continue
        if fn.name not in ("encode", "decode"):
            continue
        # Collect non-det assignments: `var = time.time()` -> var is "tainted".
        tainted_names: set[str] = set()
        nondet_call_lines: list[tuple[int, str]] = []
        for node in ast.walk(fn):
            label = _is_nondeterministic_call(node)
            if label is None:
                continue
            nondet_call_lines.append((node.lineno, label))
            # Find enclosing Assign/AugAssign target
            for parent in ast.walk(fn):
                if isinstance(parent, ast.Assign):
                    if any(node is c for c in ast.walk(parent.value)):
                        for tgt in parent.targets:
                            if isinstance(tgt, ast.Name):
                                tainted_names.add(tgt.id)
        # Check propagation: any tainted name appearing in a BinOp or AugAssign
        # whose other side is the bytes-blob (out, blob, final, payload).
        BLOB_SINKS = {"out", "blob", "final", "payload"}
        for node in ast.walk(fn):
            if isinstance(node, ast.AugAssign) and isinstance(node.target, ast.Name):
                if node.target.id in BLOB_SINKS:
                    # Does node.value contain any tainted name?
                    for inner in ast.walk(node.value):
                        if isinstance(inner, ast.Name) and inner.id in tainted_names:
                            violations.append(
                                f"src/tac/codec_pipeline.py:{node.lineno}: "
                                f"tainted name {inner.id!r} (from non-"
                                f"deterministic call) flows into blob sink "
                                f"{node.target.id!r} via AugAssign"
                            )
            if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
                # `out.extend(...)` / `blob.append(...)`
                if (
                    isinstance(node.func.value, ast.Name)
                    and node.func.value.id in BLOB_SINKS
                ):
                    for inner in ast.walk(node):
                        if isinstance(inner, ast.Name) and inner.id in tainted_names:
                            violations.append(
                                f"src/tac/codec_pipeline.py:{node.lineno}: "
                                f"tainted name {inner.id!r} flows into blob "
                                f"sink {node.func.value.id!r}.{node.func.attr}"
                            )
    if verbose:
        if violations:
            print(
                f"  [harden-codec-pipeline-determinism] {len(violations)} "
                f"violation(s) in CodecPipeline source"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [harden-codec-pipeline-determinism] OK: no time/random/"
                f"urandom/uuid in src/tac/codec_pipeline.py"
            )
    if violations and strict:
        raise PreflightError(
            "CODEC PIPELINE OP ORDER DETERMINISM VIOLATIONS:\n  • "
            + "\n  • ".join(violations)
        )
    return violations


# Wire-format contract: the Path B step 6 candidate writes
#   <I prefix> + <28-byte per-tensor K> + <56-byte per-tensor fp16 scale> +
#   <brotli payload> + <PR101 latent + sidecar blobs>
# The decoder MUST parse exactly this prefix layout. New encoder/decoder pairs
# that add per-tensor K side-info should append themselves below.
_PER_TENSOR_K_DECODER_PATHS = (
    (
        "experiments/results/admm_x_lossy_coarsening_path_b_step6_"
        "20260508T060435Z/submission_dir/inflate.py"
    ),
)
_PER_TENSOR_K_ENCODER_PATHS = (
    "tools/build_admm_x_lossy_coarsening_path_b_step6.py",
)


def check_per_tensor_K_side_info_matches_decoder_expectation(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """STRICT: any encoder writing per-tensor K side-info must match the
    decoder's expected wire-format prefix layout.

    Encoder MUST produce ``struct.pack("<I", section_total)`` followed by
    ``K_bytes`` (one byte per tensor) and ``scale_bytes`` (fp16 LE, 2 bytes
    per tensor). Decoder MUST declare the same constants:
        * ``PREFIX_BYTES = 4``
        * ``K_SECTION_BYTES = N_TENSORS``
        * ``SCALE_SECTION_BYTES = N_TENSORS * 2``
    """
    root = Path(repo_root or REPO_ROOT)
    violations: list[str] = []
    n_pairs = 0

    # Decoder side: each declared decoder must have all three constants
    for rel in _PER_TENSOR_K_DECODER_PATHS:
        path = root / rel
        if not path.is_file():
            violations.append(
                f"{rel}: declared per-tensor-K decoder MISSING — was the "
                f"candidate dir deleted? Update _PER_TENSOR_K_DECODER_PATHS."
            )
            continue
        n_pairs += 1
        text = path.read_text(encoding="utf-8")
        if "PREFIX_BYTES = 4" not in text:
            violations.append(f"{rel}: missing `PREFIX_BYTES = 4` declaration")
        if "K_SECTION_BYTES" not in text:
            violations.append(f"{rel}: missing `K_SECTION_BYTES` declaration")
        if "SCALE_SECTION_BYTES" not in text:
            violations.append(f"{rel}: missing `SCALE_SECTION_BYTES` declaration")
        if 'struct.unpack("<I"' not in text and "struct.unpack('<I'" not in text:
            violations.append(
                f"{rel}: decoder MUST use `struct.unpack(\"<I\", ...)` for "
                f"the section_total prefix — uint32 LE wire format"
            )

    # Encoder side: each declared encoder must produce the matching prefix.
    for rel in _PER_TENSOR_K_ENCODER_PATHS:
        path = root / rel
        if not path.is_file():
            violations.append(
                f"{rel}: declared per-tensor-K encoder MISSING — was it "
                f"renamed? Update _PER_TENSOR_K_ENCODER_PATHS."
            )
            continue
        text = path.read_text(encoding="utf-8")
        if 'struct.pack("<I"' not in text and "struct.pack('<I'" not in text:
            violations.append(
                f"{rel}: encoder MUST emit `struct.pack(\"<I\", section_total)` "
                f"to match the decoder's `<I` prefix wire format"
            )

    if verbose:
        if violations:
            print(
                f"  [harden-per-tensor-K-wireformat] {len(violations)} "
                f"violation(s) across {n_pairs} encoder/decoder pair(s)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [harden-per-tensor-K-wireformat] OK: {n_pairs} "
                f"encoder/decoder pair(s) have matching wire format"
            )
    if violations and strict:
        raise PreflightError(
            "PER-TENSOR-K WIRE FORMAT VIOLATIONS:\n  • "
            + "\n  • ".join(violations)
        )
    return violations


# Evidence files that may carry rows with `family_falsified` / `falsification_scope`.
_EVIDENCE_FILES = (
    "reports/cathedral_autopilot_evidence.jsonl",
    "reports/raw/pr101_omega_opt_evidence.jsonl",
)


def check_evidence_row_has_falsification_scope_when_negative(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """STRICT: negative evidence with ``family_falsified=False`` MUST also set
    ``falsification_scope`` (non-empty string).

    Per CLAUDE.md ``forbidden_premature_class_level_falsification``: a single
    config's failure does NOT extend to the whole technique class. The
    ``falsification_scope`` field names the exact tested config so future
    audits can re-open the class with a different config.

    Positive/proxy CPU-build rows may still carry ``family_falsified=False`` as
    a promotion guard; that alone does not make them falsification evidence.
    Conversely: ``family_falsified=True`` is FORBIDDEN for any row that did
    not name research-path exhaustion + grand-council consensus (per CLAUDE.md
    "KILL is the LAST RESORT"). This check warns on any True value too.
    """
    root = Path(repo_root or REPO_ROOT)
    violations: list[str] = []
    n_rows = 0
    n_files = 0
    for rel in _EVIDENCE_FILES:
        path = root / rel
        if not path.is_file():
            continue
        n_files += 1
        for lineno, line in enumerate(path.read_text(encoding="utf-8").splitlines(), 1):
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                violations.append(
                    f"{rel}:{lineno}: malformed JSON line"
                )
                continue
            n_rows += 1
            if not isinstance(row, dict):
                continue
            if "family_falsified" not in row:
                continue
            ff = row["family_falsified"]
            scope = row.get("falsification_scope", "")
            grade = str(row.get("evidence_grade", "")).lower()
            verdict = str(row.get("contest_dispatch_verdict", "")).lower()
            status = str(row.get("measured_config_status", "")).lower()
            blockers = row.get("dispatch_blockers", [])
            blocker_text = " ".join(
                str(blocker).lower() for blocker in blockers
            ) if isinstance(blockers, list) else ""
            negative_or_retired = any(
                token in " ".join([grade, verdict, status, blocker_text])
                for token in (
                    "a-negative",
                    "exact-negative",
                    "negative",
                    "retired",
                    "falsified",
                )
            )
            if (
                ff is False
                and negative_or_retired
                and not (isinstance(scope, str) and scope.strip())
            ):
                technique = row.get("technique", "<unknown>")
                violations.append(
                    f"{rel}:{lineno}: technique={technique!r} has "
                    f"family_falsified=False but falsification_scope is "
                    f"empty/missing. Per CLAUDE.md "
                    f"forbidden_premature_class_level_falsification: every "
                    f"negative non-family-falsifying row must NAME the tested config so "
                    f"reactivation criteria are explicit."
                )
            if ff is True:
                technique = row.get("technique", "<unknown>")
                violations.append(
                    f"{rel}:{lineno}: technique={technique!r} sets "
                    f"family_falsified=True — per CLAUDE.md \"KILL is the "
                    f"LAST RESORT\", this requires research-path exhaustion + "
                    f"grand-council consensus + reactivation criteria. "
                    f"Default for one-config failure is "
                    f"DEFERRED-pending-research."
                )
    if verbose:
        if violations:
            print(
                f"  [harden-falsification-scope] {len(violations)} "
                f"violation(s) across {n_rows} row(s) / {n_files} file(s)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [harden-falsification-scope] OK: {n_rows} evidence "
                f"row(s) across {n_files} file(s) all consistent"
            )
    if violations and strict:
        raise PreflightError(
            "EVIDENCE ROW FALSIFICATION SCOPE VIOLATIONS:\n  • "
            + "\n  • ".join(violations)
            + "\n\nReference: CLAUDE.md "
            "forbidden_premature_class_level_falsification + "
            "\"KILL is the LAST RESORT\"."
        )
    return violations


def check_137531_candidate_decoder_path_wired(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """STRICT: if the cross-paradigm 137,531 B candidate evidence row exists
    in ``reports/cathedral_autopilot_evidence.jsonl``, the decoder side MUST
    be wired (i.e. the candidate's submission_dir must exist with inflate.py
    + inflate.sh).

    Closes the "evidence row points at a decoder path that doesn't exist"
    bug class. The HARDEN-2026-05-08 audit found the 137,531 B record landed
    via the byte-anchor proxy but the decoder may be a separate WIRE-DECODER
    subagent deliverable; this check enforces presence at preflight time
    once the row appears.
    """
    root = Path(repo_root or REPO_ROOT)
    evidence_path = root / "reports" / "cathedral_autopilot_evidence.jsonl"
    violations: list[str] = []

    rows_with_137531 = 0
    if evidence_path.is_file():
        for lineno, line in enumerate(
            evidence_path.read_text(encoding="utf-8").splitlines(), 1
        ):
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                continue
            if not isinstance(row, dict):
                continue
            tech = (row.get("technique") or "").lower()
            bytes_field = row.get("empirical_archive_bytes") or row.get("bytes_out")
            is_target_row = (
                "cross_paradigm" in tech
                or "admm_x_continuous_k" in tech
                or "admm_continuous_k_plus_op1_finalizer" in tech
            )
            if is_target_row and isinstance(bytes_field, int) and 130_000 <= bytes_field <= 145_000:
                rows_with_137531 += 1
                # Check if any submission_dir exists for this candidate.
                # Conservative: the 137,531 B candidate is the ADMM × continuous-K
                # + Op1 finalizer, which depends on WIRE-DECODER's deliverable.
                # Until the decoder is wired, we accept either:
                #   (a) presence of the Path B step 6 ADMM-only decoder (already
                #       wired in commit 82bfc648), OR
                #   (b) explicit `decoder_pending_wire_decoder_subagent=True`
                #       flag on the row.
                step6_decoder = (
                    root
                    / "experiments/results/admm_x_lossy_coarsening_path_b_step6_"
                    "20260508T060435Z/submission_dir/inflate.py"
                )
                row_has_pending = bool(
                    row.get("decoder_pending_wire_decoder_subagent")
                )
                if not step6_decoder.is_file() and not row_has_pending:
                    violations.append(
                        f"reports/cathedral_autopilot_evidence.jsonl:{lineno}: "
                        f"row claims {bytes_field:,} B cross-paradigm candidate "
                        f"but neither the Path B step 6 decoder "
                        f"(experiments/results/admm_x_lossy_coarsening_path_b_step6_"
                        f"20260508T060435Z/submission_dir/inflate.py) exists nor "
                        f"the row sets `decoder_pending_wire_decoder_subagent=True`"
                    )
    if verbose:
        if violations:
            print(
                f"  [harden-137531-decoder] {len(violations)} violation(s) "
                f"across {rows_with_137531} target row(s)"
            )
            for v in violations[:5]:
                print(f"    • {v}")
        else:
            print(
                f"  [harden-137531-decoder] OK: {rows_with_137531} "
                f"cross-paradigm row(s) have decoder wired or pending-flag set"
            )
    if violations and strict:
        raise PreflightError(
            "137531 B CANDIDATE DECODER WIRING VIOLATIONS:\n  • "
            + "\n  • ".join(violations)
            + "\n\nReference: HARDEN-2026-05-08 mandate. The cross-paradigm "
            "byte-anchor evidence row must point at a wired decoder OR "
            "explicitly mark itself pending the WIRE-DECODER subagent."
        )
    return violations


# ─── BUGCLASSES B1-B8 (2026-05-08): session bug-class extinction ──────────────
#
# Each helper wraps a tools/check_<name>.py scanner and follows the canonical
# preflight wrapper pattern (see check_lane_smoke_signal_nontrivial). All seven
# scanners are subprocess-importable Python modules that expose `scan(repo)`
# returning a list of dataclass `Finding` records with at minimum
# `__str__`-able fields.

def _run_bugclass_scanner(
    *,
    helper_relpath: str,
    label: str,
    error_class: type,
    repo_root: str | Path | None,
    strict: bool,
    verbose: bool,
) -> list[str]:
    """Generic wrapper: load tools/<helper>.py, call scan(), format findings."""
    root = Path(repo_root or REPO_ROOT)
    helper_path = REPO_ROOT / helper_relpath
    if not helper_path.is_file():
        msg = f"{label} scanner missing: {helper_path}"
        if strict:
            raise error_class(msg)
        return [msg]
    spec = importlib.util.spec_from_file_location(
        f"_pact_bugclass_{label}", helper_path
    )
    if spec is None or spec.loader is None:
        msg = f"cannot import {label} scanner: {helper_path}"
        if strict:
            raise error_class(msg)
        return [msg]
    module = importlib.util.module_from_spec(spec)
    sys.modules[spec.name] = module
    spec.loader.exec_module(module)
    findings = module.scan(root)
    violations: list[str] = []
    for f in findings:
        if hasattr(f, "rel_path"):
            violations.append(
                f"{getattr(f, 'rel_path', '?')}:{getattr(f, 'lineno', getattr(f, 'line_number', 0))}: "
                f"{getattr(f, 'reason', str(f))[:200]}"
            )
        elif hasattr(f, "file_rel"):
            violations.append(
                f"{getattr(f, 'file_rel', '?')}:{getattr(f, 'line_number', 0)}: "
                f"{getattr(f, 'reason', str(f))[:200]}"
            )
        elif hasattr(f, "manifest_rel"):
            violations.append(
                f"{getattr(f, 'manifest_rel', '?')}: "
                f"{getattr(f, 'reason', str(f))[:200]}"
            )
        else:
            violations.append(str(f)[:200])
    if verbose:
        if violations:
            print(f"  [{label}] {len(violations)} violation(s)")
            for v in violations[:5]:
                print(f"    • {v}")
            if len(violations) > 5:
                print(f"    … (+{len(violations) - 5} more)")
        else:
            print(f"  [{label}] OK")
    if violations and strict:
        raise error_class(
            f"{label.upper()} VIOLATIONS:\n  • "
            + "\n  • ".join(violations[:50])
        )
    return violations


