def check_public_pr_intake_clones_pristine(
    *,
    repo_root: str | Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Check 109 — public PR intake clones MUST be pristine bytes-identical to upstream.

    Bug class: a scanner finding inside a public PR intake clone is "fixed"
    by adding an inline waiver comment to the clone's source file. This
    corrupts source provenance — later replay/source audits no longer match
    the public PR head, and preflight cleanliness becomes dependent on
    local-only edits not present upstream. Public PR clones under
    ``experiments/results/public_pr*_intake_*/`` are forensic inputs for
    public-frontier custody (CLAUDE.md "Public frontier watch and intake")
    and are subject to the "Non-Negotiable Upstream Rule".

    Real incident: 2026-05-08 codex adversarial review HIGH finding
    surfaced 39 in-place ``KL_BATCHMEAN_OK`` waiver comments across 8
    dirty clones (``submissions/{fp4_mask_gen,neural_inflate,ph4ntom_drv,
    quantizr,svtav1_dilated_ren}/...py``). The KL-batchmean scanner had
    already added ``_intake_`` to its ``_VENDORED_PATH_MARKERS`` exclusion
    list (``src/tac/preflight.py:5113``); the inline waivers were dead
    code at the time of review, but they still corrupted source
    provenance. See:
      * ``.omx/research/codex_finding_2_dirty_clone_revert_inventory_20260508.md``
      * ``feedback_codex_finding_2_public_intake_pristine_FIXED_20260508.md``

    Static check: discover all clones under
    ``experiments/results/public_pr*_intake_*/`` (and the canonical
    ``{source,repo,pr*_src}/{repo,...}`` subdirs), then for each clone
    that is itself a git repo (``.git`` dir or file present), refuse if
    ``git -C <clone> status --short`` returns non-empty. Replacement
    mechanism for any LEGITIMATE waiver lives in
    ``reverse_engineering/public_pr_waiver_manifest.json`` (committed
    metadata, not inline edits).

    Lands at 0 live violations (after 2026-05-08 revert). Ships STRICT
    directly per the Lane A pattern.
    """
    import concurrent.futures
    import subprocess
    root = Path(repo_root) if repo_root is not None else REPO_ROOT
    violations: list[str] = []
    n_scanned = 0
    n_skipped_not_git = 0

    # Discovery: every directory matching public_pr*_intake_* under
    # experiments/results/ (recursively, up to 4 levels deep) — covers
    # the canonical layouts:
    #   experiments/results/public_pr*_intake_*/source/
    #   experiments/results/public_pr*_intake_*/repo/
    #   experiments/results/public_pr*_intake_*/pr*_src/repo/
    #   experiments/results/public_pr_archive_*/public_pr*_intake_*/
    #   experiments/results/public_pr_intake_full/public_pr*_intake_*/
    er = root / "experiments" / "results"
    if not er.is_dir():
        if verbose:
            print(f"  [public-pr-intake-pristine] OK: no experiments/results/ dir")
        return []

    # Find every dir whose path contains _intake_ AND is a git repo
    # (.git either a directory or a file pointing to gitdir).
    candidate_clones: list[Path] = []
    for child in er.rglob("*_intake_*"):
        if not child.is_dir():
            continue
        # Common subdirs are the actual clone roots.
        for sub in ("source", "repo", "pr91_src/repo"):
            cand = child / sub
            git_marker = cand / ".git"
            if git_marker.exists():
                candidate_clones.append(cand)
        # The intake_*_auto layout has the clone root directly at the
        # intake dir (no source/repo subdir). Detect via .git presence.
        git_marker_root = child / ".git"
        if git_marker_root.exists():
            candidate_clones.append(child)

    # Deduplicate paths (rglob can hit nested intake dirs twice).
    seen: set[Path] = set()
    unique_clones: list[Path] = []
    for c in candidate_clones:
        rp = c.resolve()
        if rp in seen:
            continue
        seen.add(rp)
        unique_clones.append(c)

    def _git_status_short(clone: Path) -> tuple[Path, subprocess.CompletedProcess[str] | None]:
        try:
            result = subprocess.run(
                ["git", "-C", str(clone), "status", "--short"],
                capture_output=True, text=True, timeout=30,
            )
        except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
            return clone, None
        if result.returncode != 0:
            return clone, None
        return clone, result

    status_by_clone: dict[Path, subprocess.CompletedProcess[str] | None] = {}
    if unique_clones:
        max_workers = min(8, len(unique_clones))
        with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as pool:
            for clone, result in pool.map(_git_status_short, unique_clones):
                status_by_clone[clone] = result

    for clone in unique_clones:
        n_scanned += 1
        result = status_by_clone.get(clone)
        if result is None:
            n_skipped_not_git += 1
            continue
        status_lines = [ln for ln in result.stdout.splitlines() if ln.strip()]
        if not status_lines:
            continue
        # Codex verification HIGH-1 (2026-05-08 evening): the original gate
        # only flagged text edits via `git diff --numstat` and silently let
        # untracked files + binary/LFS payload mutations pass. That broke
        # public-frontier provenance custody — a clone could carry added
        # waiver files or mutated binary payloads and still pass strict.
        # Fix: any non-empty `git status --short` is a violation by default.
        # The single explicit exception is git-LFS smudge state (pointer
        # vs. fully-smudged content) which is provably non-corrupting; we
        # require `git lfs status` to confirm every dirty entry is an
        # LFS-managed pointer ↔ content mismatch and nothing else.
        all_dirty_lines = status_lines

        def _status_path(ln: str) -> str:
            # `git status --short` is a fixed two-column status plus a
            # separator. Do not call `.strip()` on the whole status output:
            # it removes the leading worktree-status column on the first
            # line (`" M path"` -> `"M path"`) and corrupts `ln[3:]`.
            if ln.startswith("?? "):
                return ln[3:].strip()
            if len(ln) >= 3 and ln[2] == " ":
                return ln[3:].strip()
            # Defensive fallback for porcelain-like rows whose leading
            # status-space was already stripped by older callers/logs.
            parts = ln.split(None, 1)
            return parts[1].strip() if len(parts) == 2 else ""
        # Probe LFS-managed paths via `git lfs status`. If the command
        # exists AND every dirty entry is in its output AND no untracked
        # files (?? prefix) exist, the dirty state is LFS-only and benign.
        is_lfs_only_dirty = False
        try:
            lfs_check = subprocess.run(
                ["git", "-C", str(clone), "lfs", "status", "--porcelain"],
                capture_output=True, text=True, timeout=30,
            )
        except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
            lfs_check = None
        if lfs_check is not None and lfs_check.returncode == 0:
            lfs_paths = set()
            for ln in lfs_check.stdout.strip().split("\n"):
                if not ln.strip():
                    continue
                # `git lfs status --porcelain` rows: "<status> <path>"
                parts = ln.split(None, 1)
                if len(parts) >= 2:
                    lfs_paths.add(parts[1].strip())
            untracked = [
                ln for ln in all_dirty_lines if ln.startswith("??")
            ]
            if not untracked and lfs_paths:
                # Map dirty entries (XY <path>) to paths and verify all are LFS-managed.
                dirty_paths = []
                for ln in all_dirty_lines:
                    p = _status_path(ln)
                    if p:
                        dirty_paths.append(p)
                if dirty_paths and all(p in lfs_paths for p in dirty_paths):
                    is_lfs_only_dirty = True
        if is_lfs_only_dirty:
            # Provably benign: every dirty entry is an LFS pointer-vs-content
            # state mismatch and nothing is untracked. Skip without violation.
            continue
        # Anything else dirty (untracked files, binary edits, text edits,
        # mixed) is a custody violation. Categorize for the operator.
        text_edits: list[str] = []
        binary_or_lfs_edits: list[str] = []
        untracked_or_other: list[str] = []
        try:
            ns = subprocess.run(
                ["git", "-C", str(clone), "diff", "--numstat"],
                capture_output=True, text=True, timeout=30,
            )
        except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
            ns = None
        if ns is not None and ns.returncode == 0:
            for line in ns.stdout.strip().split("\n"):
                if not line:
                    continue
                parts = line.split("\t")
                if len(parts) < 3:
                    continue
                added, removed, path = parts[0], parts[1], parts[2]
                if added == "-" and removed == "-":
                    binary_or_lfs_edits.append(path)
                else:
                    text_edits.append(f"{path} (+{added}/-{removed})")
        # Capture any status entries not surfaced by diff (untracked, etc).
        for ln in all_dirty_lines:
            if ln.startswith("??"):
                untracked_or_other.append(_status_path(ln))
        rel = clone.relative_to(root) if clone.is_absolute() else clone
        # Build a category-aware violation message. The new gate (HIGH-1)
        # treats untracked + binary as first-class violations alongside text
        # edits, since codex 2026-05-08 verification found the previous
        # text-only check let waiver files and binary mutations pass strict.
        parts_msg: list[str] = []
        if text_edits:
            preview_lines = text_edits[:5]
            preview = "; ".join(preview_lines)
            extra = (
                f" (+{len(text_edits) - 5} more)"
                if len(text_edits) > 5
                else ""
            )
            parts_msg.append(f"{len(text_edits)} text edit(s): [{preview}{extra}]")
        if binary_or_lfs_edits:
            parts_msg.append(
                f"{len(binary_or_lfs_edits)} binary/LFS payload edit(s): "
                f"[{', '.join(binary_or_lfs_edits[:3])}"
                + ("..." if len(binary_or_lfs_edits) > 3 else "")
                + "] (NOT exempted by `git lfs status` — these are real "
                "payload mutations, not pointer-vs-content noise)"
            )
        if untracked_or_other:
            parts_msg.append(
                f"{len(untracked_or_other)} untracked file(s): "
                f"[{', '.join(untracked_or_other[:3])}"
                + ("..." if len(untracked_or_other) > 3 else "")
                + "] (e.g. local-only waiver files corrupt forensic state)"
            )
        violations.append(
            f"{rel}: dirty git status — public PR intake clone has "
            + "; ".join(parts_msg)
            + f". Restore via `git -C {rel} checkout -- .` (and remove "
            "untracked files). Put any waiver rationale in "
            "`reverse_engineering/public_pr_waiver_manifest.json` "
            "instead of editing the clone in place."
        )

    if verbose and violations:
        print(
            f"  [public-pr-intake-pristine] {len(violations)} dirty clone(s) "
            f"across {n_scanned} scanned ({n_skipped_not_git} skipped non-git):"
        )
        for v in violations:
            print(f"    • {v}")
    elif verbose:
        print(
            f"  [public-pr-intake-pristine] OK: {n_scanned} clone(s) clean "
            f"({n_skipped_not_git} skipped non-git)"
        )

    if violations and strict:
        raise MetaBugViolation(
            "Public PR intake clones must remain pristine bytes-identical "
            "to upstream PR head. Inline waivers in clone source files "
            "corrupt source provenance and break replay/audit. Found "
            f"{len(violations)} dirty clone(s):\n"
            + "\n".join(f"  • {v}" for v in violations)
            + "\n\nRevert with `git -C <clone> checkout -- .`. Put any "
            "legitimate waiver rationale in "
            "`reverse_engineering/public_pr_waiver_manifest.json` "
            "(committed metadata, not inline clone edits). See "
            "`.omx/research/codex_finding_2_dirty_clone_revert_inventory_20260508.md`."
        )
    return violations


