def _commit_introduced_files(
    repo_root: Path, n_commits: int, since_sha: str | None = None,
) -> dict[str, list[str]]:
    """Return {commit_sha: [paths]} for files added/modified in the last N commits.

    Uses `git log -n <n_commits> --name-only --diff-filter=AM` to capture
    introduced or modified file paths. Renames are folded onto the new path
    via diff-filter R (added back via T below).
    """
    paths_by_sha: dict[str, list[str]] = {}
    cmd = [
        "git", "log",
        f"-n{n_commits}",
        "--name-only",
        "--diff-filter=AMRT",
        "--pretty=format:%H",
    ]
    try:
        result = subprocess.run(
            cmd,
            cwd=repo_root,
            capture_output=True,
            text=True,
            timeout=15,
            check=False,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return paths_by_sha
    if result.returncode != 0:
        return paths_by_sha
    cur_sha: str | None = None
    cur_paths: list[str] = []
    for raw_line in result.stdout.splitlines():
        line = raw_line.strip()
        if not line:
            if cur_sha is not None:
                paths_by_sha[cur_sha] = cur_paths
                cur_sha = None
                cur_paths = []
            continue
        if re.fullmatch(r"[0-9a-f]{40}", line):
            if cur_sha is not None:
                paths_by_sha[cur_sha] = cur_paths
            cur_sha = line
            cur_paths = []
        else:
            if cur_sha is not None:
                cur_paths.append(line)
    if cur_sha is not None and cur_sha not in paths_by_sha:
        paths_by_sha[cur_sha] = cur_paths
    return paths_by_sha


def _worktree_changed_files(repo_root: Path) -> list[str]:
    """Return tracked dirty/staged + untracked source paths in the worktree."""
    paths: set[str] = set()
    commands = (
        ["git", "diff", "--name-only", "--diff-filter=AMRT", "HEAD"],
        ["git", "ls-files", "--others", "--exclude-standard"],
    )
    for cmd in commands:
        try:
            result = subprocess.run(
                cmd,
                cwd=repo_root,
                capture_output=True,
                text=True,
                timeout=15,
                check=False,
            )
        except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
            continue
        if result.returncode != 0:
            continue
        for raw_line in result.stdout.splitlines():
            rel = raw_line.strip()
            if rel:
                paths.add(rel)
    return sorted(paths)


# Path prefixes that are scanned for lane_id references. Per the spec:
# src/tac/, tools/, experiments/, scripts/.
_LANE_ID_SCAN_PREFIXES: tuple[str, ...] = (
    "src/tac/",
    "tools/",
    "experiments/",
    "scripts/",
)

# File extensions worth scanning. Other extensions (e.g., .json / .md / .yaml)
# typically carry intentional lane_id references in evidence/manifest form;
# the gate is intentionally scoped to source-of-truth code surfaces where a
# lane_id reference creates a binding usage.
_LANE_ID_SCAN_EXTENSIONS: tuple[str, ...] = (
    ".py",
    ".sh",
)

# Test-fixture marker (per the spec, sister-of FAKE_LANE_OK pattern).
_LANE_ID_FAKE_WAIVER_RE = re.compile(
    r"#\s*FAKE_LANE_OK\s*:\s*[^\n]+",
    re.IGNORECASE,
)

# File-level waiver: a single `# FAKE_LANE_OK_FILE:<reason>` in the first
# 30 lines exempts the entire test file (used for files like
# `test_check_lane_pre_registered_before_work_starts.py` whose entire
# purpose is to test the gate via dozens of fake lane_id fixtures — adding
# per-line waivers would be noise and would mask real future violations).
_LANE_ID_FAKE_WAIVER_FILE_RE = re.compile(
    r"#\s*FAKE_LANE_OK_FILE\s*:\s*[^\n]+",
    re.IGNORECASE,
)

_LANE_ID_FILE_WAIVER_ALLOWED_RELS: frozenset[str] = frozenset({
    # Test files whose entire purpose is to construct fake lane_id fixtures
    # to exercise the gate. Per Check #126 file-level waiver semantics —
    # additions to this allowlist are intentional and require council/operator
    # justification (the FAKE_LANE_OK_FILE marker on its own is not enough to
    # avoid abuse; only files in this allowlist OR per-line FAKE_LANE_OK
    # markers are accepted).
    "src/tac/tests/test_check_lane_pre_registered_before_work_starts.py",
    "src/tac/tests/test_check_representation_lane_has_archive_grammar.py",
    "src/tac/tests/test_check_subagent_landing_has_solver_wire_in.py",
    "src/tac/tests/test_lane_maturity_harness.py",
    "src/tac/tests/test_continual_learning.py",
    "src/tac/tests/test_preflight_subagent_coherence.py",
})


def _line_or_window_has_fake_waiver(lines: list[str], lineno: int, window: int = 5) -> bool:
    """Return True iff the same line OR within ``window`` lines above carries
    a `# FAKE_LANE_OK:<reason>` marker.
    """
    start = max(0, lineno - window)
    end = min(len(lines), lineno + 1)
    for i in range(start, end):
        if _LANE_ID_FAKE_WAIVER_RE.search(lines[i]):
            return True
    return False


def _is_test_path(rel: str) -> bool:
    """Return True iff `rel` is a test-fixture path."""
    parts = rel.split("/")
    return any(p == "tests" for p in parts) or any(
        p.startswith("test_") for p in parts
    )


def _file_level_fake_lane_waiver_applies(rel: str, lines: list[str]) -> bool:
    """Return True only for the dedicated Check #126 self-test file."""
    if rel not in _LANE_ID_FILE_WAIVER_ALLOWED_RELS:
        return False
    head = "\n".join(lines[:30])
    return bool(_LANE_ID_FAKE_WAIVER_FILE_RE.search(head))


def check_lane_pre_registered_before_work_starts(
    *,
    repo_root: str | Path | None = None,
    n_commits: int = 50,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #126 — referenced lane_ids must be pre-registered in the registry.

    Refuses subagent commits (last ``n_commits``) whose introduced files
    under ``src/tac/`` / ``tools/`` / ``experiments/`` / ``scripts/``
    reference a ``lane_<NAME>`` token that does NOT appear in
    ``.omx/state/lane_registry.json``.

    Acceptance/exemption rules:
      - Test fixtures (``*/tests/*`` paths or filenames starting with
        ``test_``) are exempt iff the line carries (or has within 5 lines
        above) a ``# FAKE_LANE_OK:<reason>`` marker.
      - Common helper-name tokens (``lane_id``, ``lane_class``,
        ``lane_registry``, ``lane_maturity``, etc.) are blocklisted and
        never treated as lane_id references.

    Bug class: parallel subagents inventing the same fictional lane_id
    silently. Pre-registration at Level 0 (SKETCH) via
    ``tools/lane_maturity.py add-lane <id> --name <...> --phase <N>``
    forces coordination at the moment a lane has a name.

    Held warn-only on initial landing (2026-05-09); flip to STRICT after
    backfill drives live count to 0.

    Memory:
      feedback_unified_lagrangian_action_principle_GR_style_20260509.md
      CLAUDE.md "Lane maturity registry" lifecycle discipline section
    """
    root = Path(repo_root or REPO_ROOT)
    registry_path = root / ".omx" / "state" / "lane_registry.json"
    if not registry_path.is_file():
        msg = f"lane registry not found: {registry_path}"
        if verbose:
            print(f"  [lane-pre-registered] WARN: {msg}")
        if strict:
            raise PreflightError(
                "check_lane_pre_registered_before_work_starts: " + msg
            )
        return [msg]

    try:
        registry_data = json.loads(registry_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as e:
        msg = f"could not parse lane registry: {e}"
        if verbose:
            print(f"  [lane-pre-registered] WARN: {msg}")
        if strict:
            raise PreflightError(
                "check_lane_pre_registered_before_work_starts: " + msg
            )
        return [msg]

    registered_ids: set[str] = set()
    for lane in registry_data.get("lanes", []):
        lid = lane.get("id")
        if isinstance(lid, str) and lid:
            registered_ids.add(lid)
        # Also accept aliases if a lane declares them (forward-compat).
        for ak in ("aliases", "alias"):
            for alias in lane.get(ak, []) or []:
                if isinstance(alias, str) and alias:
                    registered_ids.add(alias)

    paths_by_source = _commit_introduced_files(root, n_commits)
    worktree_paths = _worktree_changed_files(root)
    if worktree_paths:
        paths_by_source["WORKTREE"] = worktree_paths
    if not paths_by_source:
        if verbose:
            print(
                f"  [lane-pre-registered] OK "
                f"(no commits or worktree changes resolvable; "
                f"git log/diff empty or git unavailable)"
            )
        return []

    violations: list[str] = []
    scanned_files = 0
    scanned_lines = 0
    for source, paths in paths_by_source.items():
        for rel in paths:
            # Filter to scan-prefix-and-extension subset.
            if not rel.endswith(_LANE_ID_SCAN_EXTENSIONS):
                continue
            if not any(rel.startswith(p) for p in _LANE_ID_SCAN_PREFIXES):
                continue
            file_path = root / rel
            if not file_path.is_file():
                # File may have been deleted in a later commit; skip cleanly.
                continue
            try:
                text = file_path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            scanned_files += 1
            lines = text.splitlines()
            scanned_lines += len(lines)
            is_test = _is_test_path(rel)
            if is_test and _file_level_fake_lane_waiver_applies(rel, lines):
                continue
            for lineno, line in enumerate(lines):
                # Quick prefilter — skip lines without "lane_" prefix.
                if "lane_" not in line:
                    continue
                for m in _LANE_ID_REFERENCE_RE.finditer(line):
                    # The regex has two capture groups (double / single quote);
                    # exactly one will be non-None per match.
                    token = m.group(1) or m.group(2)
                    if token is None:
                        continue
                    if token in _LANE_ID_REFERENCE_BLOCKLIST:
                        continue
                    if token in registered_ids:
                        continue
                    # Test fixture exemption: tests path AND FAKE_LANE_OK marker.
                    if is_test and _line_or_window_has_fake_waiver(lines, lineno):
                        continue
                    violations.append(
                        f"[Check 126] {rel}:{lineno + 1} (source {source[:8]}): "
                        f"references unregistered lane_id {token!r}. "
                        "Pre-register via "
                        f"`tools/lane_maturity.py add-lane {token} "
                        "--name <...> --phase <N>` BEFORE work starts. "
                        "Test fixtures may add "
                        "'# FAKE_LANE_OK:<reason>' on the same line "
                        "or within 5 lines above."
                    )
                    # Only one violation per (file, lineno) — avoid noise on
                    # lines that mention the same lane_id multiple times.
                    break

    if verbose:
        if violations:
            print(
                f"  [lane-pre-registered] {len(violations)} reference(s) to "
                f"unregistered lane_id(s) (scanned: {scanned_files} file(s), "
                f"{scanned_lines} line(s) across {len(paths_by_source)} source(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                f"  [lane-pre-registered] OK "
                f"({scanned_files} file(s) across {len(paths_by_source)} source(s) "
                f"scanned; 0 unregistered lane references)"
            )

    if violations and strict:
        raise PreflightError(
            "check_lane_pre_registered_before_work_starts: "
            f"{len(violations)} reference(s) to unregistered lane_id(s); "
            "first 3:\n  "
            + "\n  ".join(v[:400] for v in violations[:3])
            + "\n\nFix: pre-register via "
            "`tools/lane_maturity.py add-lane <lane_id> --name <...> "
            "--phase <N>` BEFORE editing code that references the lane. "
            "Test fixtures may add '# FAKE_LANE_OK:<reason>' on the same line."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #127 — authoritative tag emission must go through validate_custody
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round-2 HIGH 2, 2026-05-09): direct `.evidence_tag in
# AUTHORITATIVE_TAGS` checks accept anchors with mismatched axis or non-1:1
# contest-compliant hardware. The `validate_custody` validator on
# `tac.continual_learning.ContestResult` checks tag + axis +
# hardware_substrate jointly. This gate refuses any code site under
# `src/tac/`, `tools/`, or `experiments/` that bypasses the validator by
# matching the tag string directly against `AUTHORITATIVE_TAGS` (or the
# legacy short-form `[contest-CPU]` literal) without an adjacent
# `validate_custody` / `validate_custody_verdict` call OR a same-line
# waiver `# CUSTODY_VALIDATOR_OK:<reason>`.

_AUTHORITATIVE_TAG_LITERALS: tuple[str, ...] = (
    "[contest-CUDA]",
    "[contest-CPU GHA Linux x86_64]",
    "[contest-CPU GHA]",
    "[contest-CPU]",
)

_CUSTODY_VALIDATOR_TOKENS: tuple[str, ...] = (
    "validate_custody",
    "validate_custody_verdict",
    "posterior_update_locked",
    "posterior_update(",
)

_CUSTODY_WAIVER_MARKER = "CUSTODY_VALIDATOR_OK"


def _line_window_contains_any(
    lines: list[str],
    lineno: int,
    tokens: tuple[str, ...],
    *,
    before: int = 4,
    after: int = 4,
) -> bool:
    start = max(0, lineno - before)
    end = min(len(lines), lineno + after + 1)
    window = "\n".join(lines[start:end])
    return any(tok in window for tok in tokens)


def _line_has_authoritative_tag_bypass_pattern(line: str) -> bool:
    """Return True for tag-only predicates that can promote without custody."""
    if "`" in line:
        return False
    if "AUTHORITATIVE_TAGS" in line and re.search(
        r"\b(?:not\s+in|in)\s+AUTHORITATIVE_TAGS\b", line
    ):
        return True
    tag_literal = r"['\"]\[contest-(?:CPU|CUDA)[^'\"]*['\"]"
    if re.search(rf"(?:==|!=)\s*{tag_literal}", line):
        return True
    if re.search(rf"{tag_literal}\s*(?:==|!=)", line):
        return True
    if re.search(r"\.(?:startswith|endswith)\(\s*['\"]\[contest-(?:CPU|CUDA)", line):
        return True
    return False


def check_authoritative_tag_requires_custody_metadata(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #127 — authoritative-tag literals must route through validate_custody.

    Refuses code sites that match an authoritative-tag literal string
    (``"[contest-CUDA]"``, ``"[contest-CPU GHA Linux x86_64]"``, etc.)
    against ``AUTHORITATIVE_TAGS`` without either:

    1. An adjacent ``validate_custody`` / ``validate_custody_verdict``
       call OR a routing-through-``posterior_update`` /
       ``posterior_update_locked`` invocation in the same function/window,
       OR
    2. A same-line waiver comment ``# CUSTODY_VALIDATOR_OK:<reason>``.

    Held warn-only initially per the directive — flip to STRICT after
    live count drives to 0.

    Bug class: codex round-2 HIGH 2 (2026-05-09). Empirical anchors with
    a CPU tag on a non-GHA Linux host (or CUDA tag with axis mismatch)
    were promoted into the posterior because the tag-only predicate
    `is_authoritative()` did not validate substrate / axis. The custody
    validator now checks those jointly; this gate prevents the bypass
    pattern from coming back.

    Memory: feedback_codex_round2_custody_concurrency_fix_landed_20260509.md
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [root / "src" / "tac", root / "tools", root / "experiments"]
    # Exclude the canonical implementation file (which legitimately holds the
    # tag literals + validator definitions) and the test files exercising it.
    EXCLUDED = {
        root / "src" / "tac" / "continual_learning.py",
    }

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            rel_py = py.relative_to(root) if py.is_relative_to(root) else py
            rel_py_s = str(rel_py)
            if rel_py_s.startswith("experiments/results/"):
                continue
            if py in EXCLUDED:
                continue
            # Skip tests (they exercise the API legitimately).
            if "/tests/" in str(py) or py.name.startswith("test_"):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter: skip files that don't reference the tag set or
            # literal authoritative tags at all.
            if "AUTHORITATIVE_TAGS" not in text and not any(
                tag in text for tag in _AUTHORITATIVE_TAG_LITERALS
            ):
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                # Skip comment-only lines.
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                if not _line_has_authoritative_tag_bypass_pattern(line):
                    continue
                # Same-line waiver?
                if _CUSTODY_WAIVER_MARKER in line:
                    continue
                if _line_window_contains_any(
                    lines, lineno, _CUSTODY_VALIDATOR_TOKENS
                ):
                    continue
                violations.append(
                    f"[Check 127] {rel_py}:{lineno + 1}: "
                    "authoritative tag predicate without an adjacent "
                    "validate_custody / posterior_update call. "
                    "Per codex round-2 HIGH 2, every authoritative-tag site MUST "
                    "route through `tac.continual_learning.ContestResult."
                    "validate_custody` (or `posterior_update`/`posterior_update_locked`) "
                    "to verify (tag, axis, hardware_substrate) jointly. Add a "
                    "`# CUSTODY_VALIDATOR_OK:<reason>` waiver on the same line "
                    "if the site is intentionally tag-only."
                )

    if verbose:
        if violations:
            print(
                f"  [authoritative-tag-validator] {len(violations)} bypass(es) "
                f"(scanned: {scanned_files} file(s) under src/tac/, tools/, "
                f"experiments/)"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [authoritative-tag-validator] OK "
                f"({scanned_files} file(s) scanned; 0 bypass(es))"
            )

    if violations and strict:
        raise PreflightError(
            "check_authoritative_tag_requires_custody_metadata: "
            f"{len(violations)} bypass(es) of the custody validator; first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: route through `validate_custody`/`posterior_update`."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #128 — continual_learning posterior writes must use the locked path
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round-2 MEDIUM, 2026-05-09): direct `save_posterior`
# calls under parallel harvesters silently drop concurrent updates because
# the load → mutate → write cycle is not atomic. The locked path
# `posterior_update_locked` does load → update → save inside an exclusive
# fcntl lock so concurrent updates of distinct anchors all survive.
# This gate refuses any caller invoking `save_posterior` directly without a
# local `_posterior_lock` context OR a same-line waiver
# `# SAVE_POSTERIOR_LOCKED_OK:<reason>`.


_SAVE_POSTERIOR_WAIVER_MARKER = "SAVE_POSTERIOR_LOCKED_OK"


def check_continual_learning_writes_use_lock(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #128 — continual_learning writes must go through the locked path.

    Refuses code sites under `src/tac/`, `tools/`, or `experiments/` that
    import `save_posterior` from `tac.continual_learning` (or call it
    directly) without:

    1. A local `_posterior_lock` context visible near the direct write, OR
    2. A same-line waiver `# SAVE_POSTERIOR_LOCKED_OK:<reason>`.

    Held warn-only initially per the directive — flip to STRICT after live
    count drives to 0.

    Bug class: codex round-2 MEDIUM (2026-05-09). Bare `save_posterior` +
    fixed `.tmp` path under parallel harvest silently drops concurrent
    updates. The locked path uses `fcntl.flock(LOCK_EX)` on
    `.omx/state/.continual_learning.lock`, reloads inside the lock,
    re-runs the duplicate check, and writes to a UNIQUE temp file.

    Memory: feedback_codex_round2_custody_concurrency_fix_landed_20260509.md
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [root / "src" / "tac", root / "tools", root / "experiments"]
    # The canonical implementation file legitimately defines + uses both
    # symbols. Tests legitimately exercise both. Skip both.
    EXCLUDED = {
        root / "src" / "tac" / "continual_learning.py",
    }

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            rel_py = py.relative_to(root) if py.is_relative_to(root) else py
            rel_py_s = str(rel_py)
            if rel_py_s.startswith("experiments/results/"):
                continue
            if py in EXCLUDED:
                continue
            if "/tests/" in str(py) or py.name.startswith("test_"):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if "save_posterior" not in text:
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                # Direct call to save_posterior (not save_posterior_locked,
                # which doesn't currently exist but reserved as future-compat).
                # Match the bare call form `save_posterior(...)`. Skip
                # imports and diagnostic/error strings.
                if not re.search(r"(^|[^\w.])save_posterior\s*\(", line):
                    continue
                if "`save_posterior" in line:
                    continue
                if stripped.startswith(("\"", "'", "f\"", "f'", "r\"", "r'")):
                    continue
                if _SAVE_POSTERIOR_WAIVER_MARKER in line:
                    continue
                if _line_window_contains_any(
                    lines, lineno, ("_posterior_lock",), before=4, after=1
                ):
                    # The direct write is visibly inside or immediately under
                    # the lock context. A bare posterior_update_locked mention
                    # elsewhere in the file is not sufficient.
                    continue
                violations.append(
                    f"[Check 128] {rel_py}:{lineno + 1}: "
                    "calls `save_posterior(...)` directly without "
                    "`_posterior_lock` context visible in the local line window. "
                    "Per codex round-2 MEDIUM, parallel harvesters "
                    "MUST go through `posterior_update_locked` so the "
                    "load→update→save cycle is atomic under fcntl. Add a "
                    "`# SAVE_POSTERIOR_LOCKED_OK:<reason>` waiver if the site "
                    "is single-writer / serialized externally."
                )

    if verbose:
        if violations:
            print(
                f"  [continual-learning-writes-locked] {len(violations)} "
                f"unlocked save(s) (scanned: {scanned_files} file(s) under "
                "src/tac/, tools/, experiments/)"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [continual-learning-writes-locked] OK "
                f"({scanned_files} file(s) scanned; 0 unlocked save(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_continual_learning_writes_use_lock: "
            f"{len(violations)} unlocked save(s); first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: replace bare `save_posterior(...)` with "
            "`posterior_update_locked(result, ...)` from "
            "`tac.continual_learning`."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #130 — proactive sweep widening of catalog #127's tag-only check
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (proactive META-class custody+concurrency audit, 2026-05-09):
# extends catalog #127 (`AUTHORITATIVE_TAGS` membership) to also catch
# the broader META class:
#
#   - `evidence_grade in {"contest-cuda", ...}` set-membership patterns
#   - `tag.startswith("[contest-CUDA")` / `tag.startswith("[contest-CPU")`
#     substring-prefix patterns
#
# These are the same META class as catalog #127 — code that classifies
# custody / promotion eligibility from a tag string WITHOUT joint
# axis + hardware_substrate + archive_sha256 validation. The proactive
# sweep audit `.omx/research/proactive_custody_concurrency_audit_20260509.md`
# verified the live count is 0 because every existing site routes through
# a joint validator (`validate_custody`, `is_promotable_exact_cuda_evidence`,
# `predispatch_sanity._validate_non_proxy_readiness_evidence`, or fail-closed
# blocker accumulation against archive_sha256 checks).
#
# This gate prevents regression: any future code that introduces a new
# tag-membership predicate must also use one of the validator tokens
# OR add a `# CUSTODY_VALIDATOR_OK:<reason>` waiver.

# Note: the four `tag.startswith(...)` literals below are DETECTION
# PATTERNS used by this gate to scan other files. They are NOT bypass
# code — they are string constants this gate compares against.
# Same-line `CUSTODY_VALIDATOR_OK` waivers tell catalog #127's
# `_line_has_authoritative_tag_bypass_pattern` to skip these meta-pattern
# strings (which would otherwise self-match).
_TAG_GRADE_BYPASS_PATTERNS: tuple[str, ...] = (
    "evidence_grade in {",  # CUSTODY_VALIDATOR_OK: detection-pattern-string
    "evidence_grade.lower() in {",  # CUSTODY_VALIDATOR_OK: detection-pattern-string
    "evidence_grade not in {",  # CUSTODY_VALIDATOR_OK: detection-pattern-string
    "evidence_grade.lower() not in {",  # CUSTODY_VALIDATOR_OK: detection-pattern-string
    'tag.startswith("[contest-CUDA")',  # CUSTODY_VALIDATOR_OK: detection-pattern-string
    'tag.startswith("[contest-CPU")',  # CUSTODY_VALIDATOR_OK: detection-pattern-string
    'evidence_tag.startswith("[contest-CUDA")',  # CUSTODY_VALIDATOR_OK: detection-pattern-string
    'evidence_tag.startswith("[contest-CPU")',  # CUSTODY_VALIDATOR_OK: detection-pattern-string
)

# Files that legitimately implement the joint validators themselves. Other
# fail-closed callers are accepted only when the tag/grade predicate has a
# local validator / blocker context in the nearby line window.
_TAG_GRADE_VALIDATOR_FILES: tuple[str, ...] = (
    "src/tac/continual_learning.py",
    "src/tac/optimization/candidate_evidence_contract.py",
    "tools/predispatch_sanity.py",
)

# 2026-05-09 codex round-3 HIGH 2 fix: the previous accept-token list
# included the bare identifiers `blockers` and `errors`, which are
# generic enough that ANY unrelated `blockers = []` / `errors = []`
# variable in the +/-6 line window silently waived a tag-only custody
# gate. The strict gate failed open. We now require a CONCRETE validator
# call OR an explicit `archive_sha256` / `sha256_file(` reference OR a
# same-line `# CUSTODY_VALIDATOR_OK:<reason>` waiver.
#
# `*_CUSTODY_VALIDATOR_TOKENS` already covers `validate_custody`,
# `validate_custody_verdict`, `posterior_update`, and
# `posterior_update_locked`. The `is_promotable_*` tokens are concrete
# validator-name prefixes (not bare identifiers). `sha256_file(`
# requires the call form so a stray "sha256_file" docstring does not
# silently waive the gate. `archive_sha256` is the canonical promotion
# field — it is a real evidence-grade signal even when it appears as a
# `.get("archive_sha256")` dict key, because every promotion path
# routes through it.
#
# DROPPED: the bare tokens `"blockers"` and `"errors"` were unsafe
# accept-list entries. A function with `blockers = []` somewhere nearby
# does NOT prove that the tag-membership predicate is gated on custody.
# Sites that want fail-closed-blocker semantics now route through the
# joint validator OR carry a `# CUSTODY_VALIDATOR_OK:<reason>` waiver
# naming the blocker scheme. Memory:
# feedback_codex_round3_findings_fix_landed_20260509.md.
_TAG_GRADE_LOCAL_VALIDATOR_TOKENS: tuple[str, ...] = (
    *_CUSTODY_VALIDATOR_TOKENS,
    "is_promotable_exact_cuda_evidence",
    "promotable_exact_cuda_evidence_blockers",
    "sha256_file(",
    "archive_sha256",
)


def check_no_tag_only_custody_validation(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #130 — broader tag/grade membership must route through joint validator.

    Refuses code sites that match a tag/grade membership-check pattern
    (``evidence_grade in {...}``, ``tag.startswith("[contest-CUDA")``, etc.)
    without either:

    1. A local line-window route through a known joint validator
       (``validate_custody`` / ``validate_custody_verdict`` /
       ``posterior_update`` / ``posterior_update_locked`` /
       ``is_promotable_exact_cuda_evidence`` / ``promotable_exact_cuda_evidence_blockers`` /
       ``sha256_file`` / ``archive_sha256``), OR
    2. A same-line waiver comment ``# CUSTODY_VALIDATOR_OK:<reason>``.

    Held warn-only initially per the directive — flip to STRICT after
    live count drives to 0 and stability period elapses.

    Bug class: proactive META-class sweep (2026-05-09). Sister of catalog #127
    which only covered the narrower ``AUTHORITATIVE_TAGS`` membership.

    Memory: feedback_proactive_custody_concurrency_audit_landed_20260509.md
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [root / "src" / "tac", root / "tools", root / "experiments"]
    excluded_files = {root / p for p in _TAG_GRADE_VALIDATOR_FILES}

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            if py in excluded_files:
                continue
            if "/tests/" in str(py) or py.name.startswith("test_"):
                continue
            # Skip vendored public-PR intakes per Check 109.
            if "_intake_" in str(py) or "/comma_lab_public_export/" in str(py):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter
            if not any(pat in text for pat in _TAG_GRADE_BYPASS_PATTERNS):
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                if not any(pat in line for pat in _TAG_GRADE_BYPASS_PATTERNS):
                    continue
                if _CUSTODY_WAIVER_MARKER in line:
                    continue
                if _line_window_contains_any(
                    lines,
                    lineno,
                    _TAG_GRADE_LOCAL_VALIDATOR_TOKENS,
                    before=6,
                    after=6,
                ):
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 130] {rel}:{lineno + 1}: "
                    "tag/grade membership predicate without an adjacent joint "
                    "validator or archive_sha256 check. Per proactive META-class "
                    "audit, every tag/grade gate MUST route through "
                    "`validate_custody` / `is_promotable_exact_cuda_evidence` "
                    "(or accumulate a fail-closed blocker against `archive_sha256`). "
                    "Add a `# CUSTODY_VALIDATOR_OK:<reason>` waiver if the site "
                    "is a read-only filter that does not gate promotion."
                )

    if verbose:
        if violations:
            print(
                f"  [tag-grade-validator-broader] {len(violations)} bypass(es) "
                f"(scanned: {scanned_files} file(s) under src/tac/, tools/, "
                f"experiments/)"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [tag-grade-validator-broader] OK "
                f"({scanned_files} file(s) scanned; 0 bypass(es))"
            )

    if violations and strict:
        raise PreflightError(
            "check_no_tag_only_custody_validation: "
            f"{len(violations)} bypass(es) of the joint custody validator; first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: route tag/grade gate through a joint validator OR accumulate "
            "a fail-closed blocker against archive_sha256."
        )
    return violations


