# Compiled regexes for write detection (compile once, reuse across files).
_BARE_WRITE_OPEN_RE = re.compile(r"\bopen\(\s*([^,)]+),\s*['\"][wxa]b?\+?['\"]")
_BARE_WRITE_TEXT_RE = re.compile(r"\b([A-Za-z_][A-Za-z0-9_.\[\]\(\)]*)\.write_text\s*\(")
_BARE_WRITE_BYTES_RE = re.compile(r"\b([A-Za-z_][A-Za-z0-9_.\[\]\(\)]*)\.write_bytes\s*\(")
_BARE_OS_REPLACE_RE = re.compile(r"\bos\.replace\s*\(\s*[^,]+,\s*([A-Za-z_][A-Za-z0-9_.\[\]\(\)]*)")

# Module-constant assignment binding shared-state path. Caches across files
# so each file only pays one regex compile per scan.
#
# Codex round 8 MEDIUM (2026-05-09, in-place harden of #131): the all-caps
# regex above missed lowercase shared-state path bindings (e.g.
# ``state_path = Path('.omx/state/foo.json')``); the AST companion
# below catches every binding whose RHS contains a shared-state literal,
# regardless of name casing or attribute path.
_BARE_WRITE_SHARED_VAR_RE = re.compile(
    r"^\s*([A-Z_][A-Z0-9_]*)\s*[:=][^=].*?(['\"])([^'\"]*(?:" +
    "|".join(re.escape(m) for m in _SHARED_STATE_PATH_MARKERS) +
    r")[^'\"]*)\2",
    re.MULTILINE,
)


def _bare_write_string_contains_shared_marker(s: str) -> bool:
    return any(m in s for m in _SHARED_STATE_PATH_MARKERS)


def _bare_write_collect_string_constants(node: ast.AST) -> list[str]:
    """Collect every str constant inside a node sub-tree.

    Returns the literal values as Python strings. Used by the AST binding
    collector to detect ``Path('.omx/state/...')``,
    ``base / 'active.json'``, ``f"{base}/active_jobs.json"`` etc.
    """
    constants: list[str] = []
    for sub in ast.walk(node):
        if isinstance(sub, ast.Constant) and isinstance(sub.value, str):
            constants.append(sub.value)
        elif isinstance(sub, ast.JoinedStr):
            # f-string: collect literal segments
            for v in sub.values:
                if isinstance(v, ast.Constant) and isinstance(v.value, str):
                    constants.append(v.value)
    return constants


def _bare_write_target_name_from_assign_target(target: ast.AST) -> str | None:
    """Extract the variable / attribute name that an ``Assign`` target binds.

    Handles:

    - ``ast.Name`` → returns the bare name (e.g. ``state_path``)
    - ``ast.Attribute`` → returns the dotted path (e.g. ``self.foo_path``)
    - tuple/list-pack targets → returns None (rare; callers should ignore)
    """
    if isinstance(target, ast.Name):
        return target.id
    if isinstance(target, ast.Attribute):
        # Build dotted path; bail if value is not a name chain (e.g. call/sub)
        parts: list[str] = []
        cur: ast.AST = target
        while isinstance(cur, ast.Attribute):
            parts.append(cur.attr)
            cur = cur.value
        if isinstance(cur, ast.Name):
            parts.append(cur.id)
            return ".".join(reversed(parts))
        return None
    return None


def _bare_write_collect_shared_vars_ast(text: str) -> set[str]:
    """AST-based shared-state binding collector (codex round 8 MEDIUM #131).

    Walks every ``Assign`` / ``AnnAssign`` node and registers the LHS
    variable / attribute path when the RHS contains any shared-state path
    marker. Catches:

    - ``state_path = Path('.omx/state/foo.json')`` — lowercase, was missed
      by the regex collector.
    - ``self.foo_path = base / 'active_jobs.json'`` — attribute target.
    - ``base = REPO_ROOT / '.omx' / 'state' / 'foo.json'`` — Path-joined
      string-tuple where the SHARED marker is a string fragment.
    - ``cache: Path = Path('.omx/state/...')`` — annotated assignment.
    - ``foo = f'.omx/state/{name}.json'`` — f-string.

    Both bare names AND attribute names (e.g. ``self.foo_path``) are
    returned so the line scanner's receiver-match can resolve either.
    """
    try:
        tree = ast.parse(text)
    except SyntaxError:
        return set()
    out: set[str] = set()
    for node in ast.walk(tree):
        if isinstance(node, ast.Assign):
            value = node.value
            if value is None:
                continue
            consts = _bare_write_collect_string_constants(value)
            if not any(_bare_write_string_contains_shared_marker(c) for c in consts):
                continue
            for target in node.targets:
                name = _bare_write_target_name_from_assign_target(target)
                if name:
                    out.add(name)
        elif isinstance(node, ast.AnnAssign):
            value = node.value
            if value is None:
                continue
            consts = _bare_write_collect_string_constants(value)
            if not any(_bare_write_string_contains_shared_marker(c) for c in consts):
                continue
            name = _bare_write_target_name_from_assign_target(node.target)
            if name:
                out.add(name)
    return out


def _bare_write_collect_shared_vars(text: str) -> set[str]:
    """Combined regex-based all-caps + AST-based lowercase/attribute collector.

    Catalog #131 v2 (codex round 8 MEDIUM, 2026-05-09): expands #131's
    detection to lowercase variables (``state_path``), attribute paths
    (``self.foo_path``), and Path-joined bindings — all of which were
    silently invisible to the original all-caps-regex collector.
    """
    out = set(m.group(1) for m in _BARE_WRITE_SHARED_VAR_RE.finditer(text))
    out |= _bare_write_collect_shared_vars_ast(text)
    return out


def _bare_write_line_targets_shared(line: str, shared_vars: set[str]) -> bool:
    """True if the write call's path argument resolves to a shared-state path."""
    # Direct path-literal in the line
    if any(m in line for m in _SHARED_STATE_PATH_MARKERS):
        return True
    # Receiver matches a shared variable
    for pat in (_BARE_WRITE_TEXT_RE, _BARE_WRITE_BYTES_RE):
        m = pat.search(line)
        if m:
            recv = m.group(1)
            base = recv.split(".")[0].split("[")[0].split("(")[0]
            if base in shared_vars or recv in shared_vars:
                return True
    m = _BARE_WRITE_OPEN_RE.search(line)
    if m:
        arg = m.group(1).strip()
        base = arg.split(".")[0].split("[")[0].split("(")[0]
        if base in shared_vars or arg in shared_vars:
            return True
    m = _BARE_OS_REPLACE_RE.search(line)
    if m:
        arg = m.group(1).strip()
        base = arg.split(".")[0].split("[")[0].split("(")[0]
        if base in shared_vars or arg in shared_vars:
            return True
    return False


def check_no_bare_writes_to_shared_state(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #131 — shared-state writes must route through fcntl helpers.

    Refuses code sites under `src/tac/`, `tools/`, `experiments/`, `scripts/`
    that write to a recognized shared-state path (e.g. `.omx/state/*.json`,
    `vastai_active_instances`, `lightning_active_jobs`, etc.) without:

    1. The local preceding line window referencing a real lock/context token
       (``fcntl.flock``, ``LOCK_EX``, ``_posterior_lock``,
       ``_lightning_state_lock``, ``_active_jobs_lock``, or ``FileLock``), OR
    2. A same-line waiver comment ``# BARE_WRITE_OK:<reason>``.

    Held warn-only initially per the directive — flip to STRICT after live
    count drives to 0 and stability period elapses.

    Bug class: proactive META-class sweep (2026-05-09). Sister of catalog #128
    which only covered the narrower `continual_learning.save_posterior` case.
    The proactive sweep found 6 ADDITIONAL surfaces with the same META class
    beyond #128's scope; all 6 fixed in this lane.

    Memory: feedback_proactive_custody_concurrency_audit_landed_20260509.md
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "experiments",
        root / "scripts",
    ]
    excluded_files = {root / p for p in _BARE_WRITE_CANONICAL_HELPERS}

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            if py in excluded_files:
                continue
            # Skip tests
            if "/tests/" in str(py) or py.name.startswith("test_"):
                continue
            # Skip vendored public-PR intakes / hosted exports
            s = str(py)
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "experiments/results/vast_harvest" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter — file must reference a shared-state marker.
            if not any(m in text for m in _SHARED_STATE_PATH_MARKERS):
                continue
            scanned_files += 1
            shared_vars = _bare_write_collect_shared_vars(text)
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                # Skip lines inside string literals (rough heuristic).
                if stripped.startswith('"') or stripped.startswith("'"):
                    continue
                # Must be a write call.
                has_write = (
                    _BARE_WRITE_OPEN_RE.search(line)
                    or _BARE_WRITE_TEXT_RE.search(line)
                    or _BARE_WRITE_BYTES_RE.search(line)
                    or _BARE_OS_REPLACE_RE.search(line)
                )
                if not has_write:
                    continue
                if _BARE_WRITE_WAIVER_MARKER in line:
                    continue
                if not _bare_write_line_targets_shared(line, shared_vars):
                    continue
                # Window-scope check: 20 lines before + current line only. A
                # helper call after a bare write is NOT proof that the write is
                # serialized; an actual lock/context token must be visible
                # before or on the write line.
                #
                # Codex round 8 MEDIUM (2026-05-09, in-place harden of #131):
                # presence of a lock token alone is NOT sufficient to waive
                # a direct `write_text/write_bytes` on a shared-state path.
                # The atomic-replace pattern (write to `<path>.tmp` + os.replace)
                # is also required for partial-read safety. The exempt patterns
                # are:
                #   (a) call into a canonical helper (e.g. `update_active_jobs_locked`,
                #       `register_instance`, `posterior_update_locked`) — whole
                #       transactional contract owned by the helper
                #   (b) lock token AND atomic-replace tokens both visible in
                #       the window (write to .tmp then os.replace)
                #   (c) `os.replace(...)` call itself (the atomic step;
                #       the .tmp write is the partial-read-safe staging)
                lo = max(0, lineno - 20)
                hi = lineno + 1
                window = "\n".join(lines[lo:hi])
                # Wider forward window for the atomic-replace pattern check
                # (the os.replace can come AFTER the bare write but in the
                # same locked block).
                hi_forward = min(len(lines), lineno + 10)
                window_forward = "\n".join(lines[lo:hi_forward])

                has_lock_token = any(
                    tok in window for tok in _BARE_WRITE_LOCK_TOKENS
                )
                # Canonical-helper detection: token must appear as a CALL
                # (`<helper>(`), not as an import statement. Otherwise an
                # `from x import register_instance` line in the lookback
                # would falsely waive an unrelated bare write below.
                has_canonical_helper = False
                for w_line in window.splitlines():
                    stripped_line = w_line.lstrip()
                    if stripped_line.startswith(("import ", "from ")):
                        continue
                    if any(
                        (tok + "(") in w_line
                        for tok in _BARE_WRITE_CANONICAL_HELPER_CALL_TOKENS
                    ):
                        has_canonical_helper = True
                        break
                has_atomic_replace_pattern = (
                    "os.replace" in window_forward
                    or ".replace(" in window_forward
                ) and (
                    ".tmp" in window_forward
                    or "tmpfile" in window_forward.lower()
                    or "with_suffix" in window_forward
                )
                # The current line IS the os.replace itself — accept (the
                # write to the .tmp staging is partial-read safe by construction).
                line_is_atomic_replace = (
                    _BARE_OS_REPLACE_RE.search(line) is not None
                )
                if has_canonical_helper:
                    continue
                if (
                    has_lock_token
                    and (has_atomic_replace_pattern or line_is_atomic_replace)
                ):
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                # Format error message based on which gap the site has
                if has_lock_token:
                    detail = (
                        "lock token visible but no atomic-replace pattern "
                        "(`<path>.tmp` write + `os.replace`). Lock alone is "
                        "insufficient: a partial write is visible to readers "
                        "even under the same lock, and a process crash mid-write "
                        "leaves a corrupt file"
                    )
                else:
                    detail = (
                        "no `fcntl.flock` / canonical locked helper visible "
                        "in 20-line lookback"
                    )
                violations.append(
                    f"[Check 131] {rel}:{lineno + 1}: "
                    f"bare write to shared-state path — {detail}. "
                    "Per proactive META-class audit + codex round 8 MEDIUM, "
                    "every shared-state write MUST satisfy ONE of: "
                    "(a) route through a canonical helper "
                    "(`update_active_jobs_locked` / `register_instance` / "
                    "`posterior_update_locked` / etc.); "
                    "(b) reload-inside-lock + write to `<path>.tmp` + "
                    "`os.replace(<tmp>, <path>)` while holding `fcntl.flock`. "
                    "Add a `# BARE_WRITE_OK:<reason>` waiver if the site is "
                    "single-writer / serialized externally."
                )

    if verbose:
        if violations:
            print(
                f"  [bare-shared-state-writes] {len(violations)} bare write(s) "
                f"(scanned: {scanned_files} file(s) referencing shared-state markers)"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [bare-shared-state-writes] OK "
                f"({scanned_files} file(s) scanned; 0 bare write(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_no_bare_writes_to_shared_state: "
            f"{len(violations)} bare write(s) to shared state; first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: route through a canonical fcntl-locked helper "
            "or add `# BARE_WRITE_OK:<reason>` for single-writer paths."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #132 — locked writes must preserve caller deletions
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round-3 HIGH 1, 2026-05-09): a previous "locked save"
# helper (`scripts/verify_vast_instances.py::_save_setup_first_seen`)
# took a caller-supplied map under fcntl lock, then RE-LOADED the on-disk
# file inside the lock and did `existing.update(data)` before writing.
# The .update() silently merged-away any keys the caller had pruned —
# stale `first_seen` rows persisted; `--auto-destroy-stale` then targeted
# fresh instances that inherited an old age from the merge.
#
# The structural fix: locked helpers that take the FULL post-prune map
# from the caller MUST do TRANSACTIONAL REPLACE inside the lock — not
# `existing.update(data)`. The caller is the source of truth for
# deletions; the writer's job is to atomically commit that snapshot.
#
# This gate scans for `_save_*_first_seen` / `_save_*_state` /
# `update_*_locked` style functions and refuses any that contain the
# `existing.update(data)` anti-pattern (or the variant
# `<reload>.update(<param>)`) inside an fcntl-locked window. Sister of
# catalog #131 (which catches BARE writes — this one catches LOCKED but
# DELETION-LOSING writes).

# Function-name patterns this gate considers "locked save" helpers.
_LOCKED_WRITE_FUNCTION_NAME_PATTERNS: tuple[str, ...] = (
    "_save_setup_first_seen",
    "_save_state_first_seen",
    "_save_active_state",
    "_save_lane_state",
    "_save_dispatch_state",
    "_save_session_state",
    "_save_recovery_state",
    "_save_posterior_state",
)

# Anti-pattern markers we look for INSIDE a locked-save body.
# `<var>.update(<arg>)` where <var> was reloaded from the on-disk path is
# the deletion-merge bug. We approximate by detecting the literal pattern
# `existing = ... ; existing.update(data)` or `prev = ... ; prev.update(data)`.
_DELETION_MERGE_PATTERNS: tuple[str, ...] = (
    "existing.update(",
    "previous.update(",
    "prev.update(",
    "current.update(",
    "stored.update(",
    "on_disk.update(",
    "loaded.update(",
)

_DELETION_MERGE_WAIVER_MARKER = "DELETION_MERGE_OK"


def check_locked_writes_preserve_deletions(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #132 — locked-save helpers must do transactional replace, not merge.

    Refuses any function whose name matches a "locked save" pattern
    (``_save_*_first_seen`` / ``_save_*_state`` / ``update_*_locked``)
    that contains a deletion-merging pattern (``existing.update(data)``,
    ``previous.update(data)``, ``loaded.update(data)``, etc.) inside an
    fcntl-locked region. The pattern silently re-introduces stale rows
    the caller deliberately removed; the only safe contract is
    transactional replace.

    Same-line waiver: ``# DELETION_MERGE_OK:<reason>`` for the rare case
    where the merge is genuinely additive (e.g. a counter-bump helper
    that's never used for replacement).

    Live count expected: 0 after the verify_vast_instances HIGH 1 fix.

    Bug class: codex round-3 HIGH 1 (2026-05-09). Sister of catalog #131
    (bare writes) — that catches the unlocked META class; this catches
    the LOCKED-but-deletion-losing META class. Memory:
    feedback_codex_round3_findings_fix_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "experiments",
        root / "scripts",
    ]

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for src in list(scan_dir.rglob("*.py")) + list(scan_dir.rglob("*.sh")):
            if _is_oss_export_mirror_path(src):
                continue
            # Skip tests + vendored intakes / hosted exports
            s = str(src)
            if "/tests/" in s or src.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "experiments/results/vast_harvest" in s
            ):
                continue
            try:
                text = src.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter — file must have at least one anti-pattern AND
            # one fcntl-related token. (We allow 2-line gap; the function
            # name must also appear nearby.)
            if not any(pat in text for pat in _DELETION_MERGE_PATTERNS):
                continue
            if "fcntl" not in text and "LOCK_EX" not in text:
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                if not any(pat in line for pat in _DELETION_MERGE_PATTERNS):
                    continue
                if _DELETION_MERGE_WAIVER_MARKER in line:
                    continue
                # Find the enclosing function definition by scanning
                # backwards for `def <name>(` with no greater indent.
                enclosing_func: str | None = None
                line_indent = len(line) - len(line.lstrip(" "))
                for back_idx in range(lineno, -1, -1):
                    cand = lines[back_idx]
                    cand_stripped = cand.lstrip(" ")
                    if not cand_stripped.startswith("def "):
                        continue
                    cand_indent = len(cand) - len(cand_stripped)
                    if cand_indent < line_indent:
                        # Extract function name `def NAME(`
                        m = re.match(r"def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(", cand_stripped)
                        if m:
                            enclosing_func = m.group(1)
                        break
                if enclosing_func is None:
                    continue
                # Function name must match the locked-save pattern OR the
                # broader `update_*_locked` pattern.
                name_match = (
                    enclosing_func in _LOCKED_WRITE_FUNCTION_NAME_PATTERNS
                    or enclosing_func.endswith("_locked")
                    or enclosing_func.startswith("_save_")
                )
                if not name_match:
                    continue
                # Confirm the surrounding window contains an fcntl-lock
                # context token (otherwise this is just a normal merge).
                lo = max(0, lineno - 30)
                hi = min(len(lines), lineno + 5)
                window = "\n".join(lines[lo:hi])
                if not any(
                    tok in window
                    for tok in ("fcntl.flock", "LOCK_EX", "_active_jobs_lock", "_posterior_lock")
                ):
                    continue
                rel = src.relative_to(root) if src.is_relative_to(root) else src
                violations.append(
                    f"[Check 132] {rel}:{lineno + 1}: "
                    f"locked-save helper `{enclosing_func}` does "
                    "`existing.update(data)`-style deletion-MERGE inside fcntl lock. "
                    "This silently re-introduces stale keys the caller pruned; "
                    "the only safe contract is TRANSACTIONAL REPLACE. "
                    "Add a `# DELETION_MERGE_OK:<reason>` waiver if the merge "
                    "is genuinely additive (e.g. counter-bump helper)."
                )

    if verbose:
        if violations:
            print(
                f"  [locked-writes-preserve-deletions] {len(violations)} "
                f"deletion-merge violation(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [locked-writes-preserve-deletions] OK "
                f"({scanned_files} file(s) scanned; 0 deletion-merge violation(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_locked_writes_preserve_deletions: "
            f"{len(violations)} deletion-merge violation(s) "
            "in locked-save helpers; first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: change `existing.update(data)` to a TRANSACTIONAL "
            "REPLACE (write the caller's map directly). The caller owns "
            "the post-prune snapshot; the writer's job is to atomically "
            "commit it, not merge it."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #133 — Catalog #131 accept-list must contain real locked writers
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 4 HIGH 1, 2026-05-09): Catalog #131's
# `_BARE_WRITE_CANONICAL_HELPERS` exempt list includes files that are claimed
# to be "already locked" but are not. Specifically, the previous list named
# `src/tac/deploy/azure/azure_dispatch.py` as exempt, but that file did
# bare `write_text` to `.omx/state/azure_active_vms.json` with no fcntl
# context. Strict #131 reported the bare-write META class extinct, but
# concurrent Azure provisions could still drop VM rows.
#
# This META-meta gate scans #131's exempt list and verifies each named file
# actually contains the canonical lock pattern (fcntl.flock + LOCK_EX, or
# routes through an upstream canonical helper). A file in the exempt list
# that lacks the locked-writer pattern is a false-green failure mode that
# undermines the META gate.
#
# Sister of catalog #131 (bare writes — primary META gate). This is the
# META-META gate that protects the META gate's accept list itself.

_CHECK_131_EXEMPT_AUDIT_WAIVER_MARKER = "CHECK_131_EXEMPT_AUDIT_OK"


def check_no_excluded_writers_in_check_131_accept_list(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #133 — META-meta: #131's exempt list must contain real locked writers.

    Iterates every entry in ``_BARE_WRITE_CANONICAL_HELPERS`` and verifies
    the file actually has at least one of:

    1. A direct ``fcntl.flock`` + ``LOCK_EX`` pattern (canonical lock acquisition)
    2. A ``with _<something>_lock(...):`` context manager invocation (routes
       through a sister fcntl helper)
    3. An import of a canonical lock context manager
       (``_active_jobs_lock``, ``_active_vms_lock``, ``_lightning_state_lock``,
       ``posterior_update_locked``)
    4. A delegation comment + import-from one of the canonical helper modules
    5. Same-line waiver ``# CHECK_131_EXEMPT_AUDIT_OK:<reason>`` on the
       definition that needs to be exempt from the audit (rare; must justify)

    A file in the exempt list lacking ALL of the above is a false-green
    failure mode. The fix is to either (a) add a real locked writer, or
    (b) remove the file from the exempt list.

    Live count expected: 0 after the codex round 4 HIGH 1 fix swaps
    ``azure_dispatch.py`` (had no lock) for ``active_vms_state.py``
    (the new canonical Azure locked-writer module).

    Bug class: codex round 4 HIGH 1 (2026-05-09). META-meta sister of
    catalog #131. Memory:
    feedback_codex_round4_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)

    # The canonical lock-pattern tokens any exempt file MUST contain.
    LOCK_PATTERN_TOKENS: tuple[str, ...] = (
        "fcntl.flock",
        "LOCK_EX",
        "_active_jobs_lock",
        "_active_vms_lock",
        "_lightning_state_lock",
        "_posterior_lock",
        "posterior_update_locked",
        "update_active_jobs_locked",
        "update_active_vms_locked",
        "register_active_vm_record",
        "register_job",
        "register_instance",  # canonical Vast.ai writer (vastai_tracker)
        "claim_lane_dispatch",  # canonical lane-claim helper
        "threading.Lock",  # in-process serialization (cache-only modules)
    )

    # Sister-gate exemption: catalog #131's gate IS the gate that uses
    # this list, so its own implementation file does not need a lock.
    PRIMARY_GATE_FILE = "src/tac/preflight.py"

    violations: list[str] = []
    for rel in _BARE_WRITE_CANONICAL_HELPERS:
        if rel == PRIMARY_GATE_FILE:
            continue
        # Deferred-rationale entries pass the audit AND the rationale is
        # documented in `_CHECK_131_EXEMPT_AUDIT_DEFERRED_RATIONALE`.
        # Catalog #133 accepts these at gate-time; a follow-up lane lands
        # the actual fcntl helper.
        if rel in _CHECK_131_EXEMPT_AUDIT_DEFERRED_RATIONALE:
            continue
        full = root / rel
        if not full.exists():
            violations.append(
                f"[Check 133] #131 exempt-list entry {rel!r} does not exist "
                "in the repo. Either remove the entry or land the file."
            )
            continue
        try:
            text = full.read_text(encoding="utf-8", errors="replace")
        except OSError as exc:
            violations.append(
                f"[Check 133] #131 exempt-list entry {rel!r} could not be read: {exc}"
            )
            continue
        # File-wide waiver check
        if _CHECK_131_EXEMPT_AUDIT_WAIVER_MARKER in text:
            continue
        # No waiver — file must contain at least one canonical lock pattern.
        if not any(tok in text for tok in LOCK_PATTERN_TOKENS):
            violations.append(
                f"[Check 133] #131 exempt-list entry {rel!r} is claimed to be "
                "'already locked' but contains NO canonical lock-pattern token "
                f"(none of: {', '.join(LOCK_PATTERN_TOKENS[:5])}, ...). "
                "False-green failure mode: the exempt list says this file is "
                "safe but the META gate cannot verify it is. "
                "Fix: either land a canonical fcntl-locked writer, OR add a "
                "same-line `# CHECK_131_EXEMPT_AUDIT_OK:<reason>` waiver on "
                "the entry (rare; must justify per CLAUDE.md), OR add a "
                "deferred-rationale entry to "
                "`_CHECK_131_EXEMPT_AUDIT_DEFERRED_RATIONALE` with a follow-up "
                "lane reference, OR remove the entry from "
                "`_BARE_WRITE_CANONICAL_HELPERS`."
            )

    if verbose:
        if violations:
            print(
                f"  [check-131-exempt-list-audit] {len(violations)} false-green "
                f"exempt entry(ies) (scanned: {len(_BARE_WRITE_CANONICAL_HELPERS)})"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [check-131-exempt-list-audit] OK "
                f"({len(_BARE_WRITE_CANONICAL_HELPERS)} exempt entries; 0 false-green)"
            )

    if violations and strict:
        raise PreflightError(
            "check_no_excluded_writers_in_check_131_accept_list found "
            f"{len(violations)} false-green exempt entry(ies):\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #134 — Phase3DispatchGate must be fail-closed at construction
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 4 MEDIUM 1, 2026-05-09): the previous
# `Phase3DispatchGate.__post_init__` was a no-op with the comment
# "tests need to construct with a permissive gate". That comment-only
# contract let any future trainer/dispatcher silently bypass every
# precondition by forgetting to call `gate.check()`. The fix moved the
# enforcement into `__post_init__` with an explicit `unsafe_test_only=True`
# escape hatch for tests.
#
# This gate scans the repo for `Phase3DispatchGate(` instantiations
# OUTSIDE the canonical scaffold integration point and refuses any that
# do not pass `unsafe_test_only=True` AND look like a "test fixture"
# pattern. Production trainers/dispatchers cannot construct a permissive
# gate; they must satisfy every precondition.

_PHASE3_GATE_TEST_FIXTURE_TOKEN = "unsafe_test_only=True"


def check_phase3_dispatch_gate_fail_closed(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #134 — Phase3DispatchGate construction must be fail-closed.

    Refuses any ``Phase3DispatchGate(...)`` call site outside the
    canonical scaffold integration point that does NOT include
    ``unsafe_test_only=True``. Production trainers must satisfy every
    precondition; tests that need a permissive gate to exercise the API
    surface MUST opt out explicitly.

    Allowed sites (excluded from scanning):

    - ``src/tac/phase3/joint_scorer_renderer_codec.py`` — the canonical
      module that defines the gate; integration self-references are
      expected here.
    - Test files (``src/tac/tests/test_*.py``,  ``tools/tests/``,
      ``experiments/tests/``, ``scripts/tests/``) — tests legitimately
      construct opted-out gates.

    Out-of-scope sites that DO call ``Phase3DispatchGate(...)`` MUST
    either pass ``unsafe_test_only=True`` (test fixture) or supply the
    full precondition set (production dispatch). The construction itself
    will fail-close at runtime; this gate enforces it at commit time.

    Same-line waiver: ``# PHASE3_GATE_OK:<reason>`` for the rare case of
    an integration callsite that needs to construct the gate with
    explicit precondition values (e.g. a builder helper that wraps the
    construction in additional validation). Must justify per CLAUDE.md.

    Live count expected: 0 after the codex round 4 MEDIUM 1 fix.

    Bug class: codex round 4 MEDIUM 1 (2026-05-09). Sister of catalog
    #133 (META-meta exempt-list audit) and catalog #135 (verify_vast
    main-flow lost-update). Memory:
    feedback_codex_round4_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "experiments",
        root / "scripts",
    ]

    # Canonical scaffold module — its own self-references are expected
    EXCLUDED_FILES = {
        root / "src" / "tac" / "phase3" / "joint_scorer_renderer_codec.py",
        root / "src" / "tac" / "preflight.py",  # this gate's own implementation
    }

    PHASE3_GATE_WAIVER_MARKER = "PHASE3_GATE_OK"

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            if py in EXCLUDED_FILES:
                continue
            # Test files are exempt — they legitimately exercise the gate
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            # Vendored intakes / hosted exports
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "experiments/results/vast_harvest" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if "Phase3DispatchGate" not in text:
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                # Look for `Phase3DispatchGate(` (constructor call, not type
                # annotation or import).
                if "Phase3DispatchGate(" not in line:
                    continue
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                # Type-only annotations / imports / class refs without `(`
                # are already filtered above.
                if "isinstance" in line or "issubclass" in line:
                    continue
                # Same-line waiver
                if PHASE3_GATE_WAIVER_MARKER in line:
                    continue
                # Multi-line constructor: search next 30 lines for either
                # the closing paren OR `unsafe_test_only=True`.
                window_lines = lines[lineno: min(len(lines), lineno + 30)]
                window = "\n".join(window_lines)
                # Truncate to the closing paren of THIS construction.
                # Naive approach: take up to the first line that's a top-level
                # close-paren or a sibling statement.
                paren_depth = 0
                truncated_chunks: list[str] = []
                started = False
                for w_line in window_lines:
                    truncated_chunks.append(w_line)
                    for ch in w_line:
                        if ch == "(":
                            paren_depth += 1
                            started = True
                        elif ch == ")":
                            paren_depth -= 1
                    if started and paren_depth <= 0:
                        break
                ctor_text = "\n".join(truncated_chunks)
                if _PHASE3_GATE_TEST_FIXTURE_TOKEN in ctor_text:
                    continue
                # Heuristic: the construction is allowed if EVERY required
                # precondition kwarg is present (production dispatch). The
                # required kwargs are listed in the gate dataclass.
                required_kwargs = (
                    "phase2_anchor_verified",
                    "phase2_anchor_score",
                    "phase2_anchor_evidence_path",
                    "distillation_gap_estimate",
                    "distillation_gap_evidence_path",
                    "operator_approved_gpu_budget_usd",
                    "aaf68f37_verdict_clean",
                    "aaf68f37_verdict_evidence_path",
                    "phase3_council_deliberation_path",
                )
                if all(k + "=" in ctor_text for k in required_kwargs):
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 134] {rel}:{lineno + 1}: "
                    "Phase3DispatchGate(...) construction outside the canonical "
                    "scaffold module without `unsafe_test_only=True` and without "
                    "the full production-precondition kwarg set. Production "
                    "dispatch must satisfy every precondition; tests that need "
                    "a permissive gate MUST set `unsafe_test_only=True` "
                    "explicitly. Add either the kwarg or a same-line "
                    "`# PHASE3_GATE_OK:<reason>` waiver."
                )

    if verbose:
        if violations:
            print(
                f"  [phase3-gate-fail-closed] {len(violations)} "
                f"unsafe construction(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [phase3-gate-fail-closed] OK "
                f"({scanned_files} file(s) scanned; 0 unsafe construction(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_phase3_dispatch_gate_fail_closed found "
            f"{len(violations)} unsafe Phase3DispatchGate construction(s):\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #135 — SETUP-first-seen writers must update INSIDE the lock
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 4 MEDIUM 2, 2026-05-09): the round-3 fix made
# `_save_setup_first_seen` write transactionally INSIDE the lock, but the
# `main()` flow still loaded the on-disk state OUTSIDE the lock, ran
# per-instance verify (~minutes), then saved the post-mutation snapshot
# at the end. Two overlapping verifier runs both loaded the same stale
# snapshot, did per-instance work, then the slower run replaced the file
# with its now-stale view — deleting first-seen timestamps the faster run
# had created.
#
# The fix is a true transactional update API
# (`update_setup_first_seen_locked`) that does load + merge + prune + save
# INSIDE one fcntl-locked window. This gate scans for any `_save_*_first_seen`
# / `_save_setup_*` writer whose CALL SITE pattern is "load outside lock,
# write under lock" (the lost-update anti-pattern) and refuses it.
#
# Sister of catalog #132 (deletion-merge anti-pattern in the SAVE function
# itself) and catalog #131 (bare writes outside any lock).

_SETUP_FIRST_SEEN_LOST_UPDATE_WAIVER_MARKER = "SETUP_FIRST_SEEN_LOST_UPDATE_OK"


def check_setup_first_seen_uses_transactional_update_inside_lock(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #135 — SETUP-first-seen writers must update INSIDE the lock.

    Refuses any module that:

    1. Defines a ``_save_*_first_seen`` / ``_save_setup_*`` function, AND
    2. Has a CALL SITE that loads the on-disk state OUTSIDE any lock,
       performs work, then calls the save function — without using the
       canonical transactional update helper
       (``update_*_first_seen_locked`` / ``update_setup_*_locked``).

    The lost-update anti-pattern is:

        state = _load_xyz()              # outside any lock
        # ... long-running work ...
        state.update(...)
        _save_xyz(state)                  # locked save, but stale state

    The canonical fix is:

        update_xyz_locked(observed_set, tracked_set, now_ts)

    Same-line waiver:
    ``# SETUP_FIRST_SEEN_LOST_UPDATE_OK:<reason>`` on the ``_load_*`` call
    site for the rare case where the load-outside-lock is intentional
    (e.g. a read-only reporter that doesn't write back). Must justify.

    Live count expected: 0 after the codex round 4 MEDIUM 2 fix in
    ``scripts/verify_vast_instances.py::main``.

    Bug class: codex round 4 MEDIUM 2 (2026-05-09). Sister of catalog
    #132 (deletion-merge in SAVE) and catalog #131 (bare writes).
    Memory:
    feedback_codex_round4_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "experiments",
        root / "scripts",
    ]

    # Function-name patterns this gate considers "first-seen" writers
    LOAD_PATTERNS = re.compile(
        r"_load_(setup_first_seen|state_first_seen|first_seen|setup)\b"
    )
    SAVE_PATTERNS = re.compile(
        r"_save_(setup_first_seen|state_first_seen|first_seen|setup)\b"
    )
    # Canonical transactional update helpers (presence => safe pattern)
    LOCKED_UPDATE_PATTERNS = re.compile(
        r"\bupdate_(setup_first_seen|state_first_seen|first_seen|setup|"
        r"active_jobs|active_vms)_locked\b"
    )

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for src in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(src):
                continue
            s = str(src)
            if "/tests/" in s or src.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "experiments/results/vast_harvest" in s
            ):
                continue
            try:
                text = src.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter — file must reference both load + save first-seen
            if not (LOAD_PATTERNS.search(text) and SAVE_PATTERNS.search(text)):
                continue
            scanned_files += 1
            lines = text.splitlines()
            # Find every CALL site of a load helper that is OUTSIDE a `def
            # _load_*` or `def _save_*` definition (i.e. not the helpers
            # themselves) and OUTSIDE any visible `with ...lock` context.
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                if not LOAD_PATTERNS.search(line):
                    continue
                # Skip definitions
                if stripped.startswith("def "):
                    continue
                # Same-line waiver
                if _SETUP_FIRST_SEEN_LOST_UPDATE_WAIVER_MARKER in line:
                    continue
                # If THIS function uses the canonical locked-update helper,
                # the load is informational and not the lost-update class.
                # Find enclosing function and look for LOCKED_UPDATE_PATTERNS.
                line_indent = len(line) - len(line.lstrip(" "))
                func_start: int | None = None
                for back_idx in range(lineno, -1, -1):
                    cand = lines[back_idx]
                    cand_stripped = cand.lstrip(" ")
                    if not cand_stripped.startswith("def "):
                        continue
                    cand_indent = len(cand) - len(cand_stripped)
                    if cand_indent < line_indent:
                        func_start = back_idx
                        break
                if func_start is None:
                    continue
                # Find function end by indent
                func_indent = len(lines[func_start]) - len(lines[func_start].lstrip(" "))
                func_end = len(lines)
                for fwd_idx in range(func_start + 1, len(lines)):
                    cand = lines[fwd_idx]
                    if not cand.strip():
                        continue
                    cand_indent = len(cand) - len(cand.lstrip(" "))
                    if cand_indent <= func_indent and cand.lstrip(" ").startswith(("def ", "class ")):
                        func_end = fwd_idx
                        break
                func_body = "\n".join(lines[func_start:func_end])
                # If the enclosing function uses the canonical update-helper
                # pattern, the load-outside-lock is informational only.
                if LOCKED_UPDATE_PATTERNS.search(func_body):
                    continue
                # If the enclosing function does NOT call _save_*_first_seen,
                # this is read-only and out-of-scope.
                if not SAVE_PATTERNS.search(func_body):
                    continue
                # Check if the load is INSIDE a lock window in the
                # enclosing function. Look for either:
                # - `with ` + lock token (context manager pattern) at
                #   strictly LESS indent than the load line
                # - `fcntl.flock(..., LOCK_EX)` imperative call at any
                #   indent <= load indent within the function
                # within the enclosing function body BEFORE the load.
                in_lock_window = False
                load_indent = len(line) - len(line.lstrip(" "))
                for back_idx in range(lineno - 1, func_start, -1):
                    cand = lines[back_idx]
                    cand_stripped = cand.lstrip(" ")
                    if not cand_stripped:
                        continue
                    cand_indent = len(cand) - len(cand_stripped)
                    # `with <lock-token>` at LESS indent => load is inside it
                    if (
                        "with " in cand
                        and any(
                            tok in cand
                            for tok in (
                                "_lock",
                                "fcntl.flock",
                                "LOCK_EX",
                                "FileLock",
                            )
                        )
                        and cand_indent < load_indent
                    ):
                        in_lock_window = True
                        break
                    # Imperative `fcntl.flock(..., LOCK_EX)` at <= load
                    # indent => an imperative lock acquired earlier in the
                    # same block.
                    if (
                        "fcntl.flock" in cand
                        and "LOCK_EX" in cand
                        and cand_indent <= load_indent
                    ):
                        in_lock_window = True
                        break
                if in_lock_window:
                    continue
                rel = src.relative_to(root) if src.is_relative_to(root) else src
                violations.append(
                    f"[Check 135] {rel}:{lineno + 1}: "
                    "load-outside-lock + save-under-lock anti-pattern in "
                    "function that writes the SETUP-first-seen tracker. "
                    "Concurrent verifier runs would clobber each other's "
                    "first-seen timestamps. Fix: refactor to use the "
                    "canonical `update_setup_first_seen_locked(...)` helper "
                    "(or sister `update_*_locked`) which does load + merge + "
                    "prune + save inside ONE fcntl-locked window. "
                    "Add a same-line `# SETUP_FIRST_SEEN_LOST_UPDATE_OK:<reason>` "
                    "waiver only if the load is read-only (no save in the same flow)."
                )

    if verbose:
        if violations:
            print(
                f"  [setup-first-seen-transactional-update] {len(violations)} "
                f"lost-update violation(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [setup-first-seen-transactional-update] OK "
                f"({scanned_files} file(s) scanned; 0 lost-update violation(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_setup_first_seen_uses_transactional_update_inside_lock found "
            f"{len(violations)} lost-update violation(s):\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #136 — Custody-validator accept-token lists must be CONCRETE only
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (defense-in-depth on codex round-3 HIGH 2, 2026-05-09):
# the previous Check #130 accept-token list `_TAG_GRADE_LOCAL_VALIDATOR_TOKENS`
# included the bare identifiers `"blockers"` and `"errors"` so that fail-closed
# blocker-accumulator sites would not falsely trip the strict gate. The cost
# was a generic-token bypass: ANY unrelated `blockers = []` / `errors = []`
# variable in the +/-6 line window silently waived a tag-only custody gate.
# The strict gate failed open at SIX surfaces before round-3 caught it.
#
# Round-3 fixed the immediate accept-token list (removed `"blockers"` and
# `"errors"`). This META gate (#136) extincts the bug CLASS so no future
# accept-list addition can re-introduce a generic-token bypass — at any
# `*_VALIDATOR_TOKENS` / `*_LOCAL_VALIDATOR_TOKENS` / `*_VALIDATOR_PATTERNS`
# tuple/list constant in `src/tac/preflight.py`.
#
# Forbidden generic identifiers (case-sensitive; bare-string entries only):
# `"blockers"`, `"errors"`, `"failures"`, `"validations"`, `"warnings"`,
# `"issues"`, `"problems"`, `"results"`, `"checks"`, `"messages"`,
# `"verdicts"`, `"reasons"`. These are common variable names that any
# adjacent-but-unrelated code can introduce; they MUST NOT serve as
# accept-tokens for a custody validator.
#
# Same-line opt-out: `# ACCEPT_TOKENS_CONCRETE_OK:<reason>` on the entry
# line OR on the tuple-definition line. Reserved for the rare case where
# a bare generic identifier is genuinely the API contract (e.g. a typed
# attribute access like `result.blockers` whose accessor is the validator).
#
# Sister of Catalog #130 (which catches the call-site MISSING-validator
# pattern), Catalog #133 (a3f4a072's META-meta on #131 exempt list), and
# Catalog #127/#128 (the original custody gates).

# Forbidden generic identifiers — any unrelated `<tok> = ...` variable in a
# validator's line window will silently waive the gate. Constant name
# deliberately uses the suffix `_BLOCKLIST` (NOT `_VALIDATOR_TOKENS` /
# `_ACCEPT_TOKENS`) so that Catalog #136 does not flag itself.
_GENERIC_TOKEN_BLOCKLIST: tuple[str, ...] = (
    "blockers",
    "errors",
    "failures",
    "validations",
    "warnings",
    "issues",
    "problems",
    "results",
    "checks",
    "messages",
    "verdicts",
    "reasons",
)

_ACCEPT_TOKENS_CONCRETE_WAIVER_MARKER = "ACCEPT_TOKENS_CONCRETE_OK"

# Tuple/list constants whose name matches one of these patterns are scanned
# as accept-token lists. We deliberately scope to "_*VALIDATOR_TOKENS" /
# "_*VALIDATOR_PATTERNS" / "_*VALIDATOR_FNS" / "_*ACCEPT_TOKENS" / similar
# explicit accept-list naming. Generic constants like `_PATTERNS` are
# excluded — only constants whose name explicitly says VALIDATOR / ACCEPT
# count as a custody-validator accept-list.
_ACCEPT_TOKENS_CONSTANT_NAME_RE = re.compile(
    r"\b_[A-Z][A-Z0-9_]*"
    r"(VALIDATOR_TOKENS|VALIDATOR_PATTERNS|VALIDATOR_FNS|"
    r"ACCEPT_TOKENS|CUSTODY_TOKENS|GATE_TOKENS|GUARD_TOKENS)\b"
)


def check_custody_gate_accept_tokens_concrete_only(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #136 — custody-validator accept lists must be CONCRETE only.

    Scans ``src/tac/preflight.py`` (and any ``src/tac/**/*.py`` /
    ``tools/**/*.py`` / ``experiments/**/*.py`` / ``scripts/**/*.py``)
    for tuple/list literals named ``_*VALIDATOR_TOKENS`` /
    ``_*VALIDATOR_PATTERNS`` / ``_*VALIDATOR_FNS`` / ``_*ACCEPT_TOKENS`` /
    ``_*CUSTODY_TOKENS`` / ``_*GATE_TOKENS`` / ``_*GUARD_TOKENS`` and
    refuses any entry that is a bare generic identifier (one of
    ``blockers`` / ``errors`` / ``failures`` / ``validations`` /
    ``warnings`` / ``issues`` / ``problems`` / ``results`` / ``checks`` /
    ``messages`` / ``verdicts`` / ``reasons``).

    Concrete validator tokens — function call patterns like
    ``"validate_custody("``, ``"validate_custody_verdict"``, attribute
    references like ``"sha256_file("``, ``"archive_sha256"`` — are accepted.

    Same-line waiver: ``# ACCEPT_TOKENS_CONCRETE_OK:<reason>`` on the
    entry line OR on the tuple-definition line. Reserved for the rare
    case where the bare generic identifier IS the contract (typed
    attribute access whose accessor is the validator).

    Live count expected: 0 — round-3's fix already removed the only
    known instance (``"blockers"`` / ``"errors"`` from
    ``_TAG_GRADE_LOCAL_VALIDATOR_TOKENS``).

    Bug class (defense-in-depth on codex round-3 HIGH 2): the round-3
    fix patched ONE accept-list. This META gate refuses any future
    addition of a generic-token bypass to ANY accept-list, anywhere.
    Memory: feedback_production_hardening_polish_defense_in_depth_landed_20260509.md.
    Cross-ref Catalog #130 (call-site missing-validator) + #133
    (#131 exempt-list audit).

    AST-rewrite (2026-05-09): switched from line-window scanning to ``ast``
    walk over module-level Assign / AnnAssign nodes whose target name
    matches the accept-list pattern. Avoids comment / docstring / string
    literal false positives entirely.
    """
    root = Path(repo_root or REPO_ROOT)
    forbidden = set(_GENERIC_TOKEN_BLOCKLIST)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "experiments",
        root / "scripts",
    ]

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "experiments/results/vast_harvest" in s
                or "_intake_" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if not _ACCEPT_TOKENS_CONSTANT_NAME_RE.search(text):
                continue
            try:
                tree = ast.parse(text)
            except SyntaxError:
                continue
            scanned_files += 1
            lines = text.splitlines()

            for node in ast.walk(tree):
                target_names: list[str] = []
                value: ast.AST | None = None
                if isinstance(node, ast.Assign):
                    for t in node.targets:
                        if isinstance(t, ast.Name):
                            target_names.append(t.id)
                    value = node.value
                elif isinstance(node, ast.AnnAssign) and isinstance(
                    node.target, ast.Name
                ):
                    target_names.append(node.target.id)
                    value = node.value
                else:
                    continue
                if value is None:
                    continue
                matching = [
                    n for n in target_names
                    if _ACCEPT_TOKENS_CONSTANT_NAME_RE.search(n)
                ]
                if not matching:
                    continue
                def_lineno = getattr(node, "lineno", 0)
                def_line = (
                    lines[def_lineno - 1]
                    if 1 <= def_lineno <= len(lines)
                    else ""
                )
                if _ACCEPT_TOKENS_CONCRETE_WAIVER_MARKER in def_line:
                    continue
                if not isinstance(value, (ast.Tuple, ast.List)):
                    continue
                constant_name = matching[0]
                for entry in value.elts:
                    if not isinstance(entry, ast.Constant):
                        continue
                    if not isinstance(entry.value, str):
                        continue
                    tok = entry.value
                    if tok not in forbidden:
                        continue
                    entry_lineno = getattr(entry, "lineno", def_lineno)
                    entry_line = (
                        lines[entry_lineno - 1]
                        if 1 <= entry_lineno <= len(lines)
                        else ""
                    )
                    if _ACCEPT_TOKENS_CONCRETE_WAIVER_MARKER in entry_line:
                        continue
                    rel = py.relative_to(root) if py.is_relative_to(root) else py
                    violations.append(
                        f"[Check 136] {rel}:{entry_lineno}: "
                        f"accept-list `{constant_name}` contains bare generic "
                        f"identifier `{tok}`. Bug class: any unrelated "
                        f"`{tok} = ...` variable in the validator's line "
                        f"window will silently waive the gate. Replace with "
                        f"a concrete validator token (e.g. `validate_custody`, "
                        f"`archive_sha256`, `sha256_file(`) OR add a same-line "
                        f"`# ACCEPT_TOKENS_CONCRETE_OK:<reason>` waiver if "
                        f"this bare-token IS the intended contract."
                    )

    if verbose:
        if violations:
            print(
                f"  [accept-tokens-concrete-only] {len(violations)} bare-generic-token "
                f"entry(ies) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [accept-tokens-concrete-only] OK "
                f"({scanned_files} file(s) scanned; 0 bare-generic-token entry(ies))"
            )

    if violations and strict:
        raise PreflightError(
            "check_custody_gate_accept_tokens_concrete_only: "
            f"{len(violations)} bare-generic-token entry(ies) in custody-validator "
            "accept lists; first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: replace the bare token with a CONCRETE validator name "
            "(`validate_custody`, `archive_sha256`, etc.) OR add "
            "`# ACCEPT_TOKENS_CONCRETE_OK:<reason>` if the bare-token IS the "
            "intended contract."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #137 — Remote dispatch runbooks must NOT default to local CUDA probe
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (defense-in-depth on codex round-3 MEDIUM 1, 2026-05-09):
# `scripts/remote_lane_avvideodataset_cuda_path_mechanism_discriminator.sh`
# unconditionally invoked `probe_nvdec.sh` LOCALLY whenever `SKIP_CUDA=0`,
# including under `DRY_RUN=1`. The operator workstation / CI host typically
# has no CUDA / NVDEC / DALI installed; the probe exited 2 before the script
# could reach the dispatch-decision block.
#
# Round-3 fixed the immediate runbook (guard local NVDEC probing behind
# explicit `LOCAL_CUDA_WORKER=1`). This META gate (#137) extincts the bug
# CLASS so no future `scripts/remote_lane_*.sh` can introduce an unguarded
# local CUDA/NVDEC probe.
#
# The check scans `scripts/remote_lane_*.sh` for invocations of
# `probe_nvdec.sh` / `nvidia-smi` / `nvcc --version` / similar local
# CUDA-probe commands and refuses each unless:
#
# 1. The invocation is preceded (within the same Bash branch / function /
#    file scope) by a `LOCAL_CUDA_WORKER` token guard, OR
# 2. The invocation is preceded by a `DRY_RUN` short-circuit, OR
# 3. The line carries a `# LOCAL_CUDA_PROBE_OK:<reason>` waiver, OR
# 4. The script is wrapped in a `vastai exec` / `lightning ssh` / `modal run`
#    remote-execution context (the probe runs on the GPU side, not local).
#
# Sister of CLAUDE.md "Remote code parity" rule (which mandates a remote
# heartbeat) and CLAUDE.md "Vast.ai cost paranoia" (which mandates the
# probe live on the remote provider, not the dispatcher).

_LOCAL_CUDA_PROBE_TOKENS: tuple[str, ...] = (
    "probe_nvdec.sh",
    "nvidia-smi",
    "nvcc --version",
    "nvcc -V",
    "torch.cuda.is_available()",
)

_LOCAL_CUDA_PROBE_GUARD_TOKENS: tuple[str, ...] = (
    "LOCAL_CUDA_WORKER",
    "DRY_RUN",
    # Remote-execution wrapper tokens — the probe runs on the remote side
    "vastai exec",
    "lightning ssh",
    "modal run",
    "ssh ",  # generic SSH wrapper
    "$REMOTE_HOST",
    "${REMOTE_HOST",
)

_LOCAL_CUDA_PROBE_WAIVER_MARKER = "LOCAL_CUDA_PROBE_OK"


def _remote_lane_script_is_remote_side_bootstrap(text: str) -> bool:
    """Return True for scripts intended to run on the GPU provider host.

    Catalog #137 targets local dispatch drivers that accidentally probe the
    operator workstation. Legacy `remote_lane_*.sh` naming is overloaded:
    many files are the remote-side payload itself and intentionally start with
    `WORKSPACE=/workspace/pact; cd "$WORKSPACE"` before running CUDA probes.
    Those probes are in the correct place and must not be mass-waived.
    """
    active_lines = [
        line
        for line in text.splitlines()
        if line.strip() and not line.lstrip().startswith("#")
    ]
    active = "\n".join(active_lines[:80])
    workspace_default = re.search(
        r"WORKSPACE=.*\$\{WORKSPACE:-/workspace/pact\}", active
    )
    workspace_provider_default = (
        "/teamspace/studios/this_studio/pact" in active
        and "/workspace/pact" in active
    )
    cd_workspace = re.search(
        r"\bcd\s+[\"']?\$[{]?WORKSPACE[}]?[\"']?", active
    )
    header = "\n".join(text.splitlines()[:40]).lower()
    remote_host_header = any(
        marker in header
        for marker in (
            "already-claimed remote cuda host",
            "cuda/nvdec host",
            "run on a remote cuda host",
            "runs on a remote cuda host",
            "no_nvdec_needed",
        )
    )
    return bool(
        ((workspace_default or workspace_provider_default) and cd_workspace)
        or remote_host_header
    )


def _local_cuda_probe_line_is_nonblocking_provenance(line: str) -> bool:
    """Return True when a CUDA command is telemetry, not a blocking probe."""
    low = line.lower()
    if "|| true" in low or "|| echo" in low or "2>/dev/null" in low:
        return True
    if re.search(r"\b(?:gpu_name|driver_ver|driver_version|cuda_version)\s*=", low):
        return True
    return False


def check_remote_dispatch_runbooks_no_local_cuda_probe_default(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #137 — remote dispatch runbooks must NOT default to local CUDA probe.

    Scans ``scripts/remote_lane_*.sh`` (and ``scripts/remote_*.sh`` more
    broadly) for invocations of ``probe_nvdec.sh`` / ``nvidia-smi`` /
    ``nvcc`` / ``torch.cuda.is_available()`` and refuses each unless the
    invocation is guarded by:

    - ``LOCAL_CUDA_WORKER`` env-var token (``[[ "${LOCAL_CUDA_WORKER:-0}" == "1" ]]``)
    - ``DRY_RUN`` short-circuit
    - A remote-execution wrapper (``vastai exec``, ``lightning ssh``,
      ``modal run``, ``ssh $REMOTE_HOST``)
    - Same-line waiver ``# LOCAL_CUDA_PROBE_OK:<reason>``

    The scan is line-window-based: for each probe-token occurrence, look
    backwards up to 30 lines (within the same function / case-arm) for
    a guard token. If none is present, flag.

    Live count expected: 0 — round-3's fix already guarded the only known
    instance.

    Bug class (defense-in-depth on codex round-3 MEDIUM 1): the round-3
    fix patched ONE runbook. This META gate refuses any future
    `scripts/remote_lane_*.sh` from introducing an unguarded local
    CUDA/NVDEC probe.

    Memory: feedback_production_hardening_polish_defense_in_depth_landed_20260509.md.
    Cross-ref CLAUDE.md "Remote code parity" + "Vast.ai cost paranoia".
    """
    root = Path(repo_root or REPO_ROOT)
    scripts_dir = root / "scripts"
    if not scripts_dir.is_dir():
        if verbose:
            print("  [remote-dispatch-no-local-cuda-probe] OK (no scripts/ dir)")
        return []

    violations: list[str] = []
    scanned_files = 0
    # Scope tightly to `scripts/remote_lane_*.sh` per the prompt — these are
    # local dispatch drivers that fan out to remote GPUs. Sister scripts like
    # `remote_archive_only_eval.sh` and `remote_train_bootstrap.sh` are the
    # remote-side bootstraps that legitimately call `nvidia-smi` ON the GPU.
    for sh in sorted(scripts_dir.glob("remote_lane_*.sh")):
        s = str(sh)
        if "/tests/" in s or sh.name.startswith("test_"):
            continue
        try:
            text = sh.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        # Quick prefilter
        if not any(tok in text for tok in _LOCAL_CUDA_PROBE_TOKENS):
            continue
        if _remote_lane_script_is_remote_side_bootstrap(text):
            continue
        scanned_files += 1
        lines = text.splitlines()
        for lineno, line in enumerate(lines):
            stripped = line.lstrip()
            if stripped.startswith("#"):
                continue
            # Find probe tokens in this line
            probe_tok_found = None
            for tok in _LOCAL_CUDA_PROBE_TOKENS:
                if tok in line:
                    probe_tok_found = tok
                    break
            if probe_tok_found is None:
                continue
            if _local_cuda_probe_line_is_nonblocking_provenance(line):
                continue
            # Same-line waiver
            if _LOCAL_CUDA_PROBE_WAIVER_MARKER in line:
                continue
            # Look backwards up to 30 lines for a guard token
            lo = max(0, lineno - 30)
            window = "\n".join(lines[lo:lineno + 1])
            if any(g in window for g in _LOCAL_CUDA_PROBE_GUARD_TOKENS):
                continue
            rel = sh.relative_to(root) if sh.is_relative_to(root) else sh
            violations.append(
                f"[Check 137] {rel}:{lineno + 1}: "
                f"remote dispatch runbook invokes local CUDA probe "
                f"`{probe_tok_found}` without a `LOCAL_CUDA_WORKER` / "
                f"`DRY_RUN` / remote-execution-wrapper guard. The probe "
                f"belongs in the REMOTE provider bootstrap, not the local "
                f"dispatch driver. Add `[[ \"${{LOCAL_CUDA_WORKER:-0}}\" == \"1\" ]]` "
                f"OR `# LOCAL_CUDA_PROBE_OK:<reason>` waiver."
            )

    if verbose:
        if violations:
            print(
                f"  [remote-dispatch-no-local-cuda-probe] {len(violations)} "
                f"unguarded probe(s) (scanned: {scanned_files} runbook(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [remote-dispatch-no-local-cuda-probe] OK "
                f"({scanned_files} runbook(s) scanned; 0 unguarded probe(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_remote_dispatch_runbooks_no_local_cuda_probe_default: "
            f"{len(violations)} unguarded local CUDA probe(s) in remote "
            "dispatch runbook(s); first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: guard probe behind "
            "`[[ \"${LOCAL_CUDA_WORKER:-0}\" == \"1\" ]]` "
            "OR `[[ \"${DRY_RUN:-0}\" == \"1\" ]]` short-circuit OR wrap in "
            "remote execution (`vastai exec` / `lightning ssh` / `modal run`)."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #138 — State writers MUST use strict load on the mutating path
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (defense-in-depth on codex round-3 MEDIUM 2, 2026-05-09):
# `src/tac/deploy/lightning/active_jobs_state.py::load_active_jobs` returned
# `[]` on corrupt JSON or non-list state. `update_active_jobs_locked` then
# wrote the empty snapshot back, silently overwriting the malformed file
# with a fresh one — DROPPING all active and terminal rows. Harvesters
# that re-read after the dispatcher write would see `[]` and skip every
# still-running job.
#
# Round-3 fixed the immediate writer (`load_active_jobs_strict` raises on
# corrupt state; the locked-mutating path uses the strict variant inside
# the lock and quarantines the bad file). This META gate (#138) extincts
# the bug CLASS so no future writer can silently reset corrupt state.
#
# The check scans `src/tac/**/*.py` for function definitions matching
# `def update_*_locked(` / `def _save_*(` / `def upsert_*(` / `def register_*(` /
# `def mark_*_terminal(` and verifies the function body uses a STRICT load
# helper (one of `load_*_strict` / `_load_*_strict` / explicit
# `raise <CorruptError>` pattern after a load failure). Functions that
# silently fall back to `[]` / `{}` / empty default on corrupt state
# without raising are flagged.
#
# Sister of Catalog #131 (bare writes), #132 (deletion-merge in locked save),
# #133 (META-meta on #131 exempt list), #135 (lost-update outside lock).

_STATE_WRITER_FN_NAME_PATTERNS: tuple[str, ...] = (
    "update_",  # update_active_jobs_locked, update_active_vms_locked, etc.
    "_save_",
    "upsert_",
    "register_",
    "mark_",
)

_STATE_WRITER_LOCKED_SUFFIXES: tuple[str, ...] = (
    "_locked",
    "_terminal",
    "_atomic",
)

_STATE_WRITER_STRICT_LOAD_TOKENS: tuple[str, ...] = (
    "_strict(",
    "load_active_jobs_strict",
    "load_active_vms_strict",
    "load_first_seen_strict",
    "load_setup_first_seen_strict",
    "load_state_strict",
    "ActiveJobsCorruptError",
    "ActiveVmsCorruptError",
    "CorruptStateError",
    "raise PreflightError",
)

_STATE_WRITER_STRICT_LOAD_WAIVER_MARKER = "STATE_WRITER_STRICT_LOAD_OK"


def check_state_writers_strict_load_for_mutating_path(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #138 — state writers must use strict load on mutating path.

    Scans ``src/tac/**/*.py`` (and ``tools/**/*.py``) for function
    definitions whose name matches a state-writer pattern (``update_*_locked``,
    ``_save_*``, ``upsert_*``, ``register_*``, ``mark_*_terminal``) and
    verifies the function body either:

    1. Uses a STRICT load helper (``load_*_strict`` / explicit
       ``raise *CorruptError`` / ``raise PreflightError``), OR
    2. Carries a same-line ``# STATE_WRITER_STRICT_LOAD_OK:<reason>`` waiver
       on the ``def`` line (rare; e.g. genuinely-additive counter-bumps that
       can survive a corrupt load).

    The check is signature-aware: only functions that perform a load + write
    inside their body are scanned; pure-write functions (no `_load_` or
    `read_text` / `read_bytes` reference) are out-of-scope.

    Live count expected: 0 — round-3's fix already added the strict load
    path to the only known instance (`active_jobs_state.py`).

    Bug class (defense-in-depth on codex round-3 MEDIUM 2): the round-3
    fix patched ONE writer. This META gate refuses any future writer
    from silently resetting corrupt state.

    Memory: feedback_production_hardening_polish_defense_in_depth_landed_20260509.md.
    Cross-ref Catalog #131/#132/#133/#135 (sister concurrency/locking gates).
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
    ]

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "_intake_" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter — file must contain at least one writer-fn name
            if not any(p in text for p in _STATE_WRITER_FN_NAME_PATTERNS):
                continue
            # Quick prefilter — file must mention a load OR write op
            if not any(
                t in text
                for t in (
                    "_load_",
                    "load_active",
                    "load_setup",
                    "load_first_seen",
                    "read_text(",
                    "read_bytes(",
                    "json.load",
                )
            ):
                continue
            scanned_files += 1
            lines = text.splitlines()

            # Walk the file: find each `def NAME(` whose name matches the
            # state-writer pattern. Then scan that function's body (until
            # a less-or-equal-indented def/class) for the strict-load token.
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if not stripped.startswith("def "):
                    continue
                m = re.match(r"def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(", stripped)
                if not m:
                    continue
                fn_name = m.group(1)
                # Match name pattern
                name_matches = (
                    any(
                        fn_name.startswith(p) and (
                            any(fn_name.endswith(suf) for suf in _STATE_WRITER_LOCKED_SUFFIXES)
                            or p in ("_save_",)  # _save_* matches without suffix
                        )
                        for p in _STATE_WRITER_FN_NAME_PATTERNS
                    )
                )
                if not name_matches:
                    continue
                # Same-line waiver on def line
                if _STATE_WRITER_STRICT_LOAD_WAIVER_MARKER in line:
                    continue
                # Find function body — scan forward until less-or-equal-indent
                fn_indent = len(line) - len(stripped)
                body_start = lineno + 1
                body_end = len(lines)
                for j in range(body_start, len(lines)):
                    cand = lines[j]
                    cand_stripped = cand.lstrip(" ")
                    if not cand_stripped:
                        continue
                    cand_indent = len(cand) - len(cand_stripped)
                    if cand_indent <= fn_indent and (
                        cand_stripped.startswith("def ")
                        or cand_stripped.startswith("class ")
                        or cand_stripped.startswith("@")
                    ):
                        body_end = j
                        break
                body_text = "\n".join(lines[body_start:body_end])
                # Body must do a load AND a write to be in-scope
                does_load = any(
                    t in body_text
                    for t in (
                        "_load_",
                        "load_active",
                        "load_setup",
                        "load_first_seen",
                        "read_text(",
                        "read_bytes(",
                        "json.load",
                    )
                )
                does_write = any(
                    t in body_text
                    for t in (
                        "write_text(",
                        "write_bytes(",
                        "json.dump",
                        ".dump(",
                        "atomic_write",
                    )
                )
                if not (does_load and does_write):
                    continue
                # Must use a strict-load token OR the body must explicitly
                # raise on corrupt state
                has_strict_load = any(
                    t in body_text for t in _STATE_WRITER_STRICT_LOAD_TOKENS
                )
                if has_strict_load:
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 138] {rel}:{lineno + 1}: "
                    f"state writer `{fn_name}` does load + write WITHOUT a "
                    f"strict load helper. If the load returns `[]`/`{{}}` on "
                    f"corrupt state, the writer will silently reset the file "
                    f"and DROP every active row. Use a `load_*_strict` "
                    f"helper that raises on corrupt state (e.g. "
                    f"`ActiveJobsCorruptError`) OR add a same-line "
                    f"`# STATE_WRITER_STRICT_LOAD_OK:<reason>` waiver on "
                    f"the `def` line."
                )

    if verbose:
        if violations:
            print(
                f"  [state-writers-strict-load] {len(violations)} writer(s) "
                f"missing strict load (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [state-writers-strict-load] OK "
                f"({scanned_files} file(s) scanned; 0 writer(s) missing strict load)"
            )

    if violations and strict:
        raise PreflightError(
            "check_state_writers_strict_load_for_mutating_path: "
            f"{len(violations)} state writer(s) missing strict load on "
            "mutating path; first 3:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
            + "\n\nFix: replace the silent `load_*` (returns `[]` on corrupt) "
            "with `load_*_strict` (raises `*CorruptError` on corrupt) inside "
            "the locked mutating path. The strict variant must quarantine "
            "the bad file before re-raising so the operator can inspect it."
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #139 — Packet-compiler no_op_proof failures must promote to blocker
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 5 HIGH 1, 2026-05-09): the previous Phase 1 packet
# compiler ``_finalize_packet_result`` computed ``no_op_proof.runtime_consumes_bytes``
# and ``no_op_proof.no_op_detector_passed`` but never converted ``False``
# results into entries in ``blockers``. The CLI exit gate read only
# ``result.blockers`` so a no-op inflate.py exited 0 and burned eval spend.
#
# This META gate refuses any packet-compiler-style finalize function that
# computes a ``no_op_proof`` dict from ``_build_no_op_proof(...)`` /
# ``runtime_consumes_bytes`` / ``no_op_detector_passed`` etc. but does not
# also append a corresponding ``inflate_does_not_consume_archive_bytes`` /
# ``no_op_detector_failed`` blocker entry within the same enclosing function.
#
# Same-line opt-out: ``# NO_OP_PROOF_ADVISORY_OK:<reason>`` on the
# function-def line, reserved for the rare deliberately-advisory finalize
# (e.g. a probe-only packet that does not produce a runnable inflate; the
# advisory mode must explicitly justify why downstream consumers do not
# need a hard blocker).
#
# Sister of:
# - Catalog #102 (gate3 parser-section-manifest)
# - Catalog #105 (gate7 no_op provenance recorder)
# - Catalog #138 (state writers strict load on mutating path)

_PACKET_NO_OP_BLOCKER_TOKENS: tuple[str, ...] = (
    "inflate_does_not_consume_archive_bytes",
    "no_op_detector_failed",
)
# Catalog #139's CANONICAL signature for a packet-compiler
# `_build_no_op_proof`-style finalize. Other modules that maintain their
# own runtime-proof verification (e.g. monolithic_packet_closure_gate's
# ``_runtime_consumption_summary`` which uses ``runtime_proof_*`` tags,
# or ``submission_archive._typed_sidechannel_contract_row`` which uses
# typed-contract blockers) emit their own tag schemes; we ONLY scan for
# the canonical packet-compiler pattern (calls ``_build_no_op_proof(...)``
# constructor) so those alternate-tag-scheme verifiers are out-of-scope.
_PACKET_NO_OP_PROOF_REQUIRED_TOKEN = "_build_no_op_proof"
_PACKET_NO_OP_PROOF_TOKENS: tuple[str, ...] = (
    "_build_no_op_proof",
    "runtime_consumes_bytes",
    "no_op_detector_passed",
)
_PACKET_NO_OP_ADVISORY_WAIVER_MARKER = "NO_OP_PROOF_ADVISORY_OK"


def check_packet_compiler_no_op_proof_promotes_to_blocker(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #139 — packet-compiler no_op_proof must promote to blocker.

    Scans ``src/tac/**/*.py``, ``tools/**/*.py``, ``scripts/**/*.py``, and
    ``experiments/**/*.py`` for function definitions whose body references
    a ``no_op_proof`` computation (``_build_no_op_proof`` /
    ``runtime_consumes_bytes`` / ``no_op_detector_passed`` /
    ``runtime_consumption_proof``) AND mutates a ``blockers`` list.
    Refuses any such function that does NOT also append at least one of
    ``inflate_does_not_consume_archive_bytes`` /
    ``no_op_detector_failed`` (the canonical blocker tags emitted by
    ``tac.phase1_packet_compiler._finalize_packet_result``).

    Same-line waiver on the ``def`` line:
    ``# NO_OP_PROOF_ADVISORY_OK:<reason>``. Reserved for probe-only packets
    that explicitly opt to keep the no_op_proof as an advisory record.

    Live count expected: 0 — the codex round 5 HIGH 1 fix in
    ``src/tac/phase1_packet_compiler.py::_finalize_packet_result`` is the
    only known production instance.

    Bug class: codex round 5 HIGH 1 (2026-05-09). Memory:
    feedback_codex_round5_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "scripts",
        root / "experiments",
    ]

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "_intake_" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter — file must call the CANONICAL no_op_proof
            # constructor (`_build_no_op_proof`) AND mutate a blockers list.
            # Modules that maintain their own runtime-proof verification with
            # their own tag scheme (runtime_proof_*, typed_sidechannel_*) are
            # out-of-scope; this gate enforces ONLY the canonical
            # packet-compiler `_build_no_op_proof` contract.
            if _PACKET_NO_OP_PROOF_REQUIRED_TOKEN not in text:
                continue
            if "blockers" not in text:
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if not stripped.startswith("def "):
                    continue
                # Same-line waiver on the def line
                if _PACKET_NO_OP_ADVISORY_WAIVER_MARKER in line:
                    continue
                # Find function body
                func_indent = len(line) - len(stripped)
                func_end = len(lines)
                for fwd in range(lineno + 1, len(lines)):
                    cand = lines[fwd]
                    if not cand.strip():
                        continue
                    cand_indent = len(cand) - len(cand.lstrip(" "))
                    if cand_indent <= func_indent and cand.lstrip(" ").startswith(
                        ("def ", "class ")
                    ):
                        func_end = fwd
                        break
                body = "\n".join(lines[lineno:func_end])
                # Function must INVOKE the canonical _build_no_op_proof
                # constructor AND mutate blockers
                if _PACKET_NO_OP_PROOF_REQUIRED_TOKEN not in body:
                    continue
                if "blockers.append(" not in body and "blockers.extend(" not in body:
                    continue
                # Function must promote no_op_proof failures to blocker tags
                if not any(tag in body for tag in _PACKET_NO_OP_BLOCKER_TOKENS):
                    rel = py.relative_to(root) if py.is_relative_to(root) else py
                    fn_name = stripped.split("(")[0].replace("def ", "").strip()
                    violations.append(
                        f"[Check 139] {rel}:{lineno + 1}: function "
                        f"{fn_name!r} computes a no_op_proof and mutates "
                        "`blockers` but does NOT append "
                        "`inflate_does_not_consume_archive_bytes` or "
                        "`no_op_detector_failed`. The no-op proof becomes "
                        "advisory-only and the CLI exit silently passes a "
                        "no-op packet. Fix: add the blocker promotion when "
                        "`runtime_consumes_bytes is False` / "
                        "`no_op_detector_passed is False`. Same-line waiver "
                        "`# NO_OP_PROOF_ADVISORY_OK:<reason>` on the def "
                        "line for the rare advisory-only finalize."
                    )

    if verbose:
        if violations:
            print(
                f"  [packet-no-op-proof-promotes-to-blocker] {len(violations)} "
                f"function(s) miss blocker promotion (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [packet-no-op-proof-promotes-to-blocker] OK "
                f"({scanned_files} file(s) scanned; 0 missing promotion(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_packet_compiler_no_op_proof_promotes_to_blocker found "
            f"{len(violations)} function(s) missing blocker promotion:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #140 — `_save_*` writers documented as caller-locked must enforce
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 5 HIGH 2, 2026-05-09): ``LightningDispatcher._save_state``
# documented "MUST be called inside ``_lightning_state_lock``" but did not
# enforce it; any caller could pass a stale snapshot from outside the lock
# and silently lose concurrent rows. ``scripts/launch_lane_lightning.py``
# violated the contract by doing
# ``sessions = dispatcher.list_sessions(); ...; dispatcher._save_state(sessions)``
# outside any lock.
#
# This META gate refuses any ``_save_*`` writer whose docstring or comments
# document "MUST be called inside ... lock" / "caller is responsible for the
# lock" / "called inside ... locked" without an in-body runtime assertion
# against a sister ``_lock_held()`` / ``_lock_depth > 0`` predicate (or
# explicit ``raise ... lock`` if the predicate is False).
#
# Same-line opt-out: ``# CALLER_LOCK_ENFORCED_OK:<reason>`` on the def
# line for the rare case where lock-held verification is provably
# unnecessary (e.g. a single-process unittest scaffold).

_CALLER_LOCK_DOC_TOKENS: tuple[str, ...] = (
    "MUST be called inside",
    "must be called inside",
    "caller is responsible for the lock",
    "caller MUST hold",
    "caller must hold",
    "called inside the lock",
    "called inside ``_",
)
_CALLER_LOCK_ENFORCEMENT_TOKENS: tuple[str, ...] = (
    "_lock_held()",
    "_lock_depth >",
    "_lock_depth>",
    "fcntl.flock(",  # if writer itself acquires a lock, that's also enforcement
    "raise RuntimeError",
    "raise PreflightError",
)
_CALLER_LOCK_ENFORCED_WAIVER_MARKER = "CALLER_LOCK_ENFORCED_OK"


def check_state_writers_own_their_lock_end_to_end(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #140 — `_save_*` writers documented as caller-locked must enforce.

    Refuses any function whose name matches ``_save_*`` (or ``save_*_state``)
    AND whose body contains a comment/docstring with one of the
    "MUST be called inside the lock" / "caller is responsible for the lock"
    contract phrases — UNLESS the function body ALSO contains a runtime
    enforcement (call to a sister ``_lock_held()`` predicate, ``_lock_depth``
    counter check, ``fcntl.flock`` acquisition, or ``raise RuntimeError`` /
    ``raise PreflightError`` triggered by the predicate).

    Comment-only contracts are FORBIDDEN per CLAUDE.md
    "Comment-only contracts — FORBIDDEN". Pre-fix, the docstring rotted as
    a generation of callers learned to bypass the lock without surfacing
    the contract violation. Now the writer raises at runtime if the
    in-process lock-held predicate is False.

    Same-line waiver on the ``def`` line:
    ``# CALLER_LOCK_ENFORCED_OK:<reason>``. Reserved for genuinely-single-
    process unittest scaffolds.

    Live count expected: 0 — the codex round 5 HIGH 2 fix in
    ``src/tac/deploy/lightning/lightning_dispatch.py::LightningDispatcher._save_state``
    is the only known production instance.

    Bug class: codex round 5 HIGH 2 (2026-05-09). Memory:
    feedback_codex_round5_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "scripts",
    ]

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "_intake_" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter
            if not any(tok in text for tok in _CALLER_LOCK_DOC_TOKENS):
                continue
            if "_save_" not in text and "save_state" not in text:
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if not stripped.startswith("def "):
                    continue
                m = re.match(r"def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(", stripped)
                if not m:
                    continue
                fn_name = m.group(1)
                # Only consider _save_* / save_*_state names
                if not (
                    fn_name.startswith("_save_")
                    or (fn_name.startswith("save_") and fn_name.endswith("_state"))
                ):
                    continue
                if _CALLER_LOCK_ENFORCED_WAIVER_MARKER in line:
                    continue
                # Find function body
                func_indent = len(line) - len(stripped)
                func_end = len(lines)
                for fwd in range(lineno + 1, len(lines)):
                    cand = lines[fwd]
                    if not cand.strip():
                        continue
                    cand_indent = len(cand) - len(cand.lstrip(" "))
                    if cand_indent <= func_indent and cand.lstrip(" ").startswith(
                        ("def ", "class ")
                    ):
                        func_end = fwd
                        break
                body = "\n".join(lines[lineno:func_end])
                # Body must contain one of the doc tokens (caller-must-hold contract)
                if not any(tok in body for tok in _CALLER_LOCK_DOC_TOKENS):
                    continue
                # Body must contain at least one runtime enforcement token
                if any(tok in body for tok in _CALLER_LOCK_ENFORCEMENT_TOKENS):
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 140] {rel}:{lineno + 1}: function {fn_name!r} "
                    "documents a 'caller MUST hold lock' contract but the "
                    "body has NO runtime enforcement (no _lock_held() call, "
                    "no _lock_depth counter check, no fcntl.flock acquisition, "
                    "no raise on missing lock). Comment-only contracts are "
                    "FORBIDDEN per CLAUDE.md. Fix: add a sister `_lock_held()` "
                    "predicate driven by the lock context manager, then "
                    "`if not _lock_held(): raise RuntimeError(\"...\")` at "
                    "the top of this writer. Same-line waiver "
                    "`# CALLER_LOCK_ENFORCED_OK:<reason>` on the def line "
                    "for unittest scaffolds."
                )

    if verbose:
        if violations:
            print(
                f"  [state-writers-own-their-lock] {len(violations)} "
                f"comment-only-contract writer(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [state-writers-own-their-lock] OK "
                f"({scanned_files} file(s) scanned; 0 comment-only-contract writer(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_state_writers_own_their_lock_end_to_end found "
            f"{len(violations)} writer(s) with comment-only lock contract:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #141 — Cross-module state-helper calls must thread paths
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 5 HIGH 3, 2026-05-09): ``azure_dispatch.py``
# defined its own module-level ``ACTIVE_VMS_PATH`` constant AND imported
# ``register_active_vm_record`` / ``unregister_active_vm_by_name`` /
# ``load_active_vms`` from ``tac.deploy.azure.active_vms_state`` (which has
# its OWN module-level ``ACTIVE_VMS_PATH``) — without threading
# ``path=ACTIVE_VMS_PATH`` through the calls. Tests that monkeypatched
# ``azd.ACTIVE_VMS_PATH`` to isolate writes silently observed the helper's
# canonical path; recovery/cleanup tooling that constructed an alternative
# tracker location was equally affected.
#
# This META gate scans for any cross-module helper import where:
# 1. The CALLING module defines a module-level path/lock constant whose
#    name suggests a tracker file (matches ``*_PATH`` / ``*_LOCK`` /
#    ``ACTIVE_*`` regex)
# 2. The HELPER module also defines a same-named constant
# 3. The CALLING module imports the helper but invokes it WITHOUT threading
#    its own ``path=`` / ``lock_path=`` keyword
#
# Same-line opt-out: ``# STATE_HELPER_PATH_OK:<reason>`` on the call line
# for the rare case where a fresh canonical path is the intent.

_STATE_HELPER_PATH_WAIVER_MARKER = "STATE_HELPER_PATH_OK"

# Helper functions known to accept a `path=` / `lock_path=` keyword for
# tracker isolation. The calling module MUST thread both when it defines
# its own canonical path constant.
_STATE_HELPER_FN_NAMES_WITH_PATH_KW: tuple[str, ...] = (
    "register_active_vm_record",
    "unregister_active_vm_by_name",
    "load_active_vms",
    "load_active_vms_strict",
    "update_active_vms_locked",
    "register_job",
    "upsert_job",
    "mark_job_terminal",
    "load_active_jobs",
    "load_active_jobs_strict",
    "update_active_jobs_locked",
)


def check_state_helper_paths_explicit(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #141 — cross-module state-helper calls must thread paths.

    Scans ``src/tac/**/*.py``, ``tools/**/*.py``, ``scripts/**/*.py`` for
    files that:

    1. Define a module-level path constant matching a tracker pattern
       (``*_PATH`` whose value contains ``.omx/state`` or ``active_*.json``).
    2. Import a helper from
       ``tac.deploy.azure.active_vms_state`` /
       ``tac.deploy.lightning.active_jobs_state`` (or sister state-helper
       modules) whose name appears in
       ``_STATE_HELPER_FN_NAMES_WITH_PATH_KW``.
    3. Call the helper WITHOUT threading both ``path=`` and ``lock_path=``
       keywords.

    Same-line waiver on the call line: ``# STATE_HELPER_PATH_OK:<reason>``.

    Live count expected: 0 — the codex round 5 HIGH 3 fix in
    ``src/tac/deploy/azure/azure_dispatch.py`` threads
    ``path=ACTIVE_VMS_PATH`` and ``lock_path=ACTIVE_VMS_LOCK`` through
    every helper call.

    Bug class: codex round 5 HIGH 3 (2026-05-09). Memory:
    feedback_codex_round5_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "scripts",
    ]

    helper_modules = (
        "tac.deploy.azure.active_vms_state",
        "tac.deploy.lightning.active_jobs_state",
        "tac.continual_learning",
    )

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "_intake_" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter — must import from a state-helper module
            if not any(f"from {mod} import" in text for mod in helper_modules):
                continue
            # Identify module-level tracker path constant(s)
            tracker_constants: list[str] = []
            module_level_re = re.compile(
                r"^([A-Z][A-Z0-9_]*(?:_PATH|_LOCK))\s*="
            )
            for line in text.splitlines():
                m = module_level_re.match(line)
                if not m:
                    continue
                # The constant's value should reference an .omx/state path
                # to qualify as a tracker constant.
                if (
                    ".omx" in line
                    or "active_" in line.lower()
                    or "tracker" in line.lower()
                    or "ACTIVE_VMS_PATH" in line  # explicit alias case
                    or "ACTIVE_VMS_LOCK" in line
                ):
                    tracker_constants.append(m.group(1))
            if not tracker_constants:
                continue
            scanned_files += 1
            lines = text.splitlines()
            # For each helper call line, check that BOTH path= and lock_path=
            # appear (or only path= when the helper does not need lock_path).
            for lineno, line in enumerate(lines):
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                # Skip definitions
                if stripped.startswith("def "):
                    continue
                # Skip pure imports
                if stripped.startswith(("from ", "import ")):
                    continue
                if _STATE_HELPER_PATH_WAIVER_MARKER in line:
                    continue
                # Find a helper-fn invocation (not a docstring reference)
                for fn in _STATE_HELPER_FN_NAMES_WITH_PATH_KW:
                    if f"{fn}(" not in line:
                        continue
                    # Skip if it's part of an import statement we already filtered
                    # Skip plain attribute references in docstring/comment lines
                    if line.lstrip().startswith(('"', "'")):
                        continue
                    # Look for the call's full argument span (may span multiple
                    # lines). For the conservative check we examine the line
                    # itself plus the next 6 lines until a closing ')' at
                    # matching indent.
                    block = []
                    open_count = 0
                    for j in range(lineno, min(len(lines), lineno + 8)):
                        block.append(lines[j])
                        open_count += lines[j].count("(") - lines[j].count(")")
                        if open_count <= 0 and j > lineno - 1:
                            break
                    blob = "\n".join(block)
                    if "path=" in blob:
                        # path is threaded; we accept (lock_path is optional
                        # because not every helper takes one).
                        continue
                    rel = py.relative_to(root) if py.is_relative_to(root) else py
                    violations.append(
                        f"[Check 141] {rel}:{lineno + 1}: call to "
                        f"{fn}(...) does NOT thread `path=` keyword while "
                        "the calling module defines a tracker constant "
                        f"({', '.join(tracker_constants)}). Tests that "
                        "monkeypatch the calling module's constant will "
                        "silently observe the helper's canonical path; "
                        "recovery/cleanup tooling that builds an alternative "
                        "tracker location is equally affected. Fix: thread "
                        f"`path={tracker_constants[0]}` (and `lock_path=...` "
                        "when the helper accepts it) through the call. "
                        "Same-line waiver `# STATE_HELPER_PATH_OK:<reason>` "
                        "for the rare deliberate-canonical-path case."
                    )
                    break

    if verbose:
        if violations:
            print(
                f"  [state-helper-paths-explicit] {len(violations)} "
                f"un-threaded helper call(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [state-helper-paths-explicit] OK "
                f"({scanned_files} file(s) scanned; 0 un-threaded helper call(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_state_helper_paths_explicit found "
            f"{len(violations)} helper call(s) missing `path=` keyword:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #142 — `unsafe_test_only=True` restricted to test paths
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 6 HIGH 1, 2026-05-09): the round-4 fix added
# ``unsafe_test_only=True`` as an escape hatch for tests that need a
# permissive Phase3DispatchGate. Any production caller under ``tools/``
# / ``experiments/`` / ``scripts/`` / ``src/tac/`` could simply toggle
# the kwarg to bypass every Phase 3 dispatch precondition silently.
# Catalog #134 already prevented production callsites from constructing
# the gate at all, but #134's structural check accepted the
# ``unsafe_test_only=True`` token regardless of caller path.
#
# This META gate refuses ``Phase3DispatchGate(...)`` callsites that pass
# ``unsafe_test_only=True`` from non-test paths. Tests legitimately need
# it; production code MUST satisfy every precondition.
#
# Sister of:
# - Catalog #134 (Phase3DispatchGate fail-closed at construction)
# - Catalog #143 (paid-job submit must register pending row first)
# - Catalog #144 (SETUP-first-seen single transactional update)
# - Catalog #145 (preflight CLI default --scope is `all`)
#
# Memory: feedback_codex_round6_findings_fix_with_self_protection_landed_20260509.md.

_PHASE3_GATE_UNSAFE_TEST_ONLY_TOKEN = "unsafe_test_only=True"
_PHASE3_GATE_UNSAFE_PATH_AUDIT_WAIVED_TOKEN = "unsafe_test_only_path_audit_waived=True"
_PHASE3_GATE_UNSAFE_PATH_WAIVER_MARKER = "PHASE3_GATE_UNSAFE_PATH_WAIVED"


def check_unsafe_test_only_restricted_to_test_paths(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #142 — `unsafe_test_only=True` only allowed from test paths.

    Refuses any ``Phase3DispatchGate(...)`` constructor callsite outside
    a recognized test path that passes ``unsafe_test_only=True`` without
    ALSO passing ``unsafe_test_only_path_audit_waived=True`` OR carrying
    a same-line ``# PHASE3_GATE_UNSAFE_PATH_WAIVED:<reason>`` waiver.

    Test paths follow the pytest convention: ``*/tests/*``, ``test_*.py``,
    ``*_test.py``. The canonical scaffold module
    (``src/tac/phase3/joint_scorer_renderer_codec.py``) is also exempt
    because it defines the gate.

    Live count expected: 0 after the codex round 6 HIGH 1 fix.

    Bug class: codex round 6 HIGH 1 (2026-05-09). Memory:
    feedback_codex_round6_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "src" / "tac",
        root / "tools",
        root / "experiments",
        root / "scripts",
    ]

    EXCLUDED_FILES = {
        root / "src" / "tac" / "phase3" / "joint_scorer_renderer_codec.py",
        root / "src" / "tac" / "preflight.py",
    }

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            if py in EXCLUDED_FILES:
                continue
            s = str(py)
            # Test paths exempt — they legitimately need a permissive gate
            if "/tests/" in s or py.name.startswith("test_") or py.name.endswith("_test.py"):
                continue
            # Vendored intakes / hosted exports
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "experiments/results/vast_harvest" in s
                or "_intake_" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if "Phase3DispatchGate" not in text:
                continue
            if _PHASE3_GATE_UNSAFE_TEST_ONLY_TOKEN not in text:
                continue
            scanned_files += 1
            lines = text.splitlines()
            for lineno, line in enumerate(lines):
                if "Phase3DispatchGate(" not in line:
                    continue
                stripped = line.lstrip()
                if stripped.startswith("#"):
                    continue
                if "isinstance" in line or "issubclass" in line:
                    continue
                # Find the multi-line constructor
                window_lines = lines[lineno: min(len(lines), lineno + 30)]
                paren_depth = 0
                truncated_chunks: list[str] = []
                started = False
                end_lineno = lineno
                for offset, w_line in enumerate(window_lines):
                    truncated_chunks.append(w_line)
                    for ch in w_line:
                        if ch == "(":
                            paren_depth += 1
                            started = True
                        elif ch == ")":
                            paren_depth -= 1
                    if started and paren_depth <= 0:
                        end_lineno = lineno + offset
                        break
                ctor_text = "\n".join(truncated_chunks)
                # Only care if THIS construction passes unsafe_test_only=True
                if _PHASE3_GATE_UNSAFE_TEST_ONLY_TOKEN not in ctor_text:
                    continue
                # Allowed if explicit double-opt-in is also set
                if _PHASE3_GATE_UNSAFE_PATH_AUDIT_WAIVED_TOKEN in ctor_text:
                    continue
                # Allowed via same-line waiver on any line of the construction
                ctor_lines = lines[lineno: end_lineno + 1]
                if any(
                    _PHASE3_GATE_UNSAFE_PATH_WAIVER_MARKER in cl for cl in ctor_lines
                ):
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 142] {rel}:{lineno + 1}: "
                    "Phase3DispatchGate(unsafe_test_only=True) construction "
                    "outside a recognized test path "
                    "(``*/tests/*``, ``test_*.py``, ``*_test.py``). "
                    "Production code MUST satisfy every precondition; the "
                    "escape hatch is for tests only. If this is a "
                    "legitimate non-test fixture, set BOTH "
                    "`unsafe_test_only=True` AND "
                    "`unsafe_test_only_path_audit_waived=True`, OR add "
                    "`# PHASE3_GATE_UNSAFE_PATH_WAIVED:<reason>` waiver "
                    "on a constructor line."
                )

    if verbose:
        if violations:
            print(
                f"  [unsafe-test-only-restricted-to-test-paths] {len(violations)} "
                f"unsafe construction(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [unsafe-test-only-restricted-to-test-paths] OK "
                f"({scanned_files} file(s) scanned; 0 unsafe construction(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_unsafe_test_only_restricted_to_test_paths found "
            f"{len(violations)} unsafe Phase3DispatchGate construction(s) "
            "outside test paths:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #143 — Paid-job submit must register pending row first
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 6 HIGH 2, 2026-05-09): Lightning dispatchers
# called ``Job.run(...)`` (which CREATES the paid job + bills the
# operator) THEN persisted the active-jobs row. With round-3's strict
# ``register_job`` (which raises on corrupt active-jobs state), a
# corrupt tracker file → paid job created but tracker write fails →
# invisible orphan job. The harvester never knows about it; the operator
# pays for an instance no one is watching.
#
# The canonical fix is the create-pending-row-before-submit pattern:
#
#   1. ``register_pending_job_locked(metadata)`` — writes a "pending"
#      row to the tracker BEFORE submit. If the tracker is corrupt,
#      the dispatcher refuses to even attempt the paid submit.
#   2. ``Job.run(...)`` — actually submit; bill starts here.
#   3. ``update_pending_to_active_locked(job_id, ...)`` — promote the
#      pending row to active with the submit result.
#   4. On submit failure: ``cancel_pending_job_locked(job_id)`` to drop
#      the pending row.
#
# This META gate scans for any function that calls ``Job.run(...)``
# WITHOUT calling ``register_pending_job_locked(...)`` first. Same-line
# waiver on the ``Job.run`` line: ``# JOB_RUN_BEFORE_REGISTER_OK:<reason>``.

_PAID_JOB_PENDING_REGISTER_TOKENS = (
    "register_pending_job_locked",
)
_PAID_JOB_RUN_WAIVER_MARKER = "JOB_RUN_BEFORE_REGISTER_OK"
# Catalog #143: scope to filenames that actually look like Lightning
# dispatch surfaces. The bug class is specifically about
# ``lightning_sdk.Job.run`` callers that pay for compute; we don't want
# a false positive on a file that simply has the literal substring
# ``Job.run(`` in a docstring/comment/error message.
_PAID_JOB_LIGHTNING_FILENAME_PATTERNS = (
    "lightning",  # *_lightning_*.py / *_lightning.py (dispatcher convention)
)


def _is_lightning_dispatch_file(py: Path) -> bool:
    name = py.name.lower()
    return any(pat in name for pat in _PAID_JOB_LIGHTNING_FILENAME_PATTERNS)


def _ast_finds_real_job_run_call(tree: ast.AST) -> list[ast.Call]:
    """Return a list of AST ``Job.run(...)`` Call nodes.

    Filters out string constants and docstrings — only real Call nodes
    where ``func.attr == "run"`` and ``func.value.id == "Job"`` are
    considered.
    """
    calls: list[ast.Call] = []
    for n in ast.walk(tree):
        if isinstance(n, ast.Call) and isinstance(n.func, ast.Attribute):
            if n.func.attr == "run" and isinstance(n.func.value, ast.Name):
                if n.func.value.id == "Job":
                    calls.append(n)
    return calls


def check_paid_job_register_before_submit(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #143 — every ``Job.run(...)`` caller must register pending row first.

    Refuses any function in a Lightning dispatcher file that calls
    ``Job.run(...)`` (Lightning paid submit) WITHOUT calling
    ``register_pending_job_locked(...)`` first in the SAME function body.

    Detects ``Job.run`` via AST (so docstrings / comments / error
    messages that mention ``Job.run`` are NOT counted as real calls).
    Restricts the scan to files whose name contains ``lightning``
    (the Lightning dispatcher convention) so non-Lightning files that
    happen to have a class named ``Job`` are not affected.

    Same-line waiver on the ``Job.run`` line:
    ``# JOB_RUN_BEFORE_REGISTER_OK:<reason>``. Reserved for the
    submit-helper itself (which is called BY a higher-level function
    that owns the pending-row contract); the submit helper documents
    the contract and the higher-level function satisfies it.

    Live count expected: 0 after the codex round 6 HIGH 2 fix.

    Bug class: codex round 6 HIGH 2 (2026-05-09). Memory:
    feedback_codex_round6_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "experiments",
        root / "tools",
        root / "scripts",
        root / "src" / "tac",
    ]

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "_intake_" in s
            ):
                continue
            # Restrict to Lightning dispatcher files (the bug class)
            if not _is_lightning_dispatch_file(py):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if "Job.run" not in text:
                continue
            scanned_files += 1
            try:
                tree = ast.parse(text)
            except SyntaxError:
                continue
            real_calls = _ast_finds_real_job_run_call(tree)
            if not real_calls:
                continue
            lines = text.splitlines()
            # Group calls by enclosing function
            for node in ast.walk(tree):
                if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    continue
                fn_start = node.lineno
                fn_end = (
                    node.end_lineno if hasattr(node, "end_lineno") else len(lines)
                )
                # Real Job.run calls inside this function
                fn_calls = [
                    c for c in real_calls if fn_start <= c.lineno <= fn_end
                ]
                if not fn_calls:
                    continue
                body_lines = lines[fn_start - 1:fn_end]
                body_text = "\n".join(body_lines)
                # All real calls in this function waived?
                all_waived = all(
                    _PAID_JOB_RUN_WAIVER_MARKER in (
                        lines[c.lineno - 1] if c.lineno - 1 < len(lines) else ""
                    )
                    for c in fn_calls
                )
                if all_waived:
                    continue
                has_pending_register = any(
                    tok in body_text for tok in _PAID_JOB_PENDING_REGISTER_TOKENS
                )
                first_call_lineno = min(c.lineno for c in fn_calls)
                if has_pending_register:
                    first_register_lineno = None
                    for offset, bl in enumerate(body_lines):
                        if any(
                            tok in bl for tok in _PAID_JOB_PENDING_REGISTER_TOKENS
                        ):
                            first_register_lineno = fn_start + offset
                            break
                    if (
                        first_register_lineno is not None
                        and first_register_lineno < first_call_lineno
                    ):
                        continue
                    rel = py.relative_to(root) if py.is_relative_to(root) else py
                    violations.append(
                        f"[Check 143] {rel}:{node.lineno}: function "
                        f"{node.name!r} calls Job.run(...) BEFORE "
                        "register_pending_job_locked(...). Paid submit "
                        "must be registered FIRST so a corrupt-tracker "
                        "failure refuses the paid job entirely (no orphan)."
                    )
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 143] {rel}:{node.lineno}: function "
                    f"{node.name!r} calls Job.run(...) (paid Lightning "
                    "submit) WITHOUT calling register_pending_job_locked(...) "
                    "first. Bug class: a corrupt active-jobs file → paid "
                    "submit succeeds → tracker write fails → ORPHANED PAID "
                    "JOB. Fix: call `register_pending_job_locked(metadata)` "
                    "before `Job.run(...)`, then "
                    "`update_pending_to_active_locked(job_id, ...)` after. "
                    "Same-line waiver `# JOB_RUN_BEFORE_REGISTER_OK:<reason>` "
                    "on the Job.run line for submit-helper definitions whose "
                    "callers own the pending-row contract."
                )

    if verbose:
        if violations:
            print(
                f"  [paid-job-register-before-submit] {len(violations)} "
                f"orphan-prone caller(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [paid-job-register-before-submit] OK "
                f"({scanned_files} file(s) scanned; 0 orphan-prone caller(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_paid_job_register_before_submit found "
            f"{len(violations)} caller(s) that submit paid jobs "
            "without registering a pending row first:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #144 — SETUP-first-seen helpers must use single transactional update
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 6 MEDIUM 1, 2026-05-09): the round-4 fix split
# the SETUP-first-seen mutation into two SEPARATE locked transactions:
# ``update_setup_first_seen_locked(observed)`` then
# ``remove_setup_first_seen_locked(left_setup)``. Two overlapping verifier
# runs disagree on the same id (one observes SETUP, the other observes
# leaving SETUP). The runs serialize against each other but the SECOND
# transaction can drop a first-seen timestamp the FIRST inserted because
# the two transactions are not atomic together.
#
# Fix: a single API
# ``update_setup_first_seen_locked(observed_setup_ids, left_setup_ids,
# tracked_ids, now_ts)`` that does load + merge + remove + save inside ONE
# fcntl-locked window with explicit conflict semantics.
#
# This META gate refuses any function that calls BOTH a "save / update
# observed first-seen" helper AND a "remove / drop left first-seen" helper
# in separate locks within the same body. The single-transaction API
# is preferred.

_SETUP_FIRST_SEEN_OBSERVED_HELPER_TOKENS = (
    "update_setup_first_seen_locked",
    "_save_setup_first_seen",
)
_SETUP_FIRST_SEEN_LEFT_HELPER_TOKENS = (
    "remove_setup_first_seen_locked",
)
_SETUP_FIRST_SEEN_NO_SPLIT_WAIVER_MARKER = "SETUP_FIRST_SEEN_SINGLE_TXN_OK"


def check_setup_first_seen_no_split_transactions(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #144 — refuse SETUP-first-seen split transactions.

    Refuses any function that calls BOTH an "observed-insertion" helper
    (``update_setup_first_seen_locked`` or ``_save_setup_first_seen``)
    AND a "left-removal" helper (``remove_setup_first_seen_locked``)
    within the same function body. The two-transaction pattern is
    racy: overlapping runs that disagree on an id can drop first-seen
    timestamps.

    Same-line waiver on the function-def line:
    ``# SETUP_FIRST_SEEN_SINGLE_TXN_OK:<reason>`` for the canonical
    helper itself (which legitimately combines both inside one lock).

    Live count expected: 0 after the codex round 6 MEDIUM 1 fix.

    Bug class: codex round 6 MEDIUM 1 (2026-05-09). Memory:
    feedback_codex_round6_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "scripts",
        root / "tools",
        root / "experiments",
        root / "src" / "tac",
    ]

    EXCLUDED_FILES = {
        root / "src" / "tac" / "preflight.py",
    }

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            if py in EXCLUDED_FILES:
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "_intake_" in s
            ):
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            # Quick prefilter
            if not any(tok in text for tok in _SETUP_FIRST_SEEN_OBSERVED_HELPER_TOKENS):
                continue
            if not any(tok in text for tok in _SETUP_FIRST_SEEN_LEFT_HELPER_TOKENS):
                continue
            scanned_files += 1
            try:
                tree = ast.parse(text)
            except SyntaxError:
                continue
            lines = text.splitlines()
            for node in ast.walk(tree):
                if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    continue
                fn_start = node.lineno - 1
                # Same-line waiver on the def line
                if _SETUP_FIRST_SEEN_NO_SPLIT_WAIVER_MARKER in lines[fn_start]:
                    continue
                call_names: set[str] = set()
                for sub in ast.walk(node):
                    if not isinstance(sub, ast.Call):
                        continue
                    name = _call_name(sub.func) or ""
                    if not name:
                        name = _call_func_str(sub)
                    if name:
                        call_names.add(name)
                        call_names.add(name.rsplit(".", 1)[-1])
                has_observed = any(
                    tok in call_names for tok in _SETUP_FIRST_SEEN_OBSERVED_HELPER_TOKENS
                )
                has_left = any(
                    tok in call_names for tok in _SETUP_FIRST_SEEN_LEFT_HELPER_TOKENS
                )
                if not (has_observed and has_left):
                    continue
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 144] {rel}:{node.lineno}: function "
                    f"{node.name!r} calls BOTH a SETUP observed-insertion "
                    "helper AND a left-removal helper in separate locked "
                    "transactions. Two overlapping verifier runs that "
                    "disagree on the same id can drop first-seen "
                    "timestamps inserted by the other run. Fix: use the "
                    "single-transaction API "
                    "`update_setup_first_seen_locked(observed_setup_ids, "
                    "left_setup_ids, tracked_ids, now_ts)` that does "
                    "load + merge + remove + save inside ONE lock window. "
                    "Same-line waiver on the def line: "
                    "`# SETUP_FIRST_SEEN_SINGLE_TXN_OK:<reason>` for the "
                    "canonical helper itself."
                )

    if verbose:
        if violations:
            print(
                f"  [setup-first-seen-no-split-transactions] {len(violations)} "
                f"split-txn caller(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [setup-first-seen-no-split-transactions] OK "
                f"({scanned_files} file(s) scanned; 0 split-txn caller(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_setup_first_seen_no_split_transactions found "
            f"{len(violations)} function(s) using split SETUP-first-seen "
            "transactions:\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #145 — Preflight CLI default `--scope` must be `all`
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class (codex round 6 MEDIUM 2, 2026-05-09): the CLI added in DX
# ratchet defaulted ``--scope`` to ``dev``, dispatching to
# ``preflight_developer`` instead of ``preflight_all``. This silently
# weakened the default green CLI by skipping release/custody checks. A
# green CLI no longer means the repo's stated canonical contract is
# satisfied — a regression in observability.
#
# Fix: default ``--scope`` back to ``all`` (canonical full preflight).
# ``--scope dev`` is opt-in for the fast developer path with an explicit
# warning that release/custody checks are skipped.
#
# This META gate refuses any AST-detectable change to the default. It
# scans ``src/tac/preflight.py`` (and any other CLI that might add a
# ``--scope`` flag) and asserts the default is ``all``.

_PREFLIGHT_CLI_SCOPE_DEFAULT_REQUIRED = "all"
_PREFLIGHT_CLI_SCOPE_DEFAULT_WAIVER_MARKER = "PREFLIGHT_CLI_SCOPE_DEFAULT_OK"


def check_preflight_cli_default_scope_is_all(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #145 — preflight CLI ``--scope`` default must be ``all``.

    Scans ``src/tac/preflight.py`` (the canonical preflight CLI module)
    for an ``argparse`` ``--scope`` flag and asserts its default is
    ``all``. A non-``all`` default silently weakens the green CLI by
    routing to a subset of checks; the default must be the canonical
    full gate.

    Same-line waiver on the ``add_argument`` line:
    ``# PREFLIGHT_CLI_SCOPE_DEFAULT_OK:<reason>`` for an intentional
    non-canonical default with explicit operator review.

    Live count expected: 0 after the codex round 6 MEDIUM 2 fix.

    Bug class: codex round 6 MEDIUM 2 (2026-05-09). Memory:
    feedback_codex_round6_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    target_files = [
        root / "src" / "tac" / "preflight.py",
    ]

    violations: list[str] = []
    scanned_files = 0
    for py in target_files:
        if not py.is_file():
            continue
        try:
            text = py.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        if "--scope" not in text:
            continue
        scanned_files += 1
        try:
            tree = ast.parse(text)
        except SyntaxError:
            continue
        lines = text.splitlines()
        # Walk the AST for parser.add_argument("--scope", ...) calls
        for node in ast.walk(tree):
            if not isinstance(node, ast.Call):
                continue
            if not (
                isinstance(node.func, ast.Attribute)
                and node.func.attr == "add_argument"
            ):
                continue
            # First positional arg must be "--scope"
            if not node.args:
                continue
            first_arg = node.args[0]
            if not (isinstance(first_arg, ast.Constant) and first_arg.value == "--scope"):
                continue
            # Find default kwarg
            default_value = None
            for kw in node.keywords:
                if kw.arg == "default":
                    if isinstance(kw.value, ast.Constant):
                        default_value = kw.value.value
                    break
            # Same-line waiver
            line_idx = node.lineno - 1
            line_text = lines[line_idx] if line_idx < len(lines) else ""
            waiver_present = _PREFLIGHT_CLI_SCOPE_DEFAULT_WAIVER_MARKER in line_text
            # Also check up to 5 lines after for multi-line add_argument calls
            for offset in range(1, 6):
                if line_idx + offset >= len(lines):
                    break
                if _PREFLIGHT_CLI_SCOPE_DEFAULT_WAIVER_MARKER in lines[line_idx + offset]:
                    waiver_present = True
                    break
            if waiver_present:
                continue
            if default_value != _PREFLIGHT_CLI_SCOPE_DEFAULT_REQUIRED:
                rel = py.relative_to(root) if py.is_relative_to(root) else py
                violations.append(
                    f"[Check 145] {rel}:{node.lineno}: parser.add_argument("
                    f"\"--scope\", default={default_value!r}, ...). The "
                    "default MUST be \"all\" so the green CLI runs the "
                    "canonical full preflight (preflight_all). A non-`all` "
                    "default silently routes to a subset of checks and "
                    "weakens the green-CLI contract. Same-line waiver "
                    "`# PREFLIGHT_CLI_SCOPE_DEFAULT_OK:<reason>` for "
                    "intentional override with explicit operator review."
                )

    if verbose:
        if violations:
            print(
                f"  [preflight-cli-default-scope-is-all] {len(violations)} "
                f"weakened-default(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
        else:
            print(
                "  [preflight-cli-default-scope-is-all] OK "
                f"({scanned_files} file(s) scanned; 0 weakened-default(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_preflight_cli_default_scope_is_all found "
            f"{len(violations)} weakened-default(s):\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #147 — Lightning submit `cancel_pending_job_locked` only
# pre-network (codex round 7+8 HIGH 1, 2026-05-09)
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class: the round-6 fix (#143) made dispatchers register the pending
# row BEFORE submit, but the cancel-on-exception logic was too aggressive:
# `except BaseException` wrapped the entire `submit_lightning_job(...)`
# call (which includes `Job.run(...)` — the network call) and
# unconditionally invoked `cancel_pending_job_locked`. SDK timeouts,
# post-create API errors, property-access failures, or KeyboardInterrupt
# during/after `Job.run` could leave a real paid Lightning job while
# the cancel logic silently deleted the only harvester-visible row.
#
# Fix surface: dispatchers split exception routing into two narrow
# clauses — `except _PreNetworkSubmitError` calls
# `cancel_pending_job_locked` (safe pre-network), and the residual
# `except BaseException` calls `mark_pending_failed_unknown_billing_locked`
# (preserves the row for forensic recovery).
#
# This META gate refuses any function in a Lightning dispatcher file
# (filename contains "lightning") that calls `cancel_pending_job_locked`
# inside an `except` clause whose body wraps a `submit_lightning_job` /
# `Job.run` invocation, UNLESS the except clause type-narrows away from
# `BaseException` (e.g. `except _PreNetworkSubmitError`) OR carries a
# same-line waiver `# CANCEL_PENDING_PRE_NETWORK_OK:<reason>`.

_LIGHTNING_SUBMIT_AMBIGUOUS_TOKENS = (
    "submit_lightning_job",
    "Job.run",
)
_LIGHTNING_CANCEL_PENDING_FN_TOKEN = "cancel_pending_job_locked"
_LIGHTNING_PRE_NETWORK_EXC_TOKENS = (
    "_PreNetworkSubmitError",
)
_LIGHTNING_CANCEL_PRE_NETWORK_WAIVER_MARKER = "CANCEL_PENDING_PRE_NETWORK_OK"


def _check_147_is_baseexception_handler(handler: ast.ExceptHandler) -> bool:
    """True if the except handler catches ``BaseException`` or bare ``except:``."""
    if handler.type is None:
        return True
    if isinstance(handler.type, ast.Name) and handler.type.id == "BaseException":
        return True
    if isinstance(handler.type, ast.Tuple):
        for elt in handler.type.elts:
            if isinstance(elt, ast.Name) and elt.id == "BaseException":
                return True
    return False


def _check_147_handler_targets_pre_network_only(
    handler: ast.ExceptHandler,
) -> bool:
    """True if the except handler narrows to a pre-network exception class."""
    names: list[str] = []
    if handler.type is None:
        return False
    if isinstance(handler.type, ast.Name):
        names = [handler.type.id]
    elif isinstance(handler.type, ast.Tuple):
        for elt in handler.type.elts:
            if isinstance(elt, ast.Name):
                names.append(elt.id)
    if not names:
        return False
    return all(n in _LIGHTNING_PRE_NETWORK_EXC_TOKENS for n in names)


def _check_147_try_block_contains_ambiguous_submit(
    try_node: ast.Try,
) -> bool:
    """Heuristic: True if the `try:` body invokes `submit_lightning_job(...)` or `Job.run(...)`."""
    for stmt in try_node.body:
        for sub in ast.walk(stmt):
            if isinstance(sub, ast.Call):
                f = sub.func
                if isinstance(f, ast.Name) and f.id in _LIGHTNING_SUBMIT_AMBIGUOUS_TOKENS:
                    return True
                if isinstance(f, ast.Attribute):
                    if (
                        f.attr == "run"
                        and isinstance(f.value, ast.Name)
                        and f.value.id == "Job"
                    ):
                        return True
                    if f.attr in _LIGHTNING_SUBMIT_AMBIGUOUS_TOKENS:
                        return True
    return False


def _check_147_handler_body_calls_cancel(
    handler: ast.ExceptHandler,
) -> tuple[bool, int | None]:
    """True (with line) if the except body calls `cancel_pending_job_locked(...)`."""
    for stmt in handler.body:
        for sub in ast.walk(stmt):
            if isinstance(sub, ast.Call):
                f = sub.func
                if (
                    isinstance(f, ast.Name)
                    and f.id == _LIGHTNING_CANCEL_PENDING_FN_TOKEN
                ):
                    return True, sub.lineno
                if (
                    isinstance(f, ast.Attribute)
                    and f.attr == _LIGHTNING_CANCEL_PENDING_FN_TOKEN
                ):
                    return True, sub.lineno
    return False, None


def check_lightning_submit_cancel_only_before_network(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #147 — `cancel_pending_job_locked` only safe pre-network.

    Refuses any Lightning dispatcher file (filename contains "lightning")
    where a `try:` block invokes `submit_lightning_job(...)` or `Job.run(...)`
    AND an attached `except` clause:

    1. catches `BaseException` (or is a bare `except:`), AND
    2. invokes `cancel_pending_job_locked(...)` in its body,

    UNLESS the cancel call carries a same-line waiver
    `# CANCEL_PENDING_PRE_NETWORK_OK:<reason>` OR the handler type
    narrows to a pre-network exception class (`_PreNetworkSubmitError`).

    The bug: `except BaseException` around `Job.run` includes the network
    call. Cancelling on ambiguous-billing failures silently deletes the
    only harvester-visible row for a real paid job.

    Fix: split exception routing — narrow handler for pre-network failures
    (cancel safe), residual `BaseException` handler routes to
    `mark_pending_failed_unknown_billing_locked` (preserve row).

    Bug class: codex round 7+8 HIGH 1 (2026-05-09). Memory:
    feedback_codex_round78_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    scan_dirs = [
        root / "experiments",
        root / "tools",
        root / "scripts",
        root / "src" / "tac",
    ]

    violations: list[str] = []
    scanned_files = 0
    for scan_dir in scan_dirs:
        if not scan_dir.is_dir():
            continue
        for py in scan_dir.rglob("*.py"):
            if _is_oss_export_mirror_path(py):
                continue
            s = str(py)
            if "/tests/" in s or py.name.startswith("test_"):
                continue
            if (
                "experiments/results/public_pr" in s
                or "experiments/results/comma_lab_public_export" in s
                or "_intake_" in s
            ):
                continue
            if "lightning" not in py.name:
                continue
            try:
                text = py.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            if (
                _LIGHTNING_CANCEL_PENDING_FN_TOKEN not in text
                or not any(t in text for t in _LIGHTNING_SUBMIT_AMBIGUOUS_TOKENS)
            ):
                continue
            scanned_files += 1
            try:
                tree = ast.parse(text)
            except SyntaxError:
                continue
            lines = text.splitlines()
            for node in ast.walk(tree):
                if not isinstance(node, ast.Try):
                    continue
                if not _check_147_try_block_contains_ambiguous_submit(node):
                    continue
                for handler in node.handlers:
                    if not _check_147_is_baseexception_handler(handler):
                        continue
                    if _check_147_handler_targets_pre_network_only(handler):
                        continue
                    has_cancel, cancel_lineno = (
                        _check_147_handler_body_calls_cancel(handler)
                    )
                    if not has_cancel:
                        continue
                    waiver_lines: list[int] = []
                    if cancel_lineno is not None:
                        waiver_lines.append(cancel_lineno)
                    waiver_lines.append(node.lineno)
                    waiver_lines.append(handler.lineno)
                    waived = False
                    for ln in waiver_lines:
                        idx = ln - 1
                        if 0 <= idx < len(lines) and (
                            _LIGHTNING_CANCEL_PRE_NETWORK_WAIVER_MARKER
                            in lines[idx]
                        ):
                            waived = True
                            break
                    if waived:
                        continue
                    rel = py.relative_to(root) if py.is_relative_to(root) else py
                    violations.append(
                        f"[Check 147] {rel}:{handler.lineno}: "
                        "`except BaseException` around a try-block that "
                        "invokes `submit_lightning_job(...)` / `Job.run(...)` "
                        "calls `cancel_pending_job_locked(...)` in its body. "
                        "Bug class: SDK timeout / post-create API error / "
                        "KeyboardInterrupt mid-Job.run() leaves a real paid "
                        "Lightning job while this code silently deletes the "
                        "pending row → ORPHANED PAID JOB invisible to the "
                        "harvester. Fix: narrow the cancel handler to "
                        "`except _PreNetworkSubmitError` (pre-network only); "
                        "route the residual `except BaseException` to "
                        "`mark_pending_failed_unknown_billing_locked(...)` "
                        "to preserve the pending row for forensic recovery. "
                        "Same-line waiver `# CANCEL_PENDING_PRE_NETWORK_OK:"
                        "<reason>` on the try / except / cancel line."
                    )

    if verbose:
        if violations:
            print(
                f"  [lightning-submit-cancel-pre-network] {len(violations)} "
                f"ambiguous-billing-cancel(s) (scanned: {scanned_files} file(s))"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
            if len(violations) > 5:
                print(f"    ... ({len(violations) - 5} more)")
        else:
            print(
                "  [lightning-submit-cancel-pre-network] OK "
                f"({scanned_files} file(s) scanned; 0 ambiguous-billing-cancel(s))"
            )

    if violations and strict:
        raise PreflightError(
            "check_lightning_submit_cancel_only_before_network found "
            f"{len(violations)} ambiguous-billing-cancel call site(s):\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


# ─────────────────────────────────────────────────────────────────────────
# Catalog #148 — `tac.vastai_tracker` mutating callers must use the strict
# loader (codex round 7 HIGH 2, 2026-05-09)
# ─────────────────────────────────────────────────────────────────────────
#
# Bug class: `tac.vastai_tracker._load_records` returned `[]` on malformed
# JSON. `register_instance` then wrote the new single record over the
# corrupt file, dropping every previously-tracked active instance. The
# new instance looked successfully registered while every previous
# instance disappeared from cleanup/verification.
#
# Fix surface: a new `tac.vastai_tracker.load_active_instances_strict` that
# raises `VastaiTrackerCorruptError` on JSON parse failure; the locked
# writers (`register_instance`, `remove_instance`) call the strict loader
# inside the lock and quarantine the corrupt file to
# `<path>.corrupt.<utc>`.
#
# This META gate refuses any mutating writer in `tac.vastai_tracker` that
# performs `_load_records(...)` followed by `_write_records(...)` inside
# the same fcntl-locked region without routing through
# `load_active_instances_strict`. Sister of Catalog #138
# (`check_state_writers_strict_load_for_mutating_path`) but scoped to the
# vastai_tracker module specifically because the loader name there
# diverges from the canonical `_load_*` naming convention.

_VASTAI_STRICT_LOADER_TOKEN = "load_active_instances_strict"
_VASTAI_LOSSY_LOADER_TOKEN = "_load_records"
_VASTAI_TRACKER_PATH_REL = "src/tac/vastai_tracker.py"
_VASTAI_STRICT_LOAD_WAIVER_MARKER = "VASTAI_TRACKER_STRICT_LOAD_OK"
_VASTAI_MUTATING_WRITER_TOKENS = (
    "_write_records",
)


def check_vastai_tracker_strict_load(
    *,
    repo_root: Path | None = None,
    strict: bool = False,
    verbose: bool = True,
) -> list[str]:
    """Catalog #148 — vastai_tracker mutating writers must use strict load.

    Refuses any function in `src/tac/vastai_tracker.py` whose body calls
    `_write_records(...)` (mutation) inside a body that also invokes the
    LOSSY `_load_records(...)` loader, UNLESS:

    1. the body also routes through `load_active_instances_strict(...)`, OR
    2. the function carries a same-line waiver
       `# VASTAI_TRACKER_STRICT_LOAD_OK:<reason>` on its `def` line.

    The bug: lossy loader returns [] on malformed JSON; the writer then
    overwrites the corrupt file with a single new record, dropping every
    other tracked instance.

    Sister of Catalog #138 (`check_state_writers_strict_load_for_mutating_path`)
    scoped to the vastai_tracker module specifically; #138's pattern
    detection requires `_load_*` prefix names which the canonical strict
    loader does not match.

    Bug class: codex round 7 HIGH 2 (2026-05-09). Memory:
    feedback_codex_round78_findings_fix_with_self_protection_landed_20260509.md.
    """
    root = Path(repo_root or REPO_ROOT)
    target = root / _VASTAI_TRACKER_PATH_REL

    violations: list[str] = []
    if not target.is_file():
        if verbose:
            print(
                f"  [vastai-tracker-strict-load] OK "
                f"(target file not present: {_VASTAI_TRACKER_PATH_REL})"
            )
        return violations
    try:
        text = target.read_text(encoding="utf-8", errors="replace")
    except OSError as exc:
        if verbose:
            print(
                f"  [vastai-tracker-strict-load] could not read target "
                f"({_VASTAI_TRACKER_PATH_REL}): {exc!r}"
            )
        return violations
    try:
        tree = ast.parse(text)
    except SyntaxError:
        return violations
    lines = text.splitlines()

    for node in ast.walk(tree):
        if not isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            continue
        has_write = False
        has_lossy_load = False
        has_strict_load = False
        for stmt in node.body:
            for sub in ast.walk(stmt):
                if isinstance(sub, ast.Call):
                    f = sub.func
                    fname = (
                        f.id if isinstance(f, ast.Name)
                        else f.attr if isinstance(f, ast.Attribute)
                        else None
                    )
                    if fname in _VASTAI_MUTATING_WRITER_TOKENS:
                        has_write = True
                    if fname == _VASTAI_LOSSY_LOADER_TOKEN:
                        has_lossy_load = True
                    if fname == _VASTAI_STRICT_LOADER_TOKEN:
                        has_strict_load = True
        if not has_write:
            continue
        if has_strict_load:
            continue
        if not has_lossy_load:
            continue
        def_line_idx = node.lineno - 1
        if def_line_idx < len(lines) and (
            _VASTAI_STRICT_LOAD_WAIVER_MARKER in lines[def_line_idx]
        ):
            continue
        violations.append(
            f"[Check 148] {_VASTAI_TRACKER_PATH_REL}:{node.lineno}: "
            f"function {node.name!r} is a mutating writer "
            "(calls _write_records) but uses only the lossy `_load_records` "
            "loader. The lossy loader returns [] on malformed JSON; the "
            "subsequent _write_records would silently overwrite the corrupt "
            "tracker with a single new record, dropping every other tracked "
            "instance. Fix: route the load through "
            "`load_active_instances_strict(...)` inside the fcntl lock and "
            "quarantine on `VastaiTrackerCorruptError`. Same-line waiver "
            "`# VASTAI_TRACKER_STRICT_LOAD_OK:<reason>` on the `def` line "
            "for read-only-with-fallback paths."
        )

    if verbose:
        if violations:
            print(
                f"  [vastai-tracker-strict-load] {len(violations)} "
                f"non-strict-loader writer(s)"
            )
            for v in violations[:5]:
                print(f"    • {v[:240]}")
        else:
            print(
                "  [vastai-tracker-strict-load] OK "
                f"({_VASTAI_TRACKER_PATH_REL} writers all use strict loader)"
            )

    if violations and strict:
        raise PreflightError(
            "check_vastai_tracker_strict_load found "
            f"{len(violations)} non-strict-loader writer(s):\n  "
            + "\n  ".join(v[:300] for v in violations[:3])
        )
    return violations


if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(
        description=(
            "Preflight pipeline validator — fast developer scope by default; "
            "explicit release scope for exhaustive custody sweeps"
        )
    )
    parser.add_argument("--renderer", type=str, default=None,
                        help="Optional renderer .bin/.pt for artifact check")
    parser.add_argument("--masks", type=str, default=None)
    parser.add_argument("--poses", type=str, default=None)
    parser.add_argument("--archive", type=str, default=None)
    parser.add_argument("--no-codebase", action="store_true",
                        help="Skip codebase / arity / profiles / filenames / arch_consistency")
    parser.add_argument("--profile", type=str, default=None,
                        help="Profile name for training-input validation")
    parser.add_argument("--tto-frames", type=str, default=None)
    parser.add_argument("--gt-poses", type=str, default=None)
    parser.add_argument(
        "--scope",
        choices=("all", "dev", "release"),
        default="all",
        help=(
            "all (default) runs the canonical exhaustive preflight_all gate "
            "(matches the repo's stated contract); release is an alias for "
            "all kept for backward compatibility; dev runs the fast strict "
            "developer-only gate (skips release/custody checks — emits a "
            "warning if used). Codex round-6 MEDIUM 2 fix (catalog #145): "
            "default reverted from `dev` to `all` because `dev` silently "
            "weakened the green CLI."
        ),
    )
    parser.add_argument(
        "--timeout-s",
        type=float,
        default=DEFAULT_PREFLIGHT_CLI_TIMEOUT_S,
        help=(
            "Wall-clock budget for the normal developer preflight CLI. "
            f"Default: {DEFAULT_PREFLIGHT_CLI_TIMEOUT_S:g}s."
        ),
    )
    parser.add_argument(
        "--allow-slow-preflight",
        action="store_true",
        help=(
            "Explicit release/custody override: disable the normal 30s "
            "developer timeout. Do not use for routine edit/green loops."
        ),
    )
    args = parser.parse_args()

    try:
        # R38 fixed the old artifact-only CLI by routing through preflight_all.
        # 2026-05-09 DX ratchet (codex round-6 MEDIUM 2 reverted, catalog #145):
        # the default CLI runs the canonical exhaustive `preflight_all` gate
        # (matches the repo's stated contract). The previous `dev` default
        # silently weakened the green CLI by skipping release/custody checks.
        # Operators who explicitly want the fast developer-only path may
        # opt in via `--scope dev` (with a warning), and exhaustive
        # release/custody sweeps remain `--scope all` (default) or
        # `--scope release` (alias).
        profile_arch = None
        if args.profile:
            from tac.profiles import PROFILES
            if args.profile not in PROFILES:
                print(f"Unknown profile: {args.profile}", file=sys.stderr)
                sys.exit(2)
            profile_arch = PROFILES[args.profile]
        timeout_s = _preflight_cli_timeout_seconds(
            timeout_s=args.timeout_s,
            allow_slow_preflight=args.allow_slow_preflight,
        )
        if args.scope == "dev":
            print(
                "\nWARNING: --scope dev runs the fast developer-only gate; "
                "release/custody checks are SKIPPED. Run with --scope all "
                "(or omit --scope) before any release, dispatch, or "
                "frontier-claim. (codex round-6 MEDIUM 2, catalog #145)\n",
                file=sys.stderr,
            )
        # The CLI adds a hard DX budget: routine preflight must be fast, or
        # fail loudly and force profiling instead of silently taxing every edit.
        with _preflight_timeout_after(timeout_s):
            runner = preflight_developer if args.scope == "dev" else preflight_all
            runner(
                profile_name=args.profile,
                profile_arch=profile_arch,
                tto_frames_path=args.tto_frames,
                gt_poses_path=args.gt_poses,
                masks_path=args.masks,
                renderer_path=args.renderer,
                archive_path=args.archive,
                check_codebase=not args.no_codebase,
                verbose=True,
            )
        print("\nPREFLIGHT PASSED")
    except (PreflightError, ArityViolation, FilenameContractError,
            CodebaseDriftError, LoaderFormatSafetyError) as e:
        print(f"\nPREFLIGHT FAILED: {e}", file=sys.stderr)
        sys.exit(1)
